@ARTICLE{10.3390/nu18050826,
	author = {İmre KE and Akyol A},
	title = {Propolis in Obesity and Related Metabolic Disorders: Mechanistic and Clinical Insights-A Scoping Review.},
	journal = {Nutrients},
	year = {2026},
	abstract = {OBJECTIVES: Obesity and related metabolic disorders, including insulin resistance, dyslipidemia, and non-alcoholic fatty liver disease, represent major global health challenges. Growing interest in complementary strategies has brought propolis, a resinous bee-derived product rich in phenolic and flavonoid compounds, into focus. This scoping review aimed to map and synthesize available in vitro, in vivo, and clinical evidence regarding the metabolic effects of whole propolis preparations and propolis-derived bioactive compounds in obesity-related contexts. METHODS: The review was conducted in accordance with the PRISMA-ScR framework and included experimental and human studies evaluating adipogenesis, lipid and glucose metabolism, oxidative stress, inflammatory signaling, non-alcoholic fatty liver disease-related outcomes, and gut microbiota modulation. RESULTS: Across preclinical models, propolis preparations have been associated with modulation of antioxidant defenses, attenuation of inflammatory signaling, regulation of adipogenic transcriptional programs, and alterations in gut microbiota composition and barrier integrity. Clinical evidence suggests modest improvements in selected metabolic and inflammatory biomarkers; however, effects on body weight and adiposity remain inconsistent. Interpretation is limited by heterogeneity in propolis type, extraction method, chemical standardization, dosing strategies, and study design. CONCLUSIONS: Overall, current evidence indicates that propolis may influence obesity-related metabolic pathways, primarily at the level of biomarker modulation. Nevertheless, mechanistic causality and long-term clinical efficacy require confirmation through well-designed, adequately powered, and chemically standardized trials.},
	doi = {10.3390/nu18050826},
	pmid = {41829996 [Indexed for MEDLINE]},
	note = {PMC12987181}
}

@ARTICLE{10.3390/nu18050786,
	author = {Tago A and Kagawa N and Sakai T and Tian A and Takano S, Nahrowi and Nomura J and Suzuki T},
	title = {Compounds Contributing to the Modulation of Visceral Adiposity and Hepatic Lipid Metabolism in High-Fat-Diet-Fed Rats by Pometia pinnata (Matoa) Peel Powder: Identification of Pancreatic Lipase Inhibitors.},
	journal = {Nutrients},
	year = {2026},
	abstract = {Background:Pometia pinnata (matoa) peel powder attenuates high-fat diet-induced adiposity and hepatic lipid accumulation in rats, but the responsible compounds remain unclear. This study aimed to identify the bioactive compounds that may contribute to this phenotype, with an emphasis on pancreatic lipase inhibition as a candidate mechanism. Methods: Rats received high-fat diets containing matoa peel powder, or its water- or ethanol extraction residue. Visceral fat accumulation, hepatic lipid deposition, and serum lipid profiles were evaluated. An ethanol extract was fractionated by activity-guided column chromatography based on pancreatic lipase-inhibitory activity, and structures were identified by nuclear magnetic resonance analysis. Static in vitro gastrointestinal digestion was performed to assess inhibition of fatty acid release by the extract or isolated compounds. Results: The visceral adiposity- and hepatic lipid-modulating effects observed with matoa peel powder were retained in the water extraction residue but not in the ethanol extraction residue, suggesting removal of bioactive constituents by ethanol extraction. The ethanol extract inhibited pancreatic lipase (IC50 = 740 μg/mL). Two active compounds-hederagenin saponin and protocatechuic acid-were isolated, and both inhibited pancreatic lipase (IC50 = 149 μmol/L and 404 μmol/L, respectively). Under simulated digestion in vitro, the ethanol extract and protocatechuic acid reduced free fatty acid release, whereas hederagenin saponin did not. Conclusions: Matoa peel powder contains ethanol-soluble constituents, including pancreatic lipase-inhibitory compounds that may contribute to the modulation of adiposity and hepatic lipid metabolism in high-fat-diet-fed rats. The attenuation of individual-compound activity under simulated digestion is consistent with matrix- and intestinal milieu-dependent effects, and supports a multi-component mechanism involving saponins, phenolics (protocatechuic acid), and their intestinal biotransformation products.},
	doi = {10.3390/nu18050786},
	pmid = {41829956 [Indexed for MEDLINE]},
	note = {PMC12987302}
}

@ARTICLE{10.3390/molecules31050887,
	author = {Schifano E and Zinno P and Natella F and Pompa L and Sonaglia E and Spaziani S and Sharbaf M and Esposito F and Cirillo T and Squillante J and Maglione G and Mancini P and Angeloni A and Santarelli ML and Devirgiliis C and Uccelletti D},
	title = {Coffee Silverskin Supplementation Alleviates High-Glucose-Diet-Induced Obesity by Modulating Lipogenic Gene Expression in Caenorhabditis elegans Model.},
	journal = {Molecules},
	year = {2026},
	abstract = {Coffee silverskin (CSS), the major by-product of coffee roasting, is reported to contain bioactive compounds, including xanthines and polyphenols, showing promising potential for food and nutraceutical applications. This study investigated the beneficial effects of CSS hydroalcoholic extracts, which were chemically characterized by Attenuated Total Reflectance-Fourier-Transform Infrared Spectroscopy and ElectroSpray Ionization tandem Mass Spectrometry, on Caenorhabditis elegans physiology. CSS supplementation improved healthspan-related parameters and delayed aging-associated functional decline, without significantly extending lifespan in wild-type nematodes. Treated worms exhibited a 57% reduction in reactive oxygen species (ROS) levels and upregulation of antioxidant genes (gst-4 and sod-3), suggesting that CSS mitigates oxidative stress through the DAF-2/DAF-16 pathway. Under high-glucose diet conditions, CSS reduced lipid droplet accumulation and modulated the expression of metabolic genes, including upregulation of nhr-49 which is a key regulator of fatty acid oxidation. CSS restored lipid homeostasis and rescued the shortened lifespan of obese nhr-49 mutant worms, suggesting enhanced β-oxidation. Moreover, CSS modulated serotonergic signaling by increasing tph-1 and ser-6 expression, linking its effects to serotonin-mediated regulation of fat metabolism. Finally, CSS promoted the growth of probiotic strains, suggesting potential prebiotic properties. Overall, these findings identify CSS as a metabolic modulator capable of alleviating oxidative and metabolic stress, supporting its sustainable application in the development of functional foods and nutraceuticals.},
	doi = {10.3390/molecules31050887},
	pmid = {41828874 [Indexed for MEDLINE]},
	note = {PMC12986101}
}

@ARTICLE{10.3390/molecules31050849,
	author = {Wilczak J and Prostek A, Karpiński P and Ciesielska K, Dzięgelewska-Sokołowska Ż and Gajewska M},
	title = {Fish Oil Alters the Metabolome, Antioxidative Potential, and Secretory Profile of Visceral Adipose Tissue in Mice with High-Fat Diet-Induced Obesity Compared with Other Dietary Fat Sources.},
	journal = {Molecules},
	year = {2026},
	abstract = {Dietary fat quality, determined by fatty acid composition, plays a central role in regulating adipose tissue function and metabolic homeostasis in obesity. This study examined whether different dietary fat sources modulate the secretory activity, antioxidant capacity, and metabolomic profiles of visceral adipose tissue (VAT) in mice with established high-fat diet (HFD)-induced obesity. Male C57BL/6J mice were rendered obese by long-term feeding with a lard-based HFD and subsequently maintained on isocaloric HFDs containing lard, coconut oil, olive oil, or fish oil. Antioxidant capacity, redox enzyme activities, adipokine levels, and untargeted metabolomic profiles of VAT were analyzed. Fish oil-enriched HFD significantly improved antioxidant potential and partially restored redox enzyme activity compared with the lard-based diet. It preserved adiponectin levels and reduced leptin accumulation in VAT. Multivariate metabolomic analyses showed clear separation of dietary groups and distinct metabolic signatures related to fat quality. Replacement of lard with fish oil induced a coordinated remodeling of the lipid and amino acid metabolism and reduced metabolites linked to mitochondrial overload and oxidative stress, whereas saturated fat-rich diets promoted patterns consistent with metabolic dysfunction. These findings indicate that dietary fat quality reshapes adipose tissue metabolism in obesity and highlights fish oil as a strategy to attenuate adipose tissue dysfunction.},
	doi = {10.3390/molecules31050849},
	pmid = {41828836 [Indexed for MEDLINE]},
	note = {PMC12986175}
}

@ARTICLE{10.3390/ijms27052287,
	author = {Lee S and Seo D and Yoo C and Kim HD and Suh HJ and Lee HJ},
	title = {Anti-Obesity Activity of Giant Centella asiatica Lava Seawater Extract (GCA-LS-90) Through Regulation of Adipocyte Differentiation and Lipid Metabolism In Vitro.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Obesity is well-known as a major risk factor for metabolic disorders, and natural compounds are being explored as alternatives to conventional therapies. While Centella asiatica is well known for its medicinal and dietary benefits, the biological activities of Giant Centella asiatica (GCA), especially when extracted with mineral-rich lava seawater, remain poorly characterized. This study aimed to evaluate the anti-adipogenic and lipid-metabolism-regulating effects of a novel GCA extract (GCA-LS-90) and its ability to stimulate GLP-1 secretion in vitro. GCA-LS-90 significantly inhibited lipid accumulation in 3T3-L1 adipocytes by up to 24.3% at 200 μg/mL (p < 0.001). It downregulated adipogenic transcription factors (C/EBPβ, C/EBPα, PPARγ) and lipogenic regulators (SREBP1c, FAS, G6PD, ME), while upregulating KLF2 (all p < 0.001). Western blotting confirmed reduced SREBP1c and SREBP2 protein expression, increased phosphorylation of AMPKα/ACC, and enhanced HSL activity (p < 0.05-0.001). In STC-1 cells, GCA-LS-90 increased GLP-1 secretion (53.5 pmol/L at 90 μg/mL vs. 41.3 pmol/L in control, p < 0.001). The major compounds, 3,5- and 4,5-di-O-caffeoylquinic acids, reproduced these effects. In conclusion, GCA-LS-90 modulated adipogenesis-, lipid-metabolism-, and GLP-1 secretion-related pathways in vitro, suggesting its potential as a functional ingredient for obesity management. Further in vivo studies are needed to confirm efficacy and translational relevance.},
	doi = {10.3390/ijms27052287},
	pmid = {41828505 [Indexed for MEDLINE]},
	note = {PMC12984701}
}

@ARTICLE{10.1371/journal.pone.0344452,
	author = {Li X and Min R},
	title = {Identification of core genes mediating the association between obesity and hepatocellular carcinoma: A bioinformatics study based on mitochondrial metabolism and immune pathways.},
	journal = {PLoS One},
	year = {2026},
	abstract = {PURPOSE: Obesity is strongly associated with hepatocellular carcinoma (HCC), yet the molecular mechanisms linking them remain unclear. This study aimed to identify mitochondrial metabolism-related genes bridging obesity and HCC and to investigate their role in regulating the metabolic-immune microenvironment. METHODS: Public transcriptomic datasets from obesity (derived from peripheral blood mononuclear cells) and HCC (derived from liver tissue) cohorts were integrated. A multi-step bioinformatic pipeline combining differential expression analysis (DEA), weighted gene co-expression network analysis (WGCNA), and machine learning (ML) algorithms was applied to identify and validate hub genes. Associations with the tumor immune microenvironment were assessed using ssGSEA and correlation analyses. RESULTS: 27 core genes were identified, significantly enriched in lipid metabolism and immune response pathways. Among these, ML highlighted ACAA1 and ADI1 as downregulated candidate genes. While discovery datasets showed high diagnostic potential, ADI1 exhibited more variable performance in obesity external validation compared to the robust consistency of ACAA1. Downregulation of both genes correlated with effector T/NK cell lipid-mediated functional exhaustion and disrupted networks of immune checkpoints and chemokines, reflecting an immunosuppressive microenvironment. CONCLUSIONS: ACAA1 and potentially ADI1 are downregulated candidate genes linking obesity to HCC. Their suppression likely drives obesity-related HCC progression by coupling mitochondrial metabolic reprogramming with immunosuppressive tumor microenvironment remodeling, representing potential therapeutic targets.},
	doi = {10.1371/journal.pone.0344452},
	pmid = {41801960 [Indexed for MEDLINE]},
	note = {PMC12970922}
}

@ARTICLE{10.2147/DDDT.S595588,
	author = {Chen S and Xue J and Shao Y and Liu H and Zhou F and Gu X and Zhou G and Xu T and Wang D and Tang L},
	title = {Gut-Derived Hippuric Acid Alleviates Hepatic Lipid Metabolism via UGDH/FOXK1/CD36 Axis in Obese Mice.},
	journal = {Drug Des Devel Ther},
	year = {2026},
	abstract = {BACKGROUND: Metabolic dysfunction-associated steatotic liver disease (MASLD) is the leading cause of chronic liver disease globally, creating an urgent need to elucidate its pathogenesis and develop effective therapeutic strategies. METHODS: In this study, we established obese mouse models using distinct dietary patterns. We then employed 16S rRNA sequencing and metabolomics to profile gut microbiota composition and identify differential metabolites in serum and intestinal contents. Using Limited proteolysis mass spectrometry, co-immunoprecipitation mass spectrometry and luciferase reporter assays were used to identify the downstream molecular mechanisms. RESULTS: Our findings revealed that the abundance of hippuric acid (HA) was significantly decreased in the serum and gut of obese C57BL/6 mice, and it positively correlated with the abundance of Akkermansia and Alistipes. Notably, HA supplementation effectively reduced body weight and alleviated hepatic lipid accumulation in obese mice. Mechanistically, we found that HA directly binds to UDP-glucose dehydrogenase (UGDH), enhancing its interaction with forkhead box protein K1 (FOXK1) in the cytoplasm, thereby preventing FOXK1 nuclear translocation. This event suppresses Cd36 transcription and mitigates hepatic lipid accumulation. Furthermore, silencing Ugdh attenuated the inhibitory effect of HA on FOXK1-mediated regulation of Cd36 transcription. CONCLUSION: We demonstrate a novel mechanism for regulating hepatic lipid metabolism through HA/UGDH/FOXK1/CD36 pathway. This study provides evidence supporting the potential of HA as a therapeutic metabolite for MASLD. Moreover, these results are derived from preclinical murine models, and further clinical studies are warranted to validate the efficacy of HA.},
	doi = {10.2147/DDDT.S595588},
	pmid = {41800297 [Indexed for MEDLINE]},
	note = {PMC12967088}
}

@ARTICLE{10.1016/j.foodres.2026.118574,
	author = {Cai J and Huang A and You L and Wang Z and Huang C and Huang R and Li Y and Liang T and Zhang F and Wu Q and Wang J and Zhu Z and Ding Y},
	title = {Neomycin-sensitive gut bacteria-derived brassicasterol mediates the anti-obesity effects of Cordyceps militaris polysaccharide.},
	journal = {Food Res Int},
	year = {2026},
	abstract = {Diet-based modulation of the gut microbiota has emerged as a promising strategy to alleviate obesity and its related complications. Our previous study demonstrated that polysaccharide derived from Cordyceps militaris (CMP) exerts anti-obesity effects, yet the specific mechanism linking gut microbiota to its metabolic impact remains unclear. Herein, we utilized murine models with distinct gut microbial profiles created via antibiotic cocktails to investigate these mechanisms. The protective effects of CMP against high-fat diet (HFD)-induced obesity and associated metabolic disturbances were substantially impaired in mice depleted of neomycin-sensitive gut bacteria. Metagenomic analyses further established that CMP required these bacteria to restore gut microbial homeostasis. Notably, we observed that CMP elevated hepatic levels of brassicasterol in a manner dependent on neomycin-sensitive gut bacteria. Brassicasterol treatment alone replicated the anti-obesity effects of CMP, as indicated by reduced body weight gain, improved lipid and glucose metabolism, and decreased inflammation. Through transcriptomic and functional analyses, we identified hepatic Apoa4 as a key downstream effector of brassicasterol. Our results indicated that brassicasterol upregulated Apoa4, facilitating lipid transport and suppressing inflammation both in vitro and in vivo. Collectively, our findings indicate that CMP exerts its anti-obesity effects through a neomycin-sensitive gut bacteria-brassicasterol-Apoa4 pathway. This work expands the mechanistic understanding of CMP and highlights a novel microbiota-metabolite-host regulatory axis for dietary intervention in metabolic disorders.},
	doi = {10.1016/j.foodres.2026.118574},
	pmid = {41794459 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.lfs.2026.124308,
	author = {Pan Z and Ding M and Gu W and Yu Z and Yi Q and Dai J and Wang L and Peng Y and Zhang Z and Zheng L},
	title = {Exercise improves high-fat diet-induced obesity and related cardiac dysfunction in Drosophila by regulating Dilp6 through FOXO in adipose tissue.},
	abstract = {Obesity is a common metabolic disease, and the development of obesity can lead to related cardiovascular diseases. Therefore, this article explores the relationship between exercise and Dilp6 in lipid metabolism and the resulting cardiac function damage, as well as the role of FOXO in the relationship between exercise and Dilp6. Our results show that adipose tissue-specific knockdown of Dilp6 leads to lipid accumulation, impaired cardiac function, and reduced exercise capacity in Drosophila. Exercise can regulate Dilp6 through FOXO, improving lipid accumulation and related cardiac function damage caused by Dilp6 downregulation. Therefore, our study provides a new theoretical basis for exercise to improve obesity and obesity-induced cardiac function damage.},
	doi = {10.1016/j.lfs.2026.124308},
	pmid = {41791487 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molimm.2026.02.013,
	author = {Tong L and Su L and He J and Chen Y and Chen Z and Tang L and Wu X},
	title = {High fat diet promotes asthma by inhibiting the differentiation of regulatory T cells via E3 ubiquitin ligase ITCH.},
	journal = {Mol Immunol},
	year = {2026},
	abstract = {Obesity, a rising global health issue, has been linked to the exacerbation of asthma, increasing both the risk of onset and disease severity. High-fat diet (HFD) has been shown to influence immune responses and worsen asthma in murine models, although the exact mechanisms remain unclear. In our study, we found that HFD significantly reduced the population of regulatory T cells (Tregs) in the lungs and led to increased eosinophilic inflammation in asthma. HFD was linked to alterations in lipid metabolism, particularly through the activation of the lipogenic enzyme acetyl-CoA carboxylase (ACC1) and inhibition of fatty acid oxidation. Additionally, treatment with Etomoxir, a CPT-1a inhibitor, diminished Treg proportions and Foxp3 expression. We also revealed that the E3 ubiquitin ligase ITCH, which regulates Treg function, was downregulated at the protein level under HFD conditions, despite unchanged mRNA levels. Overall, our research findings highlight the impact of high-fat diets on Treg function and immune regulation, providing insights for potential therapeutic strategies targeting lipid metabolism in inflammatory diseases like asthma.},
	doi = {10.1016/j.molimm.2026.02.013},
	pmid = {41791173 [Indexed for MEDLINE]}
}

@ARTICLE{10.1371/journal.pbio.3003700,
	author = {Li Y and Tao M, Ibáñez CF and Xie M},
	title = {Gpc3 selectively suppresses subcutaneous adipogenesis in diet-induced obesity.},
	journal = {PLoS Biol},
	year = {2026},
	abstract = {Subcutaneous and visceral adipose depots employ distinct expansion strategies in response to dietary cues, yet the molecular regulators underlying these depot-specific adaptations remain poorly understood. Through integrated proteomic profiling of human subcutaneous and visceral adipose tissues from paired obese/non-obese donors and temporal transcriptomic analysis of mouse adipose stem and progenitor cells (ASPCs) during dietary transitions, we identified Glypican 3 (Gpc3) as an obesity-responsive gene exhibiting reciprocal expression patterns between depots. ASPC-specific Gpc3 deletion in mice amplified high-fat diet-induced weight and fat mass gain, with a selective enhancement of expansion in inguinal white adipose tissue (WAT) without affecting epididymal WAT. Mechanistically, Gpc3 loss biased ASPC fate toward adipogenesis over proliferation through depot-specific modulation of canonical Wnt signaling. These findings establish Gpc3 as a regulator for regional adipose plasticity, offering a molecular target for reprogramming pathological fat distribution in obesity and related metabolic disorders.},
	doi = {10.1371/journal.pbio.3003700},
	pmid = {41779769 [Indexed for MEDLINE]},
	note = {PMC12978566}
}

@ARTICLE{10.1096/fj.202505066R,
	author = {Song C and Chen J and Jiang X and Chen B and Pan Y and Su C and Ren J and Li X and Chen X and Wang Y and Fang X and Zhang C},
	title = {LncRNA IGF2AS Regulates Bovine Adipocyte Differentiation by Stabilizing the ILF3/FTO Complex and Activating PI3K/AKT Signaling.},
	journal = {FASEB J},
	year = {2026},
	abstract = {In our previous study, we identified IGF2AS, an antisense long noncoding RNA transcript of insulin-like growth factor 2, as a critical regulator of bovine skeletal muscle development. Subsequent investigation revealed its differential expression pattern during bovine preadipocyte differentiation, though its functional significance remained unclear. Through gain- and loss-of-function experiments, we demonstrated that IGF2AS overexpression enhances adipogenic gene expression and promotes fat deposition, while its knockdown produces opposing effects. Mechanistically, RNA-seq analysis following IGF2AS silencing revealed significant downregulation of PI3K/AKT signaling pathway components. Furthermore, RNA immunoprecipitation (RIP) and co-immunoprecipitation (Co-IP) assays identified physical interactions between IGF2AS and the ILF3/FTO protein complex, suggesting a novel regulatory axis through which IGF2AS modulates PI3K/AKT-mediated adipogenesis in bovine adipocytes. These findings not only elucidate a previously unrecognized mechanism of lncRNA-mediated fat deposition regulation but also position IGF2AS as a potential molecular target for precision breeding strategies aimed at improving beef quality.},
	doi = {10.1096/fj.202505066R},
	pmid = {41761912 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/ijms27042014,
	author = {Choi H and Lee Y and Park SH and Park J and Park KH and Baek KS and Kim J and Jung H and Kim J and Jun W},
	title = {Terminalia bellirica Extract Attenuates Fat Accumulation Through Modulation of Obesity-Related Dysmetabolism in 3T3-L1 Adipocytes and High-Fat Diet-Induced Obese Mice.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Terminalia bellirica extract (TBE) has long been utilized in Ayurvedic medicine across Indian and surrounding regions for diverse therapeutic applications. Despite its traditional prominence, systematic investigations addressing the anti-obesity efficacy and underlying mechanisms remain limited. In this study, we evaluated the anti-obesity potential of TBE using both 3T3-L1 adipocyte and high-fat diet (HFD)-induced mice model. In vitro studies using 3T3-L1 adipocytes demonstrated that TBE significantly inhibited lipid accumulation and downregulated key genes involved in adipogenesis and lipogenesis, while upregulating genes promoted lipolysis and energy metabolism. To validate these cellular effects in a physiological context, mice were randomly assigned to six groups: normal control (NC), HFD-induced obese (C), HFD with metformin (100 mg/kg b.w., PC), and HFD with TBE at 50, 100, and 200 mg/kg b.w. Consistent with the in vitro findings, TBE supplementation significantly reduced body weight gain, adipose tissue mass, and adipocyte size in HFD-induced obese mice. Taken together, these results indicate that TBE exerts anti-obesity effects through modulation of adipose tissue metabolic pathways, highlighting its therapeutic potential for obesity management.},
	doi = {10.3390/ijms27042014},
	pmid = {41752152 [Indexed for MEDLINE]},
	note = {PMC12940958}
}

@ARTICLE{10.3390/ijms27041759,
	author = {Grenet S and Ivanov S and Chinetti G},
	title = {Adipose-Tissue Macrophage Diversity and Functions.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Macrophages are the predominant immune cell type found in adipose tissue (AT). They play a critical role in tissue homeostasis and participate in metabolic regulation. In white adipose tissue (WAT), studies show that multiple macrophage subsets co-exist in the very same microenvironment. Yet these cells express selective membrane markers, allowing for identifying several well-distinguished populations. In the present review we discuss the diversity and functions of white-adipose-tissue macrophages. We summarize current knowledge regarding the intratissue distribution of macrophage populations and their specific association with stromal cells and discuss the mechanisms governing adipose-tissue macrophage generation and survival. We emphasize the central role of adipose-tissue macrophages in handling local lipid levels. A particular focus is placed on the recently described population of lipid-associated macrophages (LAMs), particularly abundant in adipose tissue during obesity development.},
	doi = {10.3390/ijms27041759},
	pmid = {41751896 [Indexed for MEDLINE]},
	note = {PMC12941317}
}

@ARTICLE{10.3390/ijms27041747,
	author = {Han JY and Kwon O and Lee YJ and Choi M and Lee B and Kim DK and Noh S and Cho M and Lee YM},
	title = {Comparative Anti-Obesity Potential of Cannabigerol-Dominant Cannabis sativa L. Inflorescence Extracts via Differential Regulation of Lipid Metabolism in 3T3-L1 Cells.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Obesity is a chronic metabolic disorder characterized by excessive accumulation of body fat and is a major risk factor for various diseases, including type 2 diabetes, hypertension, and cardiovascular diseases. This study investigated the anti-obesity effects of cannabigerol-dominant C. sativa inflorescence extracts (CEs) obtained using various ethanol concentrations. The extracts were analyzed by UPLC to determine their major components. Additionally, anti-obesity mechanisms of the extracts were further determined through RT-qPCR and Western blot analysis to evaluate gene and protein expression levels. A total of seven cannabinoids, including cannabigerol as a major constituent, were identified within CE. Differentiation of 3T3-L1 cells was dose-dependently inhibited by CE at all ethanol concentrations. Furthermore, the gene and protein expression levels of key adipogenic and lipogenic markers, such as PPARγ, C/EBPα, SREBP-1c, and FAS, were significantly downregulated by CE treatment. In contrast, the expression of factors involved in lipolysis and white adipose tissue browning, such as HSL, ATGL, UCP1, and PGC-1α, was markedly increased by CE treatment. These effects were enhanced in an ethanol concentration-dependent manner. In conclusion, these results demonstrate that cannabigerol-dominant C. sativa effectively mitigates obesity by suppressing adipogenesis and lipogenesis while concurrently stimulating lipolysis and white adipose tissue browning.},
	doi = {10.3390/ijms27041747},
	pmid = {41751885 [Indexed for MEDLINE]},
	note = {PMC12941217}
}

@ARTICLE{10.3390/biom16020311,
	author = {Cheng X and Li S and Zhang K and Guo Y and Li H and Li Z and Tian Y and Kang X and Liu X and Tian W},
	title = {gga-let-7c-3p Inhibits Chicken Abdominal Adipogenesis by Regulating PPARD Gene.},
	journal = {Biomolecules},
	year = {2026},
	abstract = {MicroRNAs (miRNAs) have been increasingly involved in mammalian lipid metabolism. However, their regulatory roles and molecular mechanisms in abdominal fat deposition in chicken remain largely unexplored. In this study, based on the previous miRNA transcriptome data during chicken abdominal preadipocytes' adipogenic differentiation, we explored the biological functions and regulatory mechanisms of a differentially expressed miRNA, gga-let-7c-3p, in adipogenesis. Gain- and loss-of-function assays elucidated that gga-let-7c-3p significantly decreased viability, proliferation, cell cycle progression, intracellular lipid droplet accumulation and triglyceride content, as well as the mRNA expression of proliferation- and lipid metabolism-related genes in chicken abdominal preadipocytes. Dual-luciferase reporter assay confirmed that gga-let-7c-3p could directly interact with the 3'UTR of the transcription factor-peroxisome proliferator activated the receptor delta (PPARD) gene and thus inhibited its post-transcriptional expression. The PPARD gene significantly decreased viability, proliferation, and cell cycle progression, while it increased intracellular lipid droplet accumulation and triglyceride content of chicken abdominal preadipocytes, paralleling with the mRNA expression of proliferation- and lipid metabolism-related genes. Collectively, gga-let-7c-3p could inhibit the proliferation and adipogenic differentiation of chicken abdominal preadipocytes, at least by targeting the PPARD gene. These findings reveal the regulatory mechanisms of the gga-let-7c-3p/PPARD axis in chicken abdominal adipogenesis, and could provide potential molecular markers for lean line broiler breeding.},
	doi = {10.3390/biom16020311},
	pmid = {41750379 [Indexed for MEDLINE]},
	note = {PMC12938580}
}

@ARTICLE{10.1038/s41419-026-08525-3,
	author = {Khalaji S and Venit T, Lukáčová Z and Fambri V and Shrestha R and Kaluarachchi S and Boitet M and Fagny M and Saldi G and Percipalle P},
	title = {Nuclear Myosin 1 links genomic architecture to adipose tissue remodeling, metabolic inflammation and obesity in mice.},
	journal = {Cell Death Dis},
	year = {2026},
	abstract = {Adipocyte differentiation involves a metabolic transition from oxidative phosphorylation (OXPHOS) to aerobic glycolysis, allowing preadipocytes to meet the biosynthetic and energetic demands of maturation. Here, we show that nuclear myosin 1 (NM1), a chromatin-associated actomyosin motor, known to control transcription and chromatin accessibility, is required for metabolic homeostasis during adipocyte differentiation. Integrated ATAC-seq and RNA-seq profiling of NM1-deficient mouse embryonic fibroblasts (MEFs) revealed coordinated downregulation of key adipogenic and lipid-droplet machinery genes like Cebpa, Plin2, Abhd5, Agpat2, Pink1, and altered enhancer accessibility near adipogenesis-linked transcription factors (TFs) such as Klf6, Foxo3, Smad5, and Gata4. NM1 knockout (KO) mesenchymal stem cells (MSCs) exhibited impaired differentiation potential despite enlarged adipocyte morphology. In vivo, NM1-deficient mice developed progressive visceral obesity, accompanied by transcriptional reprogramming in epididymal white adipose tissue (eWAT), including repression of mitochondrial and adipogenic pathways and activation of inflammatory networks driven by IFNG, IL33, and TNF. Cross-species network analysis highlighted conserved regulatory architecture centered on MYO1C, implicating NM1/MYO1C as key chromatin-level regulators of adipose remodeling.},
	doi = {10.1038/s41419-026-08525-3},
	pmid = {41748556 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molcel.2026.02.001,
	author = {Long F and Ghosh A and Xu T and Ding L and Wu C and Khandelwal R, Noé F and Sun W and Dong H and Wang T and Hoffmann A and Gardeux V and Deplancke B and Abu-Nawwas L and Stefanicka P and Varga L and Ruiz JR, Blüher M and Balaz M and Sharma AK and Wolfrum C},
	title = {MEDAG functions as an A-kinase-anchoring protein in adipocytes.},
	journal = {Mol Cell},
	year = {2026},
	abstract = {Induction of catabolic adipocyte activity independent of mitochondrial uncoupling to induce energy expenditure has received increasing attention. In this study, we identified mesenteric estrogen-dependent adipogenesis gene (MEDAG), a poorly studied gene, as a promising therapeutic target for enhancing energy expenditure in adipocytes. We demonstrated that adipose MEDAG expression positively correlates with obesity and metabolic dysfunction in humans. Consistently, adipocyte-specific ablation of Medag in mice leads to increased energy expenditure, offering protection from diet-induced obesity. Mechanistically, we show that MEDAG functions as an A-kinase-anchoring protein (AKAP), which can directly regulate protein kinase A (PKA) activity through a negative feedback loop, involving direct interaction with PKA leading to MEDAG phosphorylation and consequent feedback fine-tuning of PKA activity. Specifically, the direct interaction of MEDAG with the PKA-RIIβ subunit regulates the stability of PKA-RIIβ to prevent PKA hyperactivation. These findings position MEDAG as a target for adipose energy expenditure and uncover its AKAP activity.},
	doi = {10.1016/j.molcel.2026.02.001},
	pmid = {41747731 [Indexed for MEDLINE]}
}

@ARTICLE{10.1038/s41419-026-08450-5,
	author = {Huang Y and He T and Zheng J and Chen J and Yang Z},
	title = {Circular RNAs in metabolic health: bridging the gap between molecular biology and therapy.},
	journal = {Cell Death Dis},
	year = {2026},
	abstract = {Recent advances in obesity research have shifted focus toward biological mechanisms, paralleling progress in pharmacotherapy. Fat browning-the conversion of white to brown adipocytes-emerges as a promising therapeutic strategy. Circular RNAs (circRNAs), stable non-coding RNAs with regulatory functions, are now recognized as key modulators of this process through organelle-mediated mechanisms. This review synthesizes current understanding of circRNA biogenesis and their roles in fat browning, particularly their interactions with mitochondria and endoplasmic reticulum in lipid metabolism. We highlight their capacity to encode peptides and regulate metabolic pathways, positioning circRNAs as potential precision therapeutics. While preclinical studies demonstrate mechanistic efficacy, clinical translation requires addressing delivery challenges and tissue-specific effects. This biological perspective advances obesity treatment paradigms beyond simplistic energy-balance models, mirroring the evolution seen in pharmacotherapeutic development.},
	doi = {10.1038/s41419-026-08450-5},
	pmid = {41741417 [Indexed for MEDLINE]},
	note = {PMC12988876}
}

@ARTICLE{10.1530/JOE-25-0131,
	author = {Qin L and Wu W and Su J and Wan Y and Zhang L and Fan L and Wang Y and Sun W and Zhang Q and Li Y and Zhu X},
	title = {miR-200b-3p inhibits adipose browning by targeting Prdm16.},
	journal = {J Endocrinol},
	year = {2026},
	abstract = {The expression of miR-200b-3p is correlated with obesity, but its biological function in the pathogenesis of obesity remains poorly understood. Here, we investigated the function of miR-200b-3p in white adipose browning. The C3H10T1/2 and 3T3-L1 cell lines were infected with lentiviruses carrying miR-200b-3p mimic or antisense; then, the mRNA and protein expression of adipogenic differentiation genes and brown adipose tissue-specific genes was detected. These lentiviruses were also directly injected into the inguinal white adipose tissue (iWAT) of C57BL/6 mice fed a normal chow diet or high-fat diet (HFD). Body weight, adipose tissue weight, glycolipid metabolism, and related gene expression were measured. Overexpression of miR-200b-3p impaired, whereas inhibition of miR-200b-3p improved white adipose browning both in vitro and in vivo. Mice with overexpression of miR-200b-3p in iWAT showed elevated levels of serum insulin and total cholesterol and were insulin resistant under HFD. Inhibition of miR-200b-3p in iWAT prevented mice from insulin resistance induced by HFD. Mechanistically, dual-luciferase reporter assay showed that miR-200b-3p directly inhibited Prdm16 expression in the Smad and p38Mapk signaling pathways. In conclusion, our findings suggest that miR-200b-3p regulates adipocyte browning by targeting Prdm16. This could be a potential therapeutic target for obesity.},
	doi = {10.1530/JOE-25-0131},
	pmid = {41738785 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.diabres.2026.113183,
	author = {Karczewska-Kupczewska M and Matulewicz N and Stefanowicz M and Dobrzycka M and Dunaj K, Kołakowski A, Myśliwiec P and Dadan J and Kowalska I},
	title = {Adipose tissue expression of Notch signaling genes in relation to insulin sensitivity and obesity in humans.},
	journal = {Diabetes Res Clin Pract},
	year = {2026},
	abstract = {AIMS: Notch signaling may regulate adipogenesis. The objective of the present study was to analyze the role of the Notch pathway in the development of insulin resistance and metabolic complications of obesity. We analyzed subcutaneous (SAT) and visceral adipose tissue (VAT) expression of Notch genes in relation to insulin sensitivity, obesity, and metabolic syndrome (MS). METHODS: Study group 1 comprised 48 individuals with normal-weight, 28 with overweight and 12 with obesity. Group 2 comprised 27 participants with overweight/obesity examined before and after weight loss. Group 3 comprised 8 individuals without obesity, 23 with obesity without MS, 29 with obesity with MS. SAT biopsy was performed in group 1 and 2. In group 3, SAT and VAT were collected during surgery. RESULTS: In group 1, SAT DLL1, NOTCH2, NOTCH4, and HEY1 were lower in individuals with obesity compared to normal-weight individuals. In group 2, weight loss increased DLL1, JAG1, NOTCH2, NOTCH4, and HES1. In group 3, both groups with obesity had lower SAT and VAT JAG1, NOTCH2, NOTCH4, and HEY1. Positive correlations between Notch genes and adipogenic genes were observed in all study groups. CONCLUSIONS: Notch signaling pathway may be associated with healthy adipose tissue through regulation of adipogenesis in humans.},
	doi = {10.1016/j.diabres.2026.113183},
	pmid = {41734827 [Indexed for MEDLINE]}
}

@ARTICLE{10.1096/fj.202504725R,
	author = {Wang Y and Edin ML and Jing N and Lih FB and Yang J and Yeliseyev V and Zeldin DC and Zhang G},
	title = {Gut Microbiota Modulate Adipose Eicosanoid Metabolism: Potential Roles of the Lipoxygenase Pathway.},
	journal = {FASEB J},
	year = {2026},
	abstract = {Numerous studies support that gut microbiota regulate adipose inflammation and function, thereby influencing the development of obesity, diabetes, and associated metabolic disorders; however, the underlying mechanisms remain not fully elucidated. While previous studies on microbiota-adipose interactions have primarily focused on how gut microbiota modulate adipose protein-based mediators, the role of lipid mediators (LMs), lipid-based signaling molecules crucial for adipose homeostasis, remains unclear. In this study, we used high-performance liquid chromatography-tandem mass spectrometry (LC-MS/MS)-based targeted lipidomics, which can quantify over 100 LMs, to compare LM profiles in adipose tissues from germ-free (GF) and conventionally raised (specific pathogen-free, SPF) mice. We found that 5- and 12/15-lipoxygenase (LOX)-derived LMs were among the most significantly altered metabolites in conventionally raised mice compared to GF controls. Mechanistically, the effects of the gut microbiota are associated with two potential pathways: (1) downregulating transcriptional expression of 5- and 12/15-LOX in adipose tissue, and (2) lowering circulating levels of 5- and 12/15-LOX-derived metabolites. Given the potent biological activities of LOX-derived LMs, these findings may suggest a novel mechanism by which gut microbiota modulate adipose function and influence disease development.},
	doi = {10.1096/fj.202504725R},
	pmid = {41733824 [Indexed for MEDLINE]}
}

@ARTICLE{10.1039/d5fo05239d,
	author = {Jing N and Mu T and Bian X and Zhao H and Li Q and Chen Z and Tang H and Li J and Guo J and Zhao K},
	title = {Fu brick tea extracts attenuate HFD induced lipid deposition by regulating the glycerolipid metabolism of gut microbiota and adipose tissue.},
	journal = {Food Funct},
	year = {2026},
	abstract = {Fu brick tea (FT), known for regulating lipid metabolism, was studied to explore its lipid-lowering mechanism by analyzing its effects on gut microbes and adipose tissue. Mice were given chow, high-fat diet (HFD), or HFD + FT aqueous extract (FTE, 400 mg per kg BW). FTE reduced HFD-induced fat deposition, altered gut microbiota (enriched the "glycerolipid metabolism" pathway, reversed HFD-suppressed Firmicutes_bacterium_ASF500), and affected epididymal fat transcriptome (genes enriched in PPAR, glycerolipid/fatty acid metabolism). Four lipid-related genes (Lipf, Lep, Kdsr, Esrra) showed reversed expression patterns, while FTE treatment demonstrated no significant in vitro effects on adipocyte differentiation. FTE may exert lipid-lowering effects via regulating gut microbe/adipose glycerolipid metabolism, with downstream metabolites playing a key role. In summary, FTE may alleviate lipid deposition by elevating Firmicutes_bacterium_ASF500 to regulate dietary derived metabolites, which may enhance Esrra-mediated fatty acid oxidation-related gene expression, thereby improving triglyceride metabolism. Further studies are warranted to elucidate the specific roles and interactions of FTE's potential microbial and gene targets.},
	doi = {10.1039/d5fo05239d},
	pmid = {41729608 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fimmu.2026.1742993,
	author = {Park MK and Cho M and Yu HS},
	title = {Macrophage migration inhibitory factor from nematode parasite as a novel approach to combat obesity and its metabolic complications.},
	journal = {Front Immunol},
	year = {2026},
	abstract = {OBJECTIVE: Obesity is a complex chronic disease characterized by excessive fat accumulation, dysregulation of energy homeostasis, and associated mild inflammation, significantly increasing the risk of metabolic diseases, cardiovascular diseases, and other chronic diseases. Addressing this requires innovative approaches targeting the underlying mechanisms. This study investigates the therapeutic effects of Anisakis simplex-derived macrophage migration inhibitory factor (1) on adipogenesis, lipid metabolism, and inflammation in high-fat diet (2)-induced obesity. METHODS: We evaluated the effects of rAs-MIF on adipocyte differentiation, lipid droplet formation, and expression of adipogenic and inflammatory genes in 3T3-L1 cells. In addition, we investigated the effects of orally administered rAs-MIF on lipid accumulation, glucose metabolism, serum biochemical markers, and immune regulation in mice fed a 45% high-fat diet. RESULTS: rAs-MIF dose-dependently reduced lipid droplet size and triglyceride accumulation, inhibited adipogenesis and inflammatory gene expression, and upregulated adiponectin levels in 3T3-L1 cells. In HFD-fed mice, rAs-MIF decreased body weight gain, fat mass, and serum lipid levels, enhanced glucose tolerance, and activated interscapular brown adipose tissue while suppressing epididymal white adipose tissue lipid synthesis. Moreover, it modulated the immune balance by promoting the polarization of anti-inflammatory macrophages and reducing the production of pro-inflammatory cytokines. CONCLUSION: rAs-MIF demonstrates a dual regulatory effect on adipogenesis and metabolism, highlighting its potential as a therapeutic candidate for obesity.},
	doi = {10.3389/fimmu.2026.1742993},
	pmid = {41727486 [Indexed for MEDLINE]},
	note = {PMC12916604}
}

@ARTICLE{10.1016/j.jacl.2025.06.016,
	author = {McNaught J},
	title = {Pathophysiology of obesity.},
	journal = {J Clin Lipidol},
	year = {2026},
	abstract = {BACKGROUND: Obesity is an increasingly common, multifactorial condition with significant consequences for patients and the healthcare system. Obesity represents a major modifiable risk factor for cardiovascular disease, type 2 diabetes and metabolic syndrome. Understanding of the pathways and mechanisms involved in the development of obesity will allow for further advancement in treatment modalities. SOURCES OF MATERIAL: Evidence was drawn from current peer-reviewed literature addressing the pathophysiology of obesity identified via PubMed searches. ABSTRACT OF FINDINGS: Obesity results from impaired energy homeostasis and chronic positive energy balance. The etiology of the positive energy balance is often a complex interplay of genetic, environmental, neurohormonal, and psychosocial factors. This paper discusses the pathophysiology of obesity. Topics included in this discussion are the genetics of obesity, the process of energy regulation and metabolism of adipose tissue. Also discussed is how visceral obesity is especially harmful, as it promotes insulin resistance, altered lipid metabolism, and inflammation. CONCLUSION: Understanding the underlying pathophysiology of obesity is crucial for making advances in treating this condition with a more individualized approach.},
	doi = {10.1016/j.jacl.2025.06.016},
	pmid = {41708211 [Indexed for MEDLINE]}
}

@ARTICLE{10.2337/db25-0979,
	author = {Lin S and Lytle KA and Fink N and Jensen MD},
	title = {Adipose Tissue Resistance to the Antilipolytic Effect of Insulin and Niacin in Humans With Obesity.},
	journal = {Diabetes},
	year = {2026},
	abstract = {Adipose tissue (AT) lipolysis insulin resistance results in excess free fatty acid (FFA) release. We tested the hypothesis that the ability of insulin to suppress AT lipolysis is unrelated to the ability of niacin to suppress lipolysis, because niacin acts through a different proximal signaling pathway. Ten volunteers (5 women and 5 men) with upper-body obesity and/or type 2 diabetes mellitus (T2DM) underwent two study visits with overnight intravenous infusions of niacin (1.4 mg/min) or saline, followed by a hyperinsulinemic-euglycemic clamp. FFA-palmitate Ra was measured using [U-13C] and [2H9]palmitate infusions; abdominal AT biopsies were performed before and during the insulin clamp. The suppression of FFA-palmitate Ra by insulin on the saline control day and by niacin after an overnight infusion were highly correlated (r = -0.93, P < 0.001). Fasting AT Akt (pAktS473/474-to-panAkt ratio, P = 0.01) and perilipin 1 (PLN1) (pPLN1S552-to-panPLN1 ratio, P = 0.02) phosphorylation were less during niacin treatment than in the saline control study. Because the suppression of lipolysis by insulin and niacin are highly correlated within individuals and because niacin and insulin act through different proximal signaling pathways, we propose dysregulated AT lipolysis in obesity/T2DM is due to dysfunction(s) in distal lipolysis proteins rather than isolated "insulin resistance." ARTICLE HIGHLIGHTS: We undertook this study to compare adipose tissue lipolysis responses to insulin and niacin in humans. We tested the hypothesis that adipose tissue insulin resistance would be unrelated to adipose tissue niacin resistance. The suppression of lipolysis by insulin and niacin were highly correlated. Dysregulated adipose tissue lipolysis in obesity/type 2 diabetes is due to dysfunction(s) in distal lipolysis proteins rather than isolated "insulin resistance."},
	doi = {10.2337/db25-0979},
	pmid = {41701570 [Indexed for MEDLINE]}
}

@ARTICLE{10.3389/fendo.2025.1736033,
	author = {Spadafora R and Zhang J and Nirmala NR and Li X and O'Tierney-Ginn P},
	title = {Placental mRNA and miRNA dynamics associated with lipid metabolism pathways in pregnancies affected by obesity.},
	journal = {Front Endocrinol (Lausanne)},
	year = {2026},
	abstract = {INTRODUCTION: Maternal obesity (pregravid body mass index >30 kg/m2), which has reached epidemic levels in the US, increases the incidence of cardiovascular disease and all cause premature death in the offspring. The placenta modulates fetal access to lipids and other nutrients and is considered a key player in fetal growth and maturation. However, the complex interplay between dysregulated metabolism in mothers with obesity and placental pathways mediating impacts on fetal development that predispose offspring to morbidities later in life, is poorly understood. METHODS: We used unbiased Whole Genome Correlation Network Analysis (WGCNA) in 39 full-term unlabored placentas from mothers affected by obesity to explore relationships between coding and non-coding placental transcripts with maternal and fetal metabolic variables. RESULTS: We identified positive correlations between members of the Rho network, a key inflammation regulator, with maternal leptin and cord blood free fatty acids (cbFFA). Furthermore, we identified negative correlations between epigenetic regulators and the lipid metabolism drivers SMUG1 and CDS1, with cbFFA. A set of placental miRNAs showed positive correlations with cbFFA. Using mirTarRnaSeq, an R/Bioconductor package, we predicted interactions between placental coding genes and miRNA, which correlated negatively and positively with cbFFA, respectively. Several FFA-associated miRNAs (miR-23b cluster, -168, -138, -6825, -6845) have been previously associated with obesity in animal models and human cohorts. DISCUSSION: Further studies are required to investigate the role that the Rho network plays in placental inflammation and the link between miRNAs and the predisposition towards cardiovascular diseases in the offspring of obese mothers.},
	doi = {10.3389/fendo.2025.1736033},
	pmid = {41684451 [Indexed for MEDLINE]},
	note = {PMC12890621}
}

@ARTICLE{10.3390/ijms27031440,
	author = {Wu H and Xu X and Chen J and Morisseau C and Hammock BD and Tseng YH and Zhao L},
	title = {Transplantation of Soluble Epoxide Hydrolase Inhibitor-Treated Human Brown Adipocytes Promotes Adipose Tissue Activation in High-Fat-Diet-Fed Nude Mice.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Brown adipose tissue (BAT) plays a key role in non-shivering thermogenesis and is a promising target for enhancing energy expenditure to combat obesity. Soluble epoxide hydrolase (sEH) is a cytosolic enzyme that catalyzes the conversion of epoxy fatty acids into less active diols. We have reported that local administration of the sEH inhibitor, t-TUCB, to the endogenous interscapular BAT (iBAT) of diet-induced obese mice decreased serum triglycerides and enhanced the expression of essential genes associated with lipid metabolism. Here, the effects of sEH inhibition by t-AUCB were assessed on human brown adipocyte (HuBr) differentiation and in nude mice transplanted with t-AUCB-treated HuBr. HuBr cells were differentiated with t-AUCB (1-10 μM) or the vehicle (0.1% DMSO). HuBr differentiated with t-AUCB at 5 μM (AUCB 5) or DMSO was mixed with matrix gel and transplanted into the nude mice. The mice were then fed a high-fat diet for eight weeks. The mice receiving AUCB 5-treated HuBr exhibited markedly reduced lipid accumulation in the iBAT compared with DMSO or matrix-only controls, along with increased protein expression of thermogenic PGC1α and UCP1, fatty acid transporter CD36, and CPT1A in the iBAT, while the NFκB inflammatory pathways were suppressed in both the AUCB 5 and DMSO groups. Moreover, the PGC1α and CPT1A protein levels were elevated, and the adipocyte sizes were decreased in the epididymal white adipose tissue of the AUCB 5 group. Our findings indicate that the transplantation of HuBr treated with AUCB 5 may stimulate thermogenesis, enhance lipid metabolism, and reduce inflammation in iBAT.},
	doi = {10.3390/ijms27031440},
	pmid = {41683861 [Indexed for MEDLINE]},
	note = {PMC12898555}
}

@ARTICLE{10.3390/ijms27031306,
	author = {Sobczyński J, Nowaczyński F, Smolińska K and Lachowicz-Radulska J and Serefko A and Szopa A},
	title = {Natural Bioactive Compounds Targeting FABP4 in Adipogenesis and Obesity: Evidence from In Vitro and In Vivo Studies.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {FABP4 (fatty acid-binding protein 4) is a lipid chaperone and secreted adipokine linking dysregulated fatty acid handling with inflammation, cellular stress, and insulin resistance in obesity. By modulating nuclear receptor signaling (notably PPARγ) and enhancing NF-κB/MAPK activation in adipocytes and macrophages, FABP4 contributes to maladaptive adipose remodeling and systemic metabolic decline. This review critically summarizes recent preclinical evidence on natural bioactive compounds that regulate FABP4 expression and associated adipogenic programs in models of adipogenesis and diet-induced obesity. Data from 3T3-L1/OP9 adipocytes, rodent studies, and selected alternative models indicate that many plant-derived extracts and phytochemicals (e.g., polyphenols, saponins, coumarins, terpenoids, and fermented products) down-regulate FABP4 at mRNA and/or protein levels. These effects are frequently accompanied by suppression of PPARγ/C/EBPα/SREBP1c signaling, activation of AMPK-related pathways, reduced lipid accumulation, and improved metabolic outcomes including lower weight gain, reduced adipocyte hypertrophy, improved steatosis, and favorable serum lipid profiles. Natural compounds from non-plant sources (animal- and microbe-derived metabolites) further broaden FABP4-targeting strategies, supporting FABP4 as a cross-class therapeutic node. Key translational barriers include poor extract standardization, incomplete identification of active constituents, limited oral bioavailability, microbiome-dependent variability, and scarce clinical validation. Future work should prioritize well-characterized lead scaffolds, targeted delivery, rational combinations, and standardized, adequately powered clinical trials assessing dose, durability of FABP4 suppression, and cardiometabolic safety.},
	doi = {10.3390/ijms27031306},
	pmid = {41683732 [Indexed for MEDLINE]},
	note = {PMC12898738}
}

@ARTICLE{10.3390/ijms27031186,
	author = {Ábel T and Csobod Csajbókné É},
	title = {Semaglutide-Mediated Remodeling of Adipose Tissue in Type 2 Diabetes: Molecular Mechanisms Beyond Glycemic Control.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Type 2 diabetes mellitus (T2DM) is characterized not only by chronic hyperglycemia but also by profound adipose tissue dysfunction, including impaired lipid handling, low-grade inflammation, mitochondrial dysfunction, and extracellular matrix (ECM) remodeling. These adipose tissue alterations play a central role in the development of systemic insulin resistance, ectopic lipid accumulation, and cardiometabolic complications. Glucagon-like peptide-1 receptor agonists (GLP-1RAs), particularly semaglutide, have emerged as highly effective therapies for T2DM and obesity. While their glucose-lowering and appetite-suppressive effects are well established, accumulating evidence indicates that semaglutide exerts pleiotropic metabolic actions that extend beyond glycemic control, with adipose tissue representing a key target organ. This review synthesizes current preclinical and clinical evidence on the molecular and cellular mechanisms through which semaglutide modulates adipose tissue biology in T2DM. We discuss depot-specific effects on visceral and subcutaneous adipose tissue, regulation of adipocyte lipid metabolism and lipolysis, enhancement of mitochondrial biogenesis and oxidative capacity, induction of beige adipocyte programming, modulation of adipokine and cytokine secretion, immunometabolic remodeling, and attenuation of adipose tissue fibrosis and ECM stiffness. Collectively, available data indicate that semaglutide promotes a functional shift in adipose tissue from a pro-inflammatory, lipid-storing phenotype toward a more oxidative, insulin-sensitive, and metabolically flexible state. These adipose-centered adaptations likely contribute to improvements in systemic insulin sensitivity, reduction in ectopic fat deposition, and attenuation of cardiometabolic risk observed in patients with T2DM. Despite compelling mechanistic insights, much of the current evidence derives from animal models or in vitro systems. Human adipose tissue-focused studies integrating molecular profiling, advanced imaging, and longitudinal clinical data are therefore needed to fully elucidate the extra-glycemic actions of semaglutide and to translate these findings into adipose-targeted therapeutic strategies.},
	doi = {10.3390/ijms27031186},
	pmid = {41683613 [Indexed for MEDLINE]},
	note = {PMC12898281}
}

@ARTICLE{10.3390/nu18030401,
	author = {He X and Liu Y and Cui S and Yu Z and He Z and Zong Y and Chen W and Geng J and Zhou J and Li Z and Zhao Y and Teng H},
	title = {Research on the Therapeutic Effect and Mechanism of Stir-Roasted Deer Velvet Antler with Ghee on Non-Alcoholic Fatty Liver Disease.},
	journal = {Nutrients},
	year = {2026},
	abstract = {Objectives: This study aims to explore the therapeutic effect and mechanism of stir-roasted deer velvet antler with ghee (ZLR) on Non-Alcoholic Fatty Liver Disease (NAFLD). Methods: This study used proteomics to analyze the protein composition of roasted deer antler velvet. It established a high-fat diet (HFD)-induced NAFLD rat model and evaluated the therapeutic effects of different dosage groups, including liver injury, oxidative stress, glucose metabolism, steatosis, and insulin homeostasis (via fasting glucose tolerance). Transcriptomics explored the mechanism. Gene expression and Western blot detected lipid metabolism-related gene expression. In vivo experiments validated that ZLR-containing serum alleviates NAFLD and reduces reactive oxygen species levels. Results: The results indicated that ZLR could significantly reduce the body weight, liver weight and degree of hepatic steatosis in HFD rats, improve glycolipid metabolism and insulin sensitivity, and alleviate oxidative stress damage. The mechanism involves activating the adenosine monophosphate-activated protein kinase/peroxisome proliferator-activated receptor (AMPK/PPAR) signaling pathway, regulating the expression of lipid metabolism-related genes, promoting fatty acid oxidation, and reducing fat deposition. The results of in vitro experiments show that ZLR-containing serum can effectively reduce lipid droplet production in liver cells and effectively alleviate oxidative stress damage in liver cells. Conclusions: The traditional Chinese medicine processed product ZLR can regulate lipid metabolism in the body and alleviate the degree of NAFLD by activating the AMPK and PPAR signaling pathways. It provides new ideas for the clinical treatment of NAFLD.},
	doi = {10.3390/nu18030401},
	pmid = {41683224 [Indexed for MEDLINE]},
	note = {PMC12899000}
}

@ARTICLE{10.1016/j.phymed.2026.157922,
	author = {Wu J and Liu S and Ma Z and Munkhbayar B and Liao Q and Hou M and Wei Y and Xiao Y and Wang Y and Chen R and Batsaikhan B and Batchuluun K and Zhou L and Li Y},
	title = {Aloesin improves metabolic associated fatty liver disease and obesity by targeting TGFBR1.},
	journal = {Phytomedicine},
	year = {2026},
	abstract = {BACKGROUND: Metabolic associated fatty liver disease (MAFLD) is a chronic liver condition with a high global prevalence. Obesity and its associated insulin resistance are among the main risk factors for MAFLD, for which no effective clinical treatments are currently available. Aloesin, a natural chromone compound derived from Aloe vera, has anti-inflammatory, antioxidant, anticancer, and antidiabetes activity. However, its involvement in MAFLD has not been systematically studied. PURPOSE: This study investigated the effectiveness of aloesin against MAFLD and obesity and elucidated its potential molecular mechanism. METHODS: Aloesin was added to the high-fat diet-of an induced mouse model and to oleic acid/palmitic acid-induced HepG2 cells to explore its effect on lipid metabolism. Molecular targets were identified by reverse docking, cellular thermal shift assay (CETSA), and drug affinity responsive target stability (DARTS). RESULTS: Aloesin significantly reduced lipid accumulation in hepatocytes in both the high-fat diet-induced MAFLD mouse model and the oleic acid/palmitic acid-induced HepG2 cells. It also alleviated oxidative stress and energy metabolism disorders and decreased the body fat mass in mice fed the high-fat diet, which ameliorated the pathological features of MAFLD and obesity. Target prediction and validation identified TGFBR1 as a direct target of aloesin, which was confirmed by CETSA and DARTS. Functional experiments demonstrated that overexpression of TGFBR1 increased lipid accumulation and metabolic disturbances, which were reversed by aloesin. CONCLUSION: Aloesin improved lipid deposition and slowed the progression of MAFLD by targeting TGFBR1. The results support its potential application for the prevention and treatment of MAFLD.},
	doi = {10.1016/j.phymed.2026.157922},
	pmid = {41678914 [Indexed for MEDLINE]}
}

@ARTICLE{10.1152/japplphysiol.00939.2025,
	author = {Claiborne A and Jevtovic F and Biagioni EM and Rossa L and Ollmann C and Zheng D and Strom C and Wisseman B and McDonald S and Newton E and Mouro S, deVente J and Kelley GA and Houmard JA and Broskey NT and May LE},
	title = {Exercise FITT-V during pregnancy: dose-dependent reduction in infant cellular lipid content and whole body fat.},
	journal = {J Appl Physiol (1985)},
	year = {1985},
	abstract = {Modifiable health behaviors such as exercise regulate adiposity in adults, but the effects of exercise during pregnancy on infant adiposity remain understudied. This report analyzed the relationship between prenatal exercise frequency, intensity, time, type, and volume (FITT-V) and infant adiposity, to better guide prenatal exercise prescription. Female participants [body mass index = 29.0 kg/m2, 30.5 yr of age, with gravida = 1 and parity = 0, peak oxygen consumption (V̇o2peak) = 21.9 mL/kg/min, and pregnant for 39.6 wk] were randomized to supervised exercise (aerobic, resistance, combination) or attention control for ∼24 wk during pregnancy. FITT-V metrics were analyzed from session records. Infant mesenchymal stem cells (MSCs), a model of infant adiposity, were collected from umbilical cord at delivery, adipogenically differentiated, and stained for lipids. Infant body fat percentage was estimated from skinfolds measured at 1 mo of age. Higher weekly exercise volume correlated with lower infant body fat (R2 = 0.12, P = 0.03) and MSC lipids (R2 = 0.13, P = 0.01). Weekly exercise frequency (R2 = 0.06, P = 0.10) and total volume (R2 = 0.19, P = 0.002) influenced adiposity. Subscapular skinfolds were notably affected by exercise (R2 = 0.27, P < 0.001). We conclude that in utero exposure to exercise beyond minimum recommendations is associated with reduced infant adiposity. Specifically, our findings suggest that exercising below 450 metabolic equivalent (MET)·min/wk, e.g., exercising at an average of 3 METs for 150 min/wk or 5 METs for 90 min/wk, excludes individuals from these offspring health benefits.NEW & NOTEWORTHY This study was the first to test how specific prenatal exercise dose, i.e., the FITT-V (frequency, intensity, time, type, volume) metrics, could influence the storage of triglycerides in infant adipogenic mesenchymal stem cells (MSCs). Prenatal exercise led to a reduction in infant whole body fat percentage (BF%), which was reflected by lower lipid storage in infant MSCs. Changes in lipid content were observed in offspring born to participants exercising beyond the minimum recommended weekly volume, 450 metabolic equivalent (MET)·min/wk.},
	doi = {10.1152/japplphysiol.00939.2025},
	pmid = {41665099 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.intimp.2026.116320,
	author = {Feng C and Liu Q and Peng J and Jia C and Pan X and Liu S and Geng X and Zhai J and Wu M and Hao S and Lei L and Xu K and Ma Y and Lei L and Liu Z and Huan Y and Shen Z},
	title = {The novel SPPARM YR3-16 ameliorates metabolic disorders in vivo and attenuates adipocyte inflammation in vitro via PPARγ-dependent ERK suppression.},
	journal = {Int Immunopharmacol},
	year = {2026},
	abstract = {Obesity-related metabolic disorders and adipocyte inflammation are key drivers of type 2 diabetes, but conventional therapies remain suboptimal in addressing these core pathologies. This study aimed to characterize YR3-16 as a novel selective peroxisome proliferator-activated receptor γ modulator (SPPARM) with efficacy in improving metabolic homeostasis and reducing adipocyte inflammation. YR3-16 is a novel tetrahydroisoquinoline derivative that selectively activates PPARγ and exhibits a binding mode distinct from that of pioglitazone. In spontaneous obese and type 2 diabetic KKAy mice, oral administration of YR3-16 (three doses, 25/50/75 mg/kg) for 30 days dose-dependently ameliorated metabolic disorders: it improved insulin sensitivity (insulin tolerance test), and reduced plasma triglycerides, free fatty acids and total cholesterol. Consistent results were also observed in diet-induced obese (DIO) mice. In 3 T3-L1 adipocytes, YR3-16 (10 μM) reprogrammed lipid metabolism at the gene transcriptional level, and suppressed pro-inflammatory cytokine secretion (tumor necrosis factor-α (TNF-α), interleukin-1β (IL-1β)), associated with the inhibition of extracellular signal-regulated kinase (ERK) signaling pathway, which was abolished by the peroxisome proliferator-activated receptor γ antagonist GW9662. YR3-16, as a novel SPPARM, concurrently improves metabolic disorders in vivo and attenuates adipocyte inflammation via peroxisome proliferator-activated receptor γ activation, highlighting its potential for treating obesity-related diseases.},
	doi = {10.1016/j.intimp.2026.116320},
	pmid = {41662813 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s10695-026-01653-9,
	author = {Wang B and Zheng H and Xiong J and Yang HJ and Li QL and Luo Z},
	title = {Lecithin supplementation to HFD improves largemouth bass liver health: Implications for regulating lipid homeostasis, antioxidant responses and endoplasmic reticulum stress.},
	journal = {Fish Physiol Biochem},
	year = {2026},
	abstract = {Dietary lipids serve as economical energy sources in aquaculture feeds. Elevating lipid content promotes protein conservation and mitigates nitrogen waste. Fish health, however, can be severely impacted by fatty liver resulting from prolonged high-fat diet (HFD) feeding. Adding lecithin to the feed might be a potential improvement solution. This study investigated how dietary lipid and phospholipid levels affect hepatic lipid homeostasis, endoplasmic reticulum (ER) stress, and redox balance in largemouth bass. Five diets were formulated: a control (10.67% lipid, no added lecithin), a normal-lipid diet with 1.0 g/kg lecithin, the HFD (18.65% lipid, no added lecithin), and the HFD supplemented with either 1.0 or 2.0 g/kg lecithin (HFD + lecithin 1, HFD + lecithin 2). Lecithin supplementation reversed HFD-induced intrahepatic fat deposition while mitigating the decline in hepatic polyunsaturated fatty acids content. Lecithin supplementation mitigated HFD-stimulated increases in hepatic triglyceride, total cholesterol, key lipogenic enzyme activities, and mRNA levels of lipogenic genes/transcription factors. Furthermore, lecithin lessened the impact of HFD on hepatic very low density lipoprotein (VLDL), preventing both a lessened VLDL content and diminished VLDL secretion. Regarding ER stress and antioxidant responses: dietary lecithin addition alleviated HFD-induced increment of mRNA levels of ER stress markers and MDA content, and mitigated HFD-induced reduction of hepatic total superoxide dismutase, catalase, and total antioxidant capacity. This demonstrates lecithin's protective role against HFD-induced hepatic injury by restoring lipid homeostasis, alleviating ER stress, and strengthening antioxidant capacity.},
	doi = {10.1007/s10695-026-01653-9},
	pmid = {41661360 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molmet.2026.102330,
	author = {Su Y and Li X and Wang Y and Lu X and Ye Y and Sun J and Liu T and Cai J and Ma X and Yang Y and Zhou J},
	title = {ANKRD53 is downregulated in human obesity and coordinates lipolysis with mitochondrial oxidative metabolism in adipocytes.},
	abstract = {AIMS: Human adipose tissue is central to obesity-associated metabolic dysfunction. ANKRD53 is a human-specific, adipocyte-enriched ankyrin repeat scaffold protein with largely unknown function. We investigated its role in human adipocyte metabolism and the underlying mechanism. METHODS: RNA-seq analysis of subcutaneous adipose tissue (SAT) and visceral adipose tissue (VAT) from 236 individuals quantified ANKRD53 expression and its association with metabolic traits. In human primary adipocytes, we assessed lipolysis (free fatty acid and glycerol release) and mitochondrial respiration (oxygen consumption rate) after ANKRD53 overexpression or knockdown. An AAV was used to overexpress ANKRD53 in mouse inguinal white adipose tissue (iWAT). Protein interactors were identified by immunoprecipitation-mass spectrometry, and knockdown experiments confirmed a functional role of ACSL1. RESULTS: ANKRD53 expression in both adipose depots was markedly reduced in obesity and inversely correlated with BMI, adiposity measures, insulin resistance indices, and circulating triglycerides, while positively associated with adiponectin and HDLc. In human adipocytes, ANKRD53 overexpression enhanced forskolin-stimulated lipolysis and mitochondrial respiration, whereas silencing impaired these processes. Adipose-targeted ANKRD53 overexpression in mice increased lipolysis in vivo. Mechanistically, ANKRD53 interacted with ACSL1 and promoted its mitochondrial localization, channeling lipolysis-derived FFAs into β-oxidation; silencing ACSL1 abrogated ANKRD53's effects. CONCLUSIONS: ANKRD53 is reduced in obesity and coordinates lipolysis with mitochondrial oxidative metabolism in human adipocytes, promoting efficient use of lipolysis-derived FFAs via ACSL1. These findings establish ANKRD53 as a key regulator of adipocyte energy metabolism and a potential therapeutic target for improving metabolic health in obesity.},
	doi = {10.1016/j.molmet.2026.102330},
	pmid = {41654016 [Indexed for MEDLINE]},
	note = {PMC12924745}
}

@ARTICLE{10.1016/j.foodres.2025.118175,
	author = {Zhang Y and Zeng W and Liu Y and Wang X},
	title = {Pine nut oil as a functional alternative to corn oil: Process selection, provenance profiling, and multi-omics evidence of lipid-lowering efficacy in Western-diet mice.},
	journal = {Food Res Int},
	year = {2026},
	abstract = {Pine nut oil (PNO) is a candidate alternative to corn oil (CO) owing to comparable unsaturated fatty-acid profiles and enrichment in pinolenic acid (Δ5-18:3) and lipid-soluble micronutrients. We systematically compared extraction routes (solvent, supercritical CO2, pressing), established solvent extraction as the optimal balance of yield and bioactive retention, and then characterized solvent-extracted oils from eight provenances using a weighted composite score to nominate Pinus tabuliformis for in vivo testing. In diet-induced obese mice (12-week Western diet, then 12-week intervention, n = 10 per group), replacing CO with PNO lowered body-mass gain and liver weight and improved serum lipids (triglycerides ↓ ∼ 28 %, total cholesterol ↓ ∼ 15 %, LDL-C ↓ ∼ 20 %) without affecting HDL-C or glucose; ALT and AST fell by ∼30 %, indicating hepatoprotection. Hepatic multi-omics revealed coherent remodeling toward PUFA-rich phospholipid species, activation of PPAR-centered peroxisomal/mitochondrial fatty-acid degradation and circadian pathways, and integrative correlations implicating Cyp4a10/14, Ehhadh, Slc27a2, Fgf21, Angptl4, and Plin5. Collectively, PNO reoriented hepatic lipid flux toward oxidation and membrane remodeling, supporting its development as a nutritionally advantaged culinary oil.},
	doi = {10.1016/j.foodres.2025.118175},
	pmid = {41652743 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.foodres.2025.118284,
	author = {Li Z and Yao Y and Han H and Cao Q and Tang B and Liu Y and Zhou Z and Zhang W},
	title = {Bioactive polymethoxylated flavones from Clerodendranthus spicatus alleviate high-fat diet-induced lipid dysfunction and metabolic inflammation via targeting the PPARα/NF-κB pathway.},
	journal = {Food Res Int},
	year = {2026},
	abstract = {The high-fat diet (HFD) pattern is currently a major cause of chronic metabolic diseases worldwide, especially metabolic dysfunction-associated steatohepatitis (MASH). Clerodendranthus spicatus (Thunb.) C. Y. Wu (CST) is an edible-medicinal plant widely used for health promotion, however its bioactive constituents and mechanisms against HFD-induced metabolic disorders have not been convincingly demonstrated. In this study, the ethyl acetate fraction of CST extract (EAF_CST), rich in polymethoxylated flavones (PMFs), showed better lipid-lowering and anti-inflammatory activities than raw extract. Subsequent in vivo experiments confirmed that EAF_CST markedly alleviated HFD-induced obesity (body weight reduced by 17% in the high-dose group, p < 0.001 vs. HFD), insulin resistance, dyslipidemia (serum TG lowered by 40% in the high-dose group, p < 0.001 vs. HFD), hepatic steatosis and inflammation in rats. Further integrative transcriptomic and network analysis revealed that tetramethylscutellarein, trimethylapigenin and eupatorin-5-methylether strongly interacted with lipid/inflammation-related hub targets and pathways (notably the PPAR signaling pathway), leading to their designation as the core bioactive constituents. Geographical commonality and efficacy validation further reinforced this designation. Mechanistically, these PMFs directly bound to PPARα, thereby enabling EAF_CST to promote fatty acid oxidation, and suppress NF-κB-mediated inflammatory response. Finally, the therapeutic effects of EAF_CST were further verified to depend on PPARα. This study establishes a clear constituent-target-pathway axis for CST's metabolic benefits, and the first evidence that these benefits are mediated by the core PMFs targeting PPARα. These findings also provide a scientific basis for developing CST into functional foods/nutraceuticals for combating HFD-related disorders (e.g., MASH).},
	doi = {10.1016/j.foodres.2025.118284},
	pmid = {41652694 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.bbadis.2026.168186,
	author = {Zhang K and Kan C and Qiu H and Shi J and Chen J and Zheng T and Zhang J and Ma Y and Sheng S and Hou N and Han F and Sun X},
	title = {12,13-diHOME ameliorates MASLD by regulating Sestrin2-mediated AMPK/ULK1/Lipophagy in obese mice.},
	journal = {Biochim Biophys Acta Mol Basis Dis},
	year = {2026},
	abstract = {Obesity-driven metabolic dysfunction-associated steatotic liver disease (MASLD) is characterized by hepatic lipid accumulation and impaired lipid metabolism. Enhancing lipophagy, the autophagic degradation of lipid droplets, represents a promising therapeutic strategy. Sestrin2, a stress-responsive protein, promotes lipophagy via the AMPK/ULK1 pathway. Here, we investigated the role of 12,13-diHOME, a brown adipose tissue-derived lipid, in modulating MASLD via Sestrin2. Male Sesn2 knockout and wild-type mice were fed a high-fat diet (HFD) and treated with 12,13-diHOME. Metabolic parameters, liver histology, and lipophagy-related protein expression were analyzed. 12,13-diHOME improved insulin sensitivity, reduced plasma triglycerides and free fatty acids, and alleviated hepatic steatosis and fibrosis by enhancing lipophagy in wild-type mice. Mechanistically, 12,13-diHOME increased Sestrin2 expression, activated AMPK/ULK1 signaling, inhibited mTOR phosphorylation, and enhanced lipophagic degradation of lipid droplets. These effects were abolished in Sesn2-deficient mice and cells, demonstrating that Sestrin2 is essential for 12,13-diHOME's protective actions. Our findings identify 12,13-diHOME as a potential therapeutic agent for MASLD via Sestrin2-mediated lipophagy.},
	doi = {10.1016/j.bbadis.2026.168186},
	pmid = {41650585 [Indexed for MEDLINE]}
}

@ARTICLE{10.1186/s40168-026-02343-7,
	author = {Li C and Liu G and Yang Y and Shi Z and Shao Q and Fang Z and Song Y and Gao W and Lei L and Du X and Li X},
	title = {Altered rumen bacterial flora is associated with increased lipogenesis of adipose tissue in obese dairy cows before calving.},
	journal = {Microbiome},
	year = {2026},
	abstract = {BACKGROUND: Prepartum obesity predisposes dairy cows to a higher risk of postpartum metabolic disorder. Volatile fatty acids (VFA) produced through ruminal microbial fermentation of feed substrates serve as a key form of energy for dairy cows. However, the precise mechanisms through which the rumen microbiota promote adipocyte lipid accumulation in obese dairy cows remain to be elucidated. Thus, the aim of this study was to investigate the mechanisms by which rumen microbiota regulates prepartum obesity in dairy cows. RESULTS: Plasma glucose, insulin, triglyceride, and free fatty acids were greater in obese dairy cows. In the adipose tissue, the triglyceride content and expression of genes involved in lipid synthesis were higher in obese dairy cows. In the liver, the expression of genes involved in gluconeogenesis and lipid synthesis was higher in obese dairy cows. The ruminal total VFA, acetate, and propionate were higher in obese dairy cows compared to normal cows. The 16S rRNA gene analysis revealed that rumen bacteria, including Tidjanibacter inops_A, Rikenella massiliensis, Papillibacter cinnamivorans, and Parabacteroides merdae, were enriched in the rumen of obese dairy cows. Enrichment of these bacteria promoted carbohydrate degradation and VFA production. The metabolome analysis showed that obese dairy cows had elevated citric acid level in the rumen, which was positively associated with body condition score, body weight, adipocyte diameter, ruminal VFA concentration, and the abundance of VFA-producing bacteria. CONCLUSIONS: Our results suggest that rumen bacterial flora in prepartum obese dairy cows supply more VFA to the host, which may induce lipid deposition in adipocytes. Video Abstract.},
	doi = {10.1186/s40168-026-02343-7},
	pmid = {41645262 [Indexed for MEDLINE]},
	note = {PMC12895798}
}

@ARTICLE{10.1039/d5fo04520g,
	author = {Ji J and Yu W and Kou X and Chen C and Shao Y and Li J and Lv B and Li J and Xue Z},
	title = {Research advancements on dietary bioactive compounds ameliorating lipid deposition mechanisms via autophagy regulation.},
	journal = {Food Funct},
	year = {2026},
	abstract = {The core pathological basis of obesity and its associated metabolic diseases is excessive lipid deposition. Bioactive compounds from dietary resources, such as polyphenols and flavonoids, can significantly improve lipid homeostatic imbalance by activating autophagy pathways, especially lipophagy. This review gives a systematic analysis of the interaction mechanism between autophagy processes and lipid metabolism, focusing on the elucidation of Rab GTPase-mediated membrane transport, membrane proteins involved in lipid droplet recognition and encapsulation, as well as lipid metabolism enzymes facilitating autophagy-dependent lipid clearance. We further illustrate how dietary bioactive compounds modulate the autophagy network via multiple targets, such as the activation of AMPK or inhibition of mTOR to improve autophagy, the promotion of TFEB nuclear translocation to drive lysosomal production, and the enhancement of SIRT1 to coordinate metabolic stress response. Despite the encouraging lipid-lowering effects of these compounds, there are still challenges related to their pleiotropic targets, discrepancies between in vivo and ex vivo studies, limited bioavailability, and long-term safety. Multidisciplinary approaches should be incorporated into future research to facilitate clinical translation, structure-activity relationship analyses, and evaluations of synergistic effects. This review offers insights for developing autophagy-modulating natural dietary agents as interventions against obesity.},
	doi = {10.1039/d5fo04520g},
	pmid = {41632038 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/17446651.2026.2624400,
	author = {Mirmiranpour H and Barber TM},
	title = {The role of batokines in metabolism and their therapeutic potential.},
	journal = {Expert Rev Endocrinol Metab},
	year = {2026},
	abstract = {INTRODUCTION: Interlinkage between lipid and carbohydrate metabolism remains a key focus of research into the pathogenesis and novel management of obesity-related conditions like Type 2 Diabetes (T2DM), dyslipidaemia, and Metabolic-Associated Fatty Liver Disease (MAFLD). The activity of Brown Adipose Tissue (BAT) unifies these two facets of metabolism and holds great therapeutic potential. AREAS COVERED: Through a brief narrative review of the current literature using Pubmed, with the search terms 'batokines,' 'metabolism' and 'obesity,' we outline the diverse effects of batokines on metabolism, BAT functioning, and metabolic signaling pathways. We explore a future role of batokines in the management of obesity and T2DM, as a biomarker for BAT activity and predictor and monitor of therapeutic response to future novel mitochondrial uncoupling therapies. EXPERT OPINION: Through its key role in the metabolism of lipids and carbohydrates, the mechanisms of BAT activation shed light on the complex mechanisms that interlink obesity with T2DM and other dysmetabolic conditions. Signaling biomolecules derived from BAT ('batokines') regulate the metabolic functioning of white adipose tissue and skeletal muscle, including glucose, lipid and protein metabolism, insulin sensitivity, and energy expenditure. Insights into batokine physiology will guide the next generation of therapies for obesity and its related dysmetabolic conditions.},
	doi = {10.1080/17446651.2026.2624400},
	pmid = {41631747 [Indexed for MEDLINE]}
}

@ARTICLE{10.1186/s12933-025-03059-y,
	author = {Thorson AS and Schaefers KP and Litts B and Rein J and Adapa S and Chinnarasu S and Shapiro K and Zhao Y and Yu S and Recupido B and Streng KJ and Ahn IS and Lan R and Pierre-Louis O and Forson D and Bennett M and Luviano H and Saleem M and Zhu L and Yang X and Kirabo A, M Stafford J},
	title = {Sex‐specific cardiovascular risk in estrogen‐treated androgen‐deprived males: metabolic characterization of glucose, adipose, and lipid pathways.},
	journal = {Cardiovasc Diabetol},
	year = {2026},
	abstract = {BACKGROUND: Estrogen therapy and androgen‐deprivation were once combined to treat prostate cancer (PrCa). Clinical studies later showed that prolonged estrogen exposure in androgen‐deprived men raises cardiovascular disease (CVD) risk, yet the metabolic pathways responsible remain unclear. METHODS: We generated an androgen‐deprived, 17β‐estradiol (E2)-treated mouse model by gonadectomizing male C57BL/6 J mice and implanting sub‐cutaneous delayed‐release E2 or vehicle pellets. Mice received a Western‐style diet and were housed at thermoneutrality to accelerate CVD‐risk phenotypes. Metabolic profiling included hyperinsulinemic‐euglycemic clamps, oral lipid and pyruvate tolerance tests, flow cytometry of immune cells, and single‐nucleus RNA sequencing of liver tissue. RESULTS: In hypogonadal males, E2 treatment induced several metabolic disturbances. During clamps, E2‐treated mice showed markedly elevated gluconeogenesis, corroborated by higher glucose peaks and AUC during pyruvate tolerance testing and by up‐regulation of hepatic Pck1 mRNA. Triglyceride (TG) clearance, which improves with E2 in females, was impaired in E2‐treated males: oral lipid‐tolerance testing revealed prolonged TG excursions, reduced maximal lipase activity, lower non‐lipase clearance at 6 h post-OLTT, and decreased free‐fatty‐acid peak levels. Hepatic lipase, VLDL clearance receptors Ldlr and Lrp1, and microsomal triglyceride transfer protein (MTP) transcripts were down‐regulated. SnRNA‐seq showed suppression of lipid‐clearance genes with E2 treatment in males. Subcutaneous adipocytes were hypertrophic, and flow cytometry identified increased TNFα‐positive macrophages, an inflammatory milieu that could promote insulin resistance. Cardiac morphology was modestly altered; E2‐treated males exhibited a larger left‐ventricular end‐diastolic diameter, while ejection fraction and arterial pressure remained unchanged. CONCLUSION: Estradiol administration in androgen‐deprived male mice produces a constellation of metabolic derangements-including enhanced hepatic gluconeogenesis, impaired TG clearance, and inflammatory adipocyte hypertrophy-that likely underlie the increased CVD risk observed clinically. The identified molecular nodes (PEPCK, hepatic lipase, LRP1, LDLR, MTP, and adipose‐macrophage TNFα) provide potential targets for mitigating estrogen‐induced CVD risk while preserving its therapeutic benefit for PrCa.},
	doi = {10.1186/s12933-025-03059-y},
	pmid = {41622197 [Indexed for MEDLINE]},
	note = {PMC12955195}
}

@ARTICLE{10.1038/s41598-026-35546-x,
	author = {Eslami Z and Ghafi AG and Wong A and Asghari SH and Asadi N and Mirghani SJ},
	title = {Additive effects of high intensity interval training and therapeutic adenosine on gene and protein expression in lipid metabolism and weight loss in high fat diet-induced obese rats.},
	journal = {Sci Rep},
	year = {2026},
	abstract = {There is significant interest in the development of comprehensive strategies to combat obesity. One such approach involves the combination of exercise training with pharmacological interventions. Recently, the injection of adenosine (Ade) has garnered attention as a potential adjunctive treatment. Forty-two male rats were assigned to two dietary groups for 25 weeks: normal diet and high-fat diet (HFD). After 13 weeks, the HFD group was randomly divided into 4 subgroups for a 12-week intervention: HFD + HIIT + Ade, HFD + HIIT, HFD + Ade and HFD control. The study comprised 4 phases:1) initiation and baseline weighing, 2) fattening, 3) first intervention (Ade 0.2 mg/kg + HIIT), and 4) second intervention (Ade 0.4 mg/kg + HIIT). The HFD + HIIT + Ade group exhibited a significant increase in the expression of AMPK, HSL and A2A receptor genes and proteins compared to other groups. The highest expression of the CGI-58 gene and protein was significantly observed in the HFD + HIIT group. The ACC gene expression was significantly higher in the HFD group, while the lowest expression was observed in the HFD + HIIT group. The most significant weight loss occurred in the HFD + HIIT + Ade group. HIIT activates lipolytic pathways while concurrently suppressing lipogenic pathways, effects that are enhanced by Ade administration. Moreover, HIIT alone can stimulate Ade-mediated lipolytic receptors, with these effects further augmented by optimal doses of Ade.},
	doi = {10.1038/s41598-026-35546-x},
	pmid = {41617762 [Indexed for MEDLINE]},
	note = {PMC12914024}
}

@ARTICLE{10.1111/jog.70185,
	author = {Asano F and Momomura M and Shibuya H and Matsumoto H and Morisada T and Kobayashi Y},
	title = {Associations of Lipid Metabolism Abnormalities and Obesity With Endometriosis-Associated Ovarian Cancer.},
	journal = {J Obstet Gynaecol Res},
	year = {2026},
	abstract = {AIM: To investigate the differences in lipid metabolism and obesity between patients with ovarian endometrioid carcinoma (OEC) and ovarian clear cell carcinoma (OCCC), both of which are classified as endometriosis-associated Type I ovarian cancers. METHODS: This retrospective study included 133 patients who underwent surgery for OEC (n = 50) or OCCC (n = 83) between 2010 and 2022. Preoperative serum lipid markers (total cholesterol [TC], low-density lipoprotein cholesterol [LDL-C], and high-density lipoprotein cholesterol [HDL-C]) and body mass index (BMI) were compared between the two groups. Associations with menopausal status and disease stage were examined, and independent predictors were evaluated by multivariate logistic regression. RESULTS: Patients with OEC had significantly higher TC (215 vs. 199.5 mg/dL, p = 0.040), LDL-C (139 vs. 120.6 mg/dL, p = 0.026), and BMI (22.1 vs. 20.4 kg/m2, p = 0.020) compared with those with OCCC. No significant differences were observed for HDL-C. In premenopausal women, TC and LDL-C were significantly higher in patients with OEC, whereas no intergroup differences were found in postmenopausal women. Among patients with OEC, those with advanced-stage disease had higher TC and LDL-C, whereas no stage-related differences were observed in patients with OCCC. Multivariate analysis identified BMI and LDL-C as independent factors associated with OEC. CONCLUSION: Lipid metabolism abnormalities and obesity were more strongly associated with OEC than with OCCC, suggesting subtype-specific metabolic mechanisms of carcinogenesis and progression. These findings highlight the importance of metabolic factors in OEC, warranting further prospective studies.},
	doi = {10.1111/jog.70185},
	pmid = {41605467 [Indexed for MEDLINE]}
}

@ARTICLE{10.3390/ijms27020917,
	author = {Jäger E and Peeva V and Gnad T and Haange SB and Rolle-Kampczyk U, Stäubert C and Krumbholz P and Heiker JT and Gebhardt C, Krügel U and Sen P and Harazin M and Stab V, Münzker J and Hamdani N and Pfeifer A, von Bergen M and Till A and Fenske WK},
	title = {Antibiotic-Mediated Modulation of the Gut Microbiome Identifies Taurine as a Modulator of Adipocyte Function Through TGR5 Signaling.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Gut microbiota has emerged as a modulator of host metabolism and energy balance. However, the precise microbial metabolites mediating thermogenic activation in obesity remain largely undefined. We investigated the effect of antibiotic treatment under a high-fat diet on metabolites and its contribution to lipolysis and thermogenesis. Antibiotic treatment in high-fat diet-fed rats reduced adiposity and enhanced adaptive thermogenesis. Metabolomics revealed elevated taurine levels in the cecum content and plasma of antibiotic-treated animals, correlating with increased expressions of UCP1 and TGR5 in brown adipose tissue. Taurine enhanced lipolysis and oxygen consumption in mouse adipose tissue and human adipocytes. Thereby, taurine modulated lipolysis dependent on TGR5 signaling in adipose tissue. Human data confirmed that taurine promotes browning of white adipocytes and that acute cold exposure leads to a marked drop in circulating taurine, suggesting its rapid recruitment into thermogenic tissues. Besides its synthesis in the liver and dietary uptake, taurine can be a microbiota-derived metabolite that activates adipose thermogenesis and lipolysis through TGR5 and possibly taurine transporter-dependent mechanisms. These findings uncover a gut-adipose axis with therapeutic potential for metabolic disease.},
	doi = {10.3390/ijms27020917},
	pmid = {41596563 [Indexed for MEDLINE]},
	note = {PMC12842370}
}

@ARTICLE{10.3390/ijms27020772,
	author = {Mihaylova LV and Savova MS and Todorova MN and Tonova V and Binev BK and Georgiev MI},
	title = {Cycloastragenol Improves Fatty Acid Metabolism Through NHR-49/FAT-7 Suppression and Potent AAK-2 Activation in Caenorhabditis elegans Obesity Model.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Obesity is among the top contributing factors for non-communicable chronic disease development and has attained menacing global proportions, affecting approximately one of eight adults. Phytochemicals that support energy metabolism and prevent obesity development have been the subject of intense research endeavors over the past several decades. Cycloastragenol is a natural triterpenoid compound and aglycon of astragaloside IV, known for activating telomerase and mitigating cellular aging. Here, we aim to characterize the effect of cycloastragenol on lipid metabolism in a glucose-induced obesity model in Caenorhabditis elegans. We assessed the changes in the body length, width, and area in C. elegans maintained under elevated glucose through automated WormLab system. Lipid accumulation in the presence of either cycloastragenol (100 μM) or orlistat (12 μM), used as a positive anti-obesity control drug, was quantified through Nile Red fluorescent staining. Furthermore, we evaluated the changes in key energy metabolism molecular players in GFP-reporter transgenic strains. Our results revealed that cycloastragenol treatment decreased mean body area and reduced lipid accumulation in the C. elegans glucose-induced model. The mechanistic data indicated that cycloastragenol suppresses the nuclear hormone receptor family member NHR-49 and the delta(9)-fatty-acid desaturase 7 (FAT-7) enzyme, and activates the 5'-AMP-activated protein kinase catalytic subunit alpha-2 (AAK-2) and the protein skinhead 1 (SKN-1) signaling. Collectively, our findings highlight that cycloastragenol reprograms lipid metabolism by down-regulating the insulin-like receptor (daf-2)/phosphatidylinositol 3-kinase (age-1)/NHR-49 signaling while simultaneously enhancing the activity of the AAK-2/NAD-dependent protein deacetylase (SIR-2.1) pathway. The anti-obesogenic potential of cycloastragenol rationalizes further validation in the context of metabolic diseases and obesity management.},
	doi = {10.3390/ijms27020772},
	pmid = {41596421 [Indexed for MEDLINE]},
	note = {PMC12841531}
}

@ARTICLE{10.3390/ijms27020756,
	author = {Dairi G and Ibrahim MA and Mahri SA and Al-Regaiey K and Malik SS and Mohammad S},
	title = {RNA-Binding Proteins in Adipose Biology: From Mechanistic Understanding to Therapeutic Opportunities.},
	journal = {Int J Mol Sci},
	year = {2026},
	abstract = {Obesity, defined by excessive body fat accumulation, is strongly associated with dysfunction of adipose tissue, a major regulator of whole-body energy balance and metabolic health. Dysfunctional adipose tissue is characterized by altered adipokine secretion, impaired insulin sensitivity, and chronic low-grade inflammation, all of which contribute to obesity-related comorbidities such as type 2 diabetes, cardiovascular disease, and certain cancers. Understanding how obesity disrupts adipose tissue biology is essential for developing strategies to mitigate these metabolic risks. In recent years, RNA-binding proteins (RBPs) have emerged as important regulators of energy metabolism. By controlling post-transcriptional gene expression, RBPs influence RNA stability, localization, and translation, thereby shaping key cellular processes. Dysregulation of specific RBPs has been implicated in obesity and metabolic disorders, with several shown to affect adipogenesis, lipid handling, thermogenesis, and insulin sensitivity across different adipose depots. Their ability to direct the fate of transcripts involved in metabolic homeostasis positions RBPs as critical nodes linking adipose dysfunction to systemic disease. This review provides a mechanistic overview of RBP functions in adipose biology, highlights how their dysregulation can reinforce metabolic dysfunction, and identifies gaps and future directions for exploring RBPs and their RNA networks as potential therapeutic targets for obesity and related metabolic diseases.},
	doi = {10.3390/ijms27020756},
	pmid = {41596407 [Indexed for MEDLINE]},
	note = {PMC12840790}
}

@ARTICLE{10.3390/genes17010093,
	author = {Yu Y and Liu S and Yang J and Xu S},
	title = {Transcriptome Analysis of Adipose Tissues from Five Sheep Breeds Reveals Key Genes Involved in Fat Deposition.},
	journal = {Genes (Basel)},
	year = {2026},
	abstract = {BACKGROUND: Sheep (Ovis aries) exhibit significant diversity in adipose tissue deposition, which influences meat quality, environmental adaptation, and economic value. Tail fat, in particular, varies widely among breeds, yet the transcriptomic basis of this variation remains incompletely understood. This study aims to systematically compare the transcriptional profiles of five adipose depots across five sheep breeds to identify molecular mechanisms underlying fat deposition and tail phenotype divergence. METHODS: We analyzed 250 publicly available RNA-seq samples from five adipose tissues (caul, subcutaneous, perirenal, intermuscular, and tail fat) of five sheep breeds (Altay, Tibetan, Merino, Wadi, Small-tailed Han). Data were processed using FastQC, STAR, and featureCounts. Differential expression analysis was performed with DESeq2, followed by GO and KEGG enrichment analyses. Breeds were grouped into three tail phenotypes: fat-tailed, short fat-tailed, and thin-tailed. Cross-tissue and phenotype-specific pathway analyses were conducted to identify key regulatory genes. RESULTS: Transcriptional divergence was most pronounced in subcutaneous and intermuscular fat, while tail fat exhibited both conserved and phenotype-specific pathways. Fat-tailed breeds showed enrichment in mitochondrial oxidative phosphorylation and lipid biosynthesis genes (TAFAZZIN, GPAM, COQ family). Short fat-tailed breeds were characterized by extracellular matrix remodeling genes (MMP9, MMP12, MMP19). Thin-tailed sheep lacked these pro-lipogenic and structural remodeling pathways. A dual-axis model of tail fat development is proposed to explain phenotypic diversity. CONCLUSIONS: This study reveals that distinct molecular mechanisms underpin tail fat phenotypes in sheep: fat-tailed breeds prioritize metabolic efficiency, short fat-tailed breeds rely on ECM remodeling, and thin-tailed breeds lack these enhancements. The identified candidate genes may serve as potential targets for molecular breeding strategies aimed at optimizing fat deposition and adaptive traits in sheep.},
	doi = {10.3390/genes17010093},
	pmid = {41595512 [Indexed for MEDLINE]},
	note = {PMC12841507}
}

@ARTICLE{10.3390/biom16010101,
	author = {Zhu Q and Hu Y and Li M and Yang H and Zhao L and Zhao Y},
	title = {N(6)-Methyladenosine (m(6)A)-Mediated Regulation of Lipid Metabolism: Molecular Mechanisms, Pathological Implications, and Therapeutic Perspectives.},
	journal = {Biomolecules},
	year = {2026},
	abstract = {Dysregulated lipid metabolism constitutes the fundamental etiology underlying the global burden of obesity and its associated metabolic disorders. N6-methyladenosine (m6A) is the most abundant reversible chemical modification on messenger RNA and influences virtually every aspect of RNA metabolism. Recent studies demonstrate that m6A mediates regulatory networks governing lipid metabolism and contributes to the pathogenesis of multiple metabolic diseases. However, the precise roles of m6A in lipid metabolism and related metabolic disorders remain incompletely understood. This review positions m6A modification as a central epigenetic switch that governs lipid homeostasis. We first summarize the molecular components of the dynamic m6A regulatory machinery and delineate the mechanisms by which it controls key lipid metabolic processes, with an emphasis on adipogenesis, thermogenesis and lipolysis. Building on this, we further discuss how dysregulated m6A acts as a shared upstream driver linking obesity, type 2 diabetes (T2D), metabolic dysfunction-associated steatotic liver disease (MASLD), and insulin resistance through tissue-specific and inter-organ communication mechanisms. We also evaluate the potential of targeting m6A regulators as therapeutic strategies for precision intervention in metabolic diseases. Ultimately, deciphering the complex interplay between m6A modification and lipid homeostasis offers a promising frontier for the development of epitranscriptome-targeted precision medicine against obesity and its associated metabolic disorders.},
	doi = {10.3390/biom16010101},
	pmid = {41594642 [Indexed for MEDLINE]},
	note = {PMC12839223}
}

@ARTICLE{10.1016/j.ijbiomac.2026.150527,
	author = {Wang F and Xu S and Zhang Y and Wang Q and Zhang B and Sun X},
	title = {The LncRNA11-hnRNPA1 functional axis maintains adipose tissue metabolic homeostasis by promoting mitochondrial respiration and lipid utilization.},
	journal = {Int J Biol Macromol},
	year = {2026},
	abstract = {Long noncoding RNAs (lncRNAs) are emerging as critical regulators of metabolic homeostasis and obesity pathogenesis. Mitochondrial dysfunction is a key driver of metabolic disorders, yet the underlying regulatory mechanisms remain incompletely understood. In this study, we unveil the metabolic function of a novel lncRNA GM44386 (LncRNA11), which is abundantly expressed in brown adipose tissue and functions as a protective molecule against obesity-related energy imbalance. Genetic deletion of LncRNA11 in mice led to exacerbated adipocyte hypertrophy, insulin resistance, and severe hepatic lipid accumulation under both normal and high-fat diet (HFD) conditions. Functionally, LncRNA11 deficiency compromised mitochondrial structure, quality, and oxidative phosphorylation capacity in adipocytes, resulting in defective fatty acid oxidation and impaired thermogenesis. Mechanistically, LncRNA11 forms a complex with Heterogeneous Nuclear Ribonucleoprotein A1 (hnRNPA1) to potentiate mitochondrial glycolysis in adipose tissue by upregulating pyruvate kinase M (PKM) expression. This enhancement supplies ATP required for UCP1-mediated uncoupling, thereby helping to maintain mitochondrial integrity and adaptive thermogenesis. Collectively, our findings identify LncRNA11 as a crucial upstream regulator that coordinates thermogenic capacity and mitochondrial stability, presenting a potential therapeutic target for combating obesity.},
	doi = {10.1016/j.ijbiomac.2026.150527},
	pmid = {41592648 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.gene.2026.150023,
	author = {Li K and Wang M and Liu Y and Lu R and Zhang H and Sui X and Zhang G and Li X},
	title = {NIPSNAP3B elevates mitochondrial biogenesis to attenuate lipid accumulation in childhood obesity via AMPK pathway.},
	journal = {Gene},
	year = {2026},
	abstract = {OBJECTIVE: Childhood obesity (CO) has become a global epidemic, leading to rising burden of many diseases and premature death. Thus, this study was conducted to screen the mitochondria-associated biomarkers for patients with CO, as well as the involved molecular mechanism. METHODS: After downloading GSE29718 and GSE104815 datasets from GEO database, differential expression analysis was conducted to screen the DEGs. Then the obtained DEGs were intersected with the mitochondrial-associated genes, and mitochondrial-related genes in CO were acquired, followed by key mitochondrial-related genes screening utilizing three machine learning algorithms. The qRT-PCR and western blot were employed to determine the expression of key genes. Gain-of-function experiment was applied to investigate the function of NIPSNAP3B in CO in vitro. RESULTS: Total 364 DEGs were screened, then 18 mitochondrial-related genes in CO were obtained. These 18 mitochondrial-associated genes in CO enriched in pyruvate metabolism, arginine biosynthesis, and AMPK signaling pathway, etc. ACACB and NIPSNAP3B were considered as the key mitochondrial-related genes. Of note, NIPSNAP3B overexpression markedly reduced the TG level and the protein expression levels of PPARγ and C/EBPα in MDI-induced 3 T3-L1 cells. Also, ATP content, mitochondrial mass, MMP, and protein expression levels of PGC-1α, NRF1, and TFAM were changed after NIPSNAP3B upregulation in MDI-induced 3 T3-L1 cells. However, opposite results were observed after NIPSNAP3B downregulation. Compound C (AMPK inhibitor) or AMPK knockdown administration could reverse the effect of NIPSNAP3B on adipocyte lipid deposition and mitochondrial biogenesis. CONCLUSION: NIPSNAP3B enhances mitochondrial biogenesis to attenuate lipid accumulation via AMPK pathway in CO.},
	doi = {10.1016/j.gene.2026.150023},
	pmid = {41587668 [Indexed for MEDLINE]}
}

@ARTICLE{10.1186/s40001-026-03860-9,
	author = {Ma W and Wang C and Jiang X and Zeng Y and Liao Y and Yi B and Feng S},
	title = {Acteoside prevents high-fat diet-induced obesity by regulating brown adipose tissue production, lipid metabolism, and the gut microbiota.},
	journal = {Eur J Med Res},
	year = {2026},
	abstract = {Acteoside, a phenylethanol glycoside, possesses various pharmacological properties. The aim of this study was to investigate the mechanism of its anti-obesity effects on high-fat diet (HFD)-induced obese mice, as well as to evaluate the anti-obesity effects of its two active metabolites, caffeic acid and hydroxytyrosol. Mice were randomly divided into six groups in the first part experiment and five groups in the second part experiment as follows: control diet group; control diet + acteoside at 150 mg/kg/day group; HFD group; HFD + orlistat at 20 mg/kg/day group; HFD + caffeic acid at 45 mg/kg/day group; HFD + hydroxytyrosol at 40 mg/kg/day group; HFD + acteoside at 75 mg/kg/day group; and HFD + acteoside at 150 mg/kg/day group. The results showed that acteoside exhibited more pronounced anti-obesity effects compared with its two active metabolites. Acteoside supplementation reduced body weight and white adipose tissue (WAT) weight and improved glucose tolerance and insulin sensitivity in obese mice, as well as partially reverse hepatic damage and fat accumulation. In addition, acteoside induced the production of brown adipose tissue (BAT) when compared with caffeic acid and hydroxytyrosol, as well as promote a thermogenesis program in BAT and activate AMPK and HSL signaling in both WAT and BAT. Furthermore, high-dose acteoside supplementation altered the gut microbiota by increasing the abundance of Akkermansia muciniphila in obese mice. In summary, our results indicate that long-term acteoside supplementation may partially reverse obesity by stimulating adipose thermogenesis, modulating lipid metabolism, and altering the gut microbiota.},
	doi = {10.1186/s40001-026-03860-9},
	pmid = {41578328 [Indexed for MEDLINE]},
	note = {PMC12911377}
}

@ARTICLE{10.1016/j.psj.2026.106470,
	author = {Li Z and Malyar RM and Sun H and Ding W and Li Y and Lu L and Shi F},
	title = {Integrated lipidomic and transcriptomic analysis of intramuscular fat deposition in yellow-feathered broilers.},
	abstract = {To elucidate the molecular basis of intramuscular fat (IMF) variation in yellow-feathered broilers, we selected 10 high-IMF (HF) and 10 low-IMF (LF) breast muscle samples from a total of 214 samples, after z-score filtering for LC-MS lipidomics and RNA-seq analyses. Lipidomics identified 94 differentially expressed lipids (DELs; 83 upregulated, 11 downregulated in HF), predominantly triglycerides (TGs, 20.2%), phosphatidylethanolamines (PEs, 15.3%), phosphatidylcholines (PCs, 12.1%), and sphingomyelins (SMs, 8.4%). LION/web enrichment indicated an unsaturated lipid-rich phenotype, characterized by fatty acids containing ≥ 2 double bonds and membrane structural components. RNA-seq revealed 423 differentially expressed genes (DEGs; 312 upregulated, 111 downregulated in HF), enriched in plasma membrane, cell periphery, retinol metabolism, and steroid hormone biosynthesis pathways. RT-qPCR validation of nine lipid metabolism-related DEGs confirmed the RNA-seq trends. Cross-omics Pearson correlation between these DEGs and the top 20 DELs identified PLIN1, SCD, and APOB as central regulatory hubs strongly associated with multiple polyunsaturated TGs and PCs. Functional overlap across omics layers suggests coordinated membrane remodeling and unsaturated lipid deposition in HF breast muscle, providing a data-driven framework for future mechanistic validation and breeding strategies.},
	doi = {10.1016/j.psj.2026.106470},
	pmid = {41576438 [Indexed for MEDLINE]},
	note = {PMC12859495}
}

@ARTICLE{10.1016/j.lfs.2026.124219,
	author = {Miguéns MV, Quintela-Vilariño C and Casado S, de Oliveira-Diz T, Müller TD and Nogueiras R, Diéguez C and Tovar S},
	title = {LEAP2 acts in hepatocytes and at central level, alleviates steatosis and inflammation but resistance in obese and aging.},
	abstract = {SCOPE: Global increase in obesity and metabolic syndrome has led to a marked rise in comorbidities, with liver disease emerging as a major concern. Metabolic dysfunction-associated fatty liver disease (MAFLD) affects over 30% of the population, making it the most prevalent liver disorder worldwide. Hepatic steatosis, hallmark of MAFLD, can progress to inflammation, fibrosis, steatohepatitis, and cirrhosis. Despite advances in elucidating its mechanisms, no effective pharmacological therapy exists to reverse disease progression. Ghrelin signaling axis has been implicated in energy and lipid homeostasis, and the recent identification of liver-expressed antimicrobial peptide 2 (LEAP2) as an endogenous ghrelin receptor antagonist and inverse agonist has generated interest in its potential role in liver metabolism. The primary objective of this study was to evaluate LEAP2 on hepatocyte lipid metabolism and determine its capacity to prevent diet- and age-induced steatosis in vivo. METHODS AND RESULTS: We investigated LEAP2 actions on hepatocyte lipid metabolism using human and mouse hepatocyte cultures, also we did in vivo studies in mice with chronic central LEAP2 administration in models of diet-induced and age-related steatosis. LEAP2 inhibited lipid accumulation in hepatocytes and reduced hepatic lipid deposition in mice fed a standard diet. However, LEAP2 did not prevent high-fat diet-induced steatosis in young mice although it attenuated hepatic inflammation. In aged animals, LEAP2 failed to suppress age-associated inflammation and steatosis. CONCLUSION: LEAP2 has been identified as a novel regulator of hepatic lipid metabolism with the potential to counteract inflammation-associated steatosis, although its effects on age-related steatosis appear limited. Targeting the LEAP2-ghrelin axis may represent a promising therapeutic strategy; however, further studies are required to determine its efficacy in diet-induced hepatic disease.},
	doi = {10.1016/j.lfs.2026.124219},
	pmid = {41571146 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cmet.2025.12.012,
	author = {Tong T and Huang X and Li L and Hu M and Zhu X and Zhu B and Ma Y and Ning L and Jiang Y and Zhang Y and Zhou Y and Wang Z and Ding J and Zhao Y and Xuan B and Zhang Y and Xiao X and Fang JY and Hong J and Yin Y and Liu F and Chen H},
	title = {Microbial metabolite FAD mobilizes adipocyte lipid remodeling to enhance cancer immunotherapy efficacy.},
	journal = {Cell Metab},
	year = {2026},
	abstract = {Crosstalk between gut microbiota and adipose tissue critically shapes immunotherapy responses in patients with cancer. An obesity-associated microbial signature enriched in riboflavin-producing taxa was identified, along with increased microbial riboflavin biosynthesis pathway and elevated levels of flavin adenine dinucleotide (FAD), in obese responders to immune checkpoint blockade (ICB). In diet-induced obese (DIO) mice, fecal microbiota transplantation (FMT), administration of Lachnospiraceae bacterium, or FAD supplementation significantly enhanced the therapeutic efficacy of anti-PD-1 therapy. These interventions increased the cytotoxicity of tumor-infiltrating CD8+ T cells via mesenteric adipocyte-driven synthesis of polyunsaturated fatty acids (PUFAs). Inhibiting fatty acid desaturase 2 (FADS2) eliminated the benefits of FAD, underscoring a critical role for adipocyte-intrinsic lipid remodeling in mediating immune responses. Clinically, elevated systemic levels of PUFAs, particularly docosahexaenoic acid (DHA), were positively correlated with intratumoral CD8+ T cell infiltration and favorable immunotherapy outcomes. Dietary DHA supplementation improved ICB responses in lean mice. This study highlights that a microbiota-adipose axis shapes antitumor immunity, enabling potential personalized metabolic and microbial immunotherapy strategies.},
	doi = {10.1016/j.cmet.2025.12.012},
	pmid = {41570815 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.phymed.2026.157833,
	author = {Wang D and You Y and Luo T and Chen T and Wu X and Huang J and Gao Y and Nie G},
	title = {Puerarin 6′′-O-xyloside improves postmenopausal lipid metabolic disorders via the PPARα-mediated FAO pathway.},
	journal = {Phytomedicine},
	year = {2026},
	abstract = {BACKGROUND: Pueraria lobata (Willd.) has long been used in traditional medicine to alleviate menopausal symptoms and is commonly employed in clinical settings. Puerarin 6′′-O-xyloside (P6OX), a naturally occurring isoflavone isolated from this plant. It is structurally similar to known phytoestrogens and may modulate metabolic homeostasis. However, its effects on lipid metabolism disturbances in postmenopausal women and the underlying molecular mechanisms remain largely unexplored. PURPOSE: To evaluate the therapeutic effects of P6OX on postmenopausal lipid metabolic disorders and to elucidate the underlying molecular mechanisms. METHODS: To evaluate the efficacy of P6OX, an ovariectomized mouse model subjected to a high-fat diet (OVX + HFD) was established to mimic postmenopausal lipid metabolic disorders. In vitro studies were conducted using free fatty acid (FFA)-treated HepG2 cells. Potential molecular targets were identified through transcriptomic analysis. The involvement of the PPARα signaling pathway was further confirmed using the antagonist GW6471. RESULTS: P6OX administration significantly reduced body weight, ameliorated obesity phenotypes, improved serum lipid profiles, decreased hepatic lipid accumulation and adipocyte size, and enhanced energy metabolism in OVX+HFD mice. These effects were associated with upregulated PPARα expression and induction of its FAO-linked downstream genes. In FFA-treated HepG2 cells, P6OX effectively attenuated intracellular lipid deposition and enhanced fatty acid oxidation. The observed effects of P6OX appeared to depend on PPARα signaling, underscoring its regulatory significance. CONCLUSION: P6OX ameliorates postmenopausal lipid metabolic disorders by activating the PPARα-regulated FAO pathway, suggesting its promise as a natural, mechanism-based alternative for metabolic management.},
	doi = {10.1016/j.phymed.2026.157833},
	pmid = {41570785 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.phymed.2026.157836,
	author = {Zhang S and Wen Z and Xu X and Zhou Y and Chen Y and Zhang Y and Kan Z and Wang J and Wu B and Chen C and Ni Q},
	title = {Morus alba L. (Sangzhi) alkaloids alleviate diabetic nephropathy by suppressing endoplasmic reticulum stress and modulating AMPK-associated phosphatidylethanolamine content.},
	journal = {Phytomedicine},
	year = {2026},
	abstract = {BACKGROUND: Diabetic nephropathy (DN) is frequently characterized by significant alterations in lipid metabolism, a pathological condition that amplifies renal injury and accelerates disease progression. Sangzhi alkaloid (SZ-A), a major extract from Morus alba l., is clinically used in China for the treatment of type 2 diabetes mellitus. In addition to its antihyperglycemic effect, SZ-A has demonstrated protective activity in diabetic target organs and has shown promise in modulating lipid metabolic pathways. PURPOSE: In this study, we examined the therapeutic role of SZ-A in DN, with particular focus on its regulation of phosphatidylethanolamine (PE) biosynthesis via AMP-activated protein kinase (AMPK) signaling. METHODS: KK-Ay mice, a spontaneous model of early-stage DN, were treated with SZ-A for 12 weeks. Renal pathology was assessed by periodic acid-silver methenamine and hematoxylin-eosin staining, along with transmission electron microscopy. Renal lipid deposition and oxidative stress were evaluated by Oil Red O staining and immunohistochemical detection. Lipidomics and transcriptomics analyses were conducted to elucidate changes in PE synthesis and endoplasmic reticulum (ER) stress. RESULTS: SZ-A significantly reduced blood glucose, 24-hour urinary protein excretion, and the albumin-to-creatinine ratio, indicating improvement in renal function. SZ-A also lowered circulating lipid levels and decreased ectopic lipid accumulation in renal tissues, correlating with alterations in PE metabolism. Mechanistically, SZ-A promoted AMPK activation, thereby increasing PE content and reducing the expression of ER stress-related proteins, including IRE1, pIRE1, EIF2α, pEIF2α, and ATF4. Silencing of the PE-synthesizing enzyme Pcyt2 by siRNA abolished these effects, confirming an associated link between PE regulation and ER stress attenuation under glucolipotoxic conditions. CONCLUSION: This study finds that SZ-A significantly reduced diabetic kidney damage, acting primarily through the regulation of lipid metabolism mediated by AMPK signal.},
	doi = {10.1016/j.phymed.2026.157836},
	pmid = {41570782 [Indexed for MEDLINE]}
}

@ARTICLE{10.1038/s42003-026-09581-3,
	author = {Cheng J and Han K and Xu D and Tian H and Zhang X and Zhao L and Yang X and Zhang D and Huang K and Zhang Y and Zhao Y and Li X and Xu Q and Ma Z and Wu W and Wang J and Li F and Wang W},
	title = {Single-cell atlas reveals cellular heterogeneity and BMP5-mediated regulation of adipogenic differentiation in sheep adipose tissue.},
	journal = {Commun Biol},
	year = {2026},
	abstract = {Adipose tissue is a heterogeneous multifunctional organ, and understanding depot-specific cellular and molecular diversity reveals functional differences. Here, We construct a single-cell atlas of major adipose depots in sheep, providing foundational data for understanding regional fat deposition. We identify depot-specific adipocytes, with visceral fat (ACSS3+ADC3) and subcutaneous fat (SCD+ADC2) showing distinct adipocyte populations, and tail fat containing a specific type of fibroadipogenic progenitor cells (PDGFRA+ASPC2). Focusing on the unique tail fat of fat-tailed sheep, we conduct longitudinal developmental analyses and identify the BMP signaling pathway as a key upstream regulator of adipogenesis, with bone morphogenetic protein 5 (BMP5) as a critical ligand. We show that knockdown of BMP5 significantly reduces triglyceride accumulation in adipocytes. Collectively, this study indicates that subcutaneous fat is primarily involved in lipid metabolism, whereas visceral fat is linked to metabolic and immune homeostasis. Moreover, BMP5 was identified as a key candidate gene regulating tail fat development. These findings provide potential molecular targets for regulating fat deposition in livestock breeding and offer a valuable resource for studying adipose tissue biology in large mammals.},
	doi = {10.1038/s42003-026-09581-3},
	pmid = {41565772 [Indexed for MEDLINE]},
	note = {PMC12923642}
}

