@ARTICLE{10.1007/s13105-026-01147-5,
	author = {Soria-Gondek A and Gonzalez-Riano C, Fernández-García P and Requena B, González L and Reyes-Farias M and Murillo M and Valls A and Real N and Villarroya F and Corrales P and Cereijo R and Herrero L and Barbas C, Sánchez-Infantes D},
	title = {Subcutaneous and visceral adipose tissue lipidome in children reveals novel lipid species involved in obesity.},
	journal = {J Physiol Biochem},
	year = {2026},
	abstract = {Overweight impacts over 390 million children and adolescents worldwide, of whom around 160 million are living with obesity. Adipose tissue biology in pediatric obesity is still relatively unknown. Adaptations to obesity including fat mobilization and remodeling are being investigated. The objective was to examine the lipidomic profile of subcutaneous and visceral adipose tissue (sWAT and vWAT, respectively) in children with obesity compared to those with normal weight, in order to identify novel lipid species modulated by obesity. Thirty pediatric patients with and without obesity were prospectively recruited at a referral single center and clinical data were reported. sWAT and vWAT samples were obtained for lipidomic analysis. Novel lipid species, including ether-linked triglycerides, ether-linked phosphatidylethanolamine, and oxidized triglycerides, were identified as altered in the sWAT from children with obesity compared with normal-weight children. These species are involved in beige adipose tissue development, energy metabolism, mitochondrial function, and oxidative stress. Compared with normal-weight children, the vWAT lipidome from children with obesity showed significant changes in some glycerophosphocholines, ceramides, and diglycerides, with accumulation of lipid species involved in inflammation, insulin resistance, and cardiovascular risk. The observed lipid correlations between vWAT and sWAT highlighted systemic dysregulation of lipid storage in childhood obesity, identifying both shared and depot-specific mechanisms of lipid handling. Our study reveals several critical lipid species that are modulated across both WAT depots, with notable implications for oxidative stress, lipid storage, and adipose tissue dysfunction. Key Points • The adipose lipidome of children with obesity showed specific alterations. • Lipid correlations revealed shared and depot-specific lipid handling mechanisms. • The altered lipid species had an impact on oxidative stress and insulin resistance.},
	doi = {10.1007/s13105-026-01147-5},
	pmid = {41535500 [Indexed for MEDLINE]},
	note = {PMC12804287}
}

@ARTICLE{10.1016/j.jnutbio.2026.110263,
	author = {Chan PC and Jhuang CH and Chang HY and Hsieh PS},
	title = {Brown adipocyte-derived SAA3-CPT1A axis regulates diet-induced thermogenesis and protects against obesity.},
	journal = {J Nutr Biochem},
	year = {2026},
	abstract = {Diet-induced thermogenesis (DIT), a critical component of energy expenditure driven by brown adipose tissue (BAT), is essential for maintaining metabolic health; however, its precise molecular regulation remains poorly understood. We investigated whether serum amyloid A3 (SAA3), a factor secreted by brown adipocytes, regulates DIT and protects against diet-induced obesity. Using two distinct mouse models: mice with brown adipocyte-specific Saa3 deletion and mice with lentiviral-mediated Saa3 overexpression in BAT, we examined energy expenditure, substrate utilization, and thermogenic responses under chow or short-term high-fat diet feeding. SAA3 expression in BAT was acutely induced by refeeding. Loss of SAA3 severely diminished postprandial DIT and total energy expenditure, leading to accelerated weight gain on a high-fat diet. Mechanistically, Saa3 deletion compromised uncoupling protein‐1 induction, chiefly by impairing adipose triglyceride lipase-driven lipolysis and, critically, by inhibiting carnitine palmitoyltransferase 1A (CPT1A)-dependent fatty acid oxidation (FAO). Conversely, SAA3 overexpression robustly enhanced DIT, stimulated lipolysis and FAO, and promoted mitochondrial oxidative phosphorylation. Studies in primary brown adipocytes confirmed that SAA3 deficiency reduced CPT1A expression, palmitate-stimulated lipolysis, and mitochondrial respiration. Together, these findings identify the SAA3-CPT1A axis as a novel, BAT-intrinsic mechanism that couples nutrient sensing to uncoupling protein‐11 function via enhanced FAO. By promoting lipid utilization and postprandial energy dissipation, SAA3 optimizes postprandial thermogenesis and defends against obesity, highlighting conserved SAA signaling as a potential nutritional and therapeutic target in metabolic disease.},
	doi = {10.1016/j.jnutbio.2026.110263},
	pmid = {41534602 [Indexed for MEDLINE]}
}

@ARTICLE{10.1152/ajpregu.00259.2025,
	author = {Bruzina AS and Crum BA and Goodman LA and Ng YE and Hawe RL and Call JA and Greising SM},
	title = {Novel assessment of postprandial metabolism reveals sex-specific metabolic flexibility and lipid remodeling following volumetric muscle loss.},
	journal = {Am J Physiol Regul Integr Comp Physiol},
	year = {2026},
	abstract = {Localized skeletal muscle injury [e.g., volumetric muscle loss (VML)] can disrupt diurnal metabolic flexibility. However, it remains unclear how the evaluation of whole body metabolism and physical activity following a prandial stimuli may reveal differences in metabolic flexibility between injured and uninjured states. This study aimed to develop a novel tool to examine whole body metabolic impairments following VML injury, with consideration of lipid-related mechanisms. Adult C57BL/6J mice (n = 50; equal males and females) were randomized to a methodology development cohort to undergo VML injury, intramuscular glycerol injection, or remain as controls. The developed tool using an intraperitoneal glucose injection and indirect calorimetry was used to characterize the dynamic nature of whole body metabolism. Whole body metabolism, in vivo muscle function, and markers of lipid and glycemic regulation were evaluated 6 wk following injury. Females, regardless of injury, exhibited greater daily energy expenditure alongside increases in activity. Females exhibit lower whole body lipid oxidation during the inactive period, despite higher in active period, suggesting more coordinated substrate utilization. Biological sex differences in postprandial substrate utilization reveal that males fail to suppress whole body lipid oxidation, exhibiting marked impairments in postprandial metabolic flexibility. VML injury increases protein expression of perilipin 2 and SIRT1 in the muscle remaining, while inducing sex-specific changes, with adipose triglyceride lipase (ATGL) expression markedly increased and with perilipin 5 expression markedly reduced in females. The remaining muscle following VML accumulates neutral lipids and perilipin 1-positive adipocytes. This work highlights sex-specific mechanisms of metabolic disruption following traumatic skeletal muscle injuries, such as VML.NEW & NOTEWORTHY We developed a novel, freely ambulatory preclinical tool to assess dynamic postprandial metabolic flexibility. Using this tool, we identified sex differences in whole body energy expenditure and substrate utilization. The use of a single intramuscular glycerol injection model is not sufficient as a comparative model for evaluating chronic ectopic lipid accumulation and metabolic disruptions. In the context of volumetric muscle loss injury, disruptions in metabolic flexibility occur alongside alterations in lipid handling and ectopic lipid accumulation.},
	doi = {10.1152/ajpregu.00259.2025},
	pmid = {41533362 [Indexed for MEDLINE]},
	note = {PMC12921476}
}

@ARTICLE{10.1021/acs.jafc.5c13938,
	author = {Yang R and Li X and Tang W and Qiu X and Ma W and Wu W and Wang M and Wang C and Zhao P and Wang H},
	title = {SCD-Mediated Oleic Acid-PPARγ Self-Reinforcing Loop Drives Porcine Intramuscular Fat Deposition.},
	journal = {J Agric Food Chem},
	year = {2026},
	abstract = {Intramuscular fat (IMF) deposition is a key determinant of pork quality and canonically regulated by peroxisome proliferator-activated receptor gamma (PPARγ). However, PPARγ expression levels do not always correlate directly with fat deposition, suggesting that transcript abundance alone is insufficient to account for the adipogenic potential. Here, we identified a self-reinforcing stearoyl-CoA desaturase (SCD)-oleic acid (OA)-PPARγ feedback loop that amplifies lipid metabolic gene expression and drives efficient IMF accumulation. Multilayer omics integration and functional assays showed that SCD-derived OA acts as an endogenous ligand to activate PPARγ, while PPARγ transcriptionally upregulates SCD, together amplifying a broad lipid metabolic gene network. Both SCD overexpression and OA-delivery nanoparticles consistently promoted IMF deposition in vivo, supporting the central role of this SCD-OA-PPARγ axis. Our findings reveal a conserved but dynamic feedback mechanism underlying IMF deposition and provide a molecular explanation for breed-specific differences in pork quality.},
	doi = {10.1021/acs.jafc.5c13938},
	pmid = {41528204 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cellsig.2026.112358,
	author = {Chen PQ and Wei YD and Zheng X and Xu QT and Xu SL and He S and Xu MJ and Ge JF},
	title = {Role of CTRP9 in obesity-associated microglial dysregulation: Promoting lipophagy via the PI3K/AKT/FOXO1 signaling pathway.},
	journal = {Cell Signal},
	year = {2026},
	abstract = {Activation of microglia triggers neuroinflammation, which subsequently leads to neurological dysfunction, representing a significant pathological mechanism underlying obesity-related cognitive impairment. Microglial lipophagy plays a critical role in regulating lipid homeostasis and inflammation; however, its involvement in obesity-related cognitive impairment remains largely unexplored. The accumulation of lipid droplets in microglia is a prominent feature of aging and reflects an imbalance in microglial lipid metabolism. CTRP9 is an important regulator in this process. The aim of this study was to investigate the potential role of CTRP9 in high-fat diet-induced disruption of microglial lipid metabolism. First, cognitive impairment was observed in an obesity model induced by a high-fat diet. We then observed a significant increase in lipid droplets in hippocampal microglia, inhibition of autophagic activity, and decreased CTRP9 expression in obese mice with cognitive impairment. Additionally, both BV2 and HMC3 cells stimulated with palmitic acid (PA) displayed lipid droplet accumulation, along with impaired lipophagy. Mechanistically, PA stimulation significantly reduced CTRP9 expression. To further investigate the role of CTRP9, we demonstrated that silencing CTRP9 exacerbated lipophagy impairment and increased lipid droplet accumulation in microglia. Conversely, overexpression of CTRP9 was able to reverse the aberrant activation of the PI3K/AKT/FOXO1 signaling pathway in PA-stimulated BV2 cells, thereby ameliorating these phenotypes. Taken together, these results suggest that CTRP9 plays a crucial regulatory role in lipid metabolism disorders in high-fat-stimulated microglia, and its mechanism may be closely linked to the dysfunction of the PI3K/AKT/FOXO1 signaling pathway.},
	doi = {10.1016/j.cellsig.2026.112358},
	pmid = {41525835 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jlr.2026.100978,
	author = {Jiao H, Cázarez-Márquez F and Rumanova VS and Wang Y and Kalsbeek A and Kramer G and Guo S and Yi CX},
	title = {Targeted PPARδ activation reprograms microglial immunometabolism and improves insulin sensitivity in HFD-fed rats.},
	journal = {J Lipid Res},
	year = {2026},
	abstract = {Microglia lipid metabolism plays a crucial role in maintaining immune function and supporting neuronal health. Previous studies have shown that a high-fat diet (HFD) promotes lipid accumulation in microglia, while disruption of lipid uptake and utilization impair neuroimmune competency and accelerate obesity in response to a HFD, highlighting the importance of lipid processing under obesogenic conditions. However, whether enhancing microglial lipid metabolism can restore their immune function and mitigate obesity-associated hypothalamic dysfunction remains unclear. In this study, we investigated whether activation of peroxisome proliferator-activated receptor delta (PPARδ), a key regulator of lipid metabolism, could counteract obesity-related metabolic disturbances. Using thermal proteome profiling, we identified GW0742 as the most potent PPARδ agonist among those tested. Treatment of microglial cells in vitro with GW0742 enhanced phagocytosis, reduced inflammation, and improved microglial metabolic flexibility. To assess therapeutic potential in vivo, we selectively delivering GW0742 to mediobasal hypothalamic microglia in HFD-fed rats using polymeric nanoparticles (NPs-GW0742). This targeted intervention reprogrammed microglial activity and improved insulin sensitivity without affecting body weight or food intake, suggesting a direct central metabolic benefit. Our findings highlight the therapeutic potential of targeting microglial lipid metabolism to improve metabolic health in obesity.},
	doi = {10.1016/j.jlr.2026.100978},
	pmid = {41519472 [Indexed for MEDLINE]},
	note = {PMC12874120}
}

@ARTICLE{10.1016/j.psj.2026.106376,
	author = {Wang Z and Wang D and Liu Y and Jian Z and Wang M and Lin H},
	title = {Identification of blood biomarkers associated with hepatic lipid accumulation in aging laying hens with fatty liver.},
	abstract = {Fatty Liver Hemorrhagic Syndrome (FLHS) is a metabolic disorder characterized by excessive hepatic triglycerides (TG) accumulation, primarily affecting high-producing, caged laying hens. In surviving hens, clinical signs are often subtle, making early diagnosis challenging. This study aimed to investigate the relationship between various blood parameters and hepatic fat deposition in late-phase laying hens under both fasting and fed conditions, with the goal of identifying reliable biomarkers for fatty liver (FL) diagnosis. Contrary to common assumptions, hepatic TG levels showed no significant correlation with classical blood lipid markers such as serum TG, total cholesterol (TCHO), and glucose (GLU) (P > 0.05). Under fasting conditions, hepatic TG content was positively correlated with albumin (ALB), total amino acids (TAA), and Leu (P < 0.05), while negatively correlated with α-aminobutyric acid (α-ABA), β-alanine (β-Ala), and β-aminoisobutyric acid (β-AiBA) (P < 0.05). Ala exhibited a highly significant negative correlation with liver TG (P < 0.001). Under fed conditions, hepatic TG levels were significantly positively correlated with alanine aminotransferase (ALT), the ALT/aspartate aminotransferase (AST) ratio (P < 0.05), and ALB (P < 0.001). Additionally, liver TG content was positively correlated with body weight (P < 0.05). Untargeted metabolomics identified 57 differentially expressed metabolites (VIP > 1, P < 0.05) between the NORM and FL groups, including 28 upregulated (e.g., taurodeoxycholic acid [TUDCA], taurolithocholic acid 3-sulfate [TLCAS], D-tryptophan), while 29 were downregulated (e.g., chenodeoxycholic acid, PC (18:0/14:0), PC 32:0). Functional enrichment analysis revealed these metabolites were significantly enriched in 67 metabolic pathways, particularly those related to protein digestion and absorption, amino acid biosynthesis, and bile secretion. Fasting-state biomarkers including plasma levels of TAA, Ala, Leu, D-tryptophan metabolites and bile acids (TUDCA, TLCAS), as well as fed-state serum ALB and ALT/AST ratio, may indicate FL. The present result provides theoretical basis and detection targets for the early diagnosis of fatty liver in laying hens, and offer theoretical support for the construction of precise nutritional intervention and non-invasive screening systems.},
	doi = {10.1016/j.psj.2026.106376},
	pmid = {41518905 [Indexed for MEDLINE]},
	note = {PMC12816915}
}

@ARTICLE{10.1152/ajpgi.00225.2025,
	author = {Jang H and Bae M and Lee Y and Kang H and Kim MB and Hu S and Corvino O and Lee J and Woo H and Kostour V and Odell W and Kim A and Park YK and Lee JY},
	title = {Loss of histone deacetylase 4 in hepatocytes perturbs lipid metabolism and insulin signaling in mice with diet-induced obesity.},
	journal = {Am J Physiol Gastrointest Liver Physiol},
	year = {2026},
	abstract = {Epigenetic regulations link environmental factors to the development of obesity and metabolic dysfunction-associated steatotic liver disease (MASLD). We determined the role of hepatocyte histone deacetylase 4 (HDAC4) in the pathogenesis of MASLD. Male and female hepatocyte-specific Hdac4 knockout (Hdac4HKO) mice and control Hdac4 floxed (Hdac4fl/fl) mice were fed a high-fat, high-sucrose, high-cholesterol diet for 16 wk to induce obesity and MASLD. The loss of hepatic Hdac4 increased serum alanine transaminase activity and exacerbated hepatic steatosis with higher liver weights and triglyceride levels than Hdac4fl/fl mice in males. Hepatic expression of lipogenic genes was significantly higher in male and female Hdac4HKO mice than in controls. Moreover, primary hepatocytes and the liver of Hdac4HKO mice exhibited perturbed insulin signaling, characterized by reduced phosphorylated AKT2. Interestingly, hepatocyte Hdac4 loss increased inflammatory and fibrogenic genes in gonadal white adipose tissue (gWAT). Serum cytokine array and proteomic analysis demonstrated alterations in several serum factors, which may contribute to crosstalk between the liver and WAT in Hdac4HKO, leading to obesity-induced metabolic dysfunction in gWAT. In conclusion, hepatocyte Hdac4 loss exacerbates hepatic steatosis, accompanied by disturbed insulin signaling and WAT inflammation and fibrosis in obese mice, underscoring its crucial role in liver-WAT crosstalk.NEW & NOTEWORTHY We examined the role of hepatocyte histone deacetylase 4 (HDAC4) in the development of obesity and metabolic dysfunction-associated steatotic liver disease (MASLD) using Hdac4-deficient mice with hepatocyte-specific deletion. We found that deleting Hdac4 in hepatocytes worsens hepatic steatosis and disrupts insulin signaling in the liver. In addition, this deletion caused inflammation and fibrosis in the white adipose tissue of obese mice, highlighting the role of HDAC4 in the liver-adipose axis.},
	doi = {10.1152/ajpgi.00225.2025},
	pmid = {41512278 [Indexed for MEDLINE]}
}

@ARTICLE{10.1096/fj.202501928RR,
	author = {de Oliveira ACC, Babêtto AM and Silva ML, de Souza Barbosa Lacerda L, de Souza Rodrigues T, de Oliveira MC and Rouault C and Gautier EL and Oliveira AG, Clément K and Teixeira MM and Marcelin G and Ferreira AVM},
	title = {TNF/TNFR1 is a Key Regulator of Prolonged Fasting-Induced Decrease in Adipose Tissue.},
	journal = {FASEB J},
	year = {2026},
	abstract = {Nutrient availability influences white adipose tissue (WAT) inflammation, leading to decreased or increased adiposity. Tumor necrosis factor (TNF) is elevated in WAT under both conditions, being involved in lipolysis and regulation of interleukin 18 (IL-18) secretion, which may regulate lipolytic processes. However, the role of these cytokines in adiposity reduction due to low energy availability remains unclear. Wild-type (WT) mice fasted for 24 h showed decreased adiposity, whereas TNFR1 knockout mice (TNFR1-/-) were unresponsive to fat pad loss, even after 48-h fasting. TNFR1-/- mice were also resistant to β3-adrenergic receptor agonist CL316,243-induced fat mobilization, which was linked with reduced expression of lipases, β3-adrenergic receptors, and cytokines in WAT. Also, mice treated with the TNF-α inhibitor infliximab and fasted for 48 h showed resistance to adiposity loss, suggesting that prolonged fasting-induced TNF signaling may modulate adipose tissue reduction. Conversely, IL-18 does not seem to influence fat pad loss induced by 24-h fasting as IL-18 knockout mice (IL-18-/-) express TNF in WAT and respond to prolonged fasting similarly to WT animals. To assess the potential translational relevance of our findings to human obesity, we analyzed 53 samples from patients with obesity who underwent bariatric surgery. Interestingly, TNFR1 and IL-18 expressions in sWAT correlate with the expression of lipases and adipokines in the subcutaneous site despite no correlation with body weight or fat mass 1 year after surgery. In summary, this study suggests that the TNF/TNFR1 axis is crucial for metabolic adaptation and is a prerequisite for prolonged fasting-induced lipolysis in male mice.},
	doi = {10.1096/fj.202501928RR},
	pmid = {41508774 [Indexed for MEDLINE]},
	note = {PMC12784137}
}

@ARTICLE{10.1016/j.ejphar.2026.178523,
	author = {Sun Y and Xia Y and Ge W and Li Q},
	title = {Tirzepatide reduces intracellular lipid content by promoting the browning of white fat via the cAMP signaling pathway.},
	journal = {Eur J Pharmacol},
	year = {2026},
	abstract = {Tirzepatide is well known for its glucose-lowering and weight-reducing effects, primarily through central appetite suppression. However, its direct role in promoting white adipose tissue (WAT) browning and the underlying mechanisms remain unclear. We investigated Tirzepatide's direct effects on WAT in high-fat diet (HFD)-induced obese mice. RNA sequencing was performed to assess transcriptional changes in WAT. In vitro, differentiated 3T3-L1 adipocytes were treated with Tirzepatide, with or without the adenylyl cyclase inhibitor SQ22536, to explore the involvement of cAMP-dependent signaling. Tirzepatide significantly reduced body weight as well as perirenal white adipose tissue (prWAT) and inguinal white adipose tissue (ingWAT) mass, accompanied by a marked reduction in adipocyte hypertrophy in obese mice. Transcriptomic analysis revealed a coordinated upregulation of gene programs involved in thermogenesis and lipid metabolism. These molecular changes were confirmed by immunoblotting and immunohistochemistry, which showed increased expression of browning markers, including peroxisome proliferator-activated receptor gamma coactivator 1-alpha (PGC-1α) and uncoupling protein 1 (UCP1), indicating a phenotypic shift of WAT toward a thermogenic state. In 3T3-L1 adipocytes, Tirzepatide activated the PGC-1α/UCP1 signaling axis in a cAMP-dependent manner, promoting white fat browning and reducing lipid droplet accumulation. The presence of SQ22536 attenuated these effects, highlighting cAMP signaling as a critical mediator of Tirzepatide's action. Collectively, these results demonstrate that Tirzepatide induces WAT browning via activation of the cAMP-PGC-1α-UCP1 signaling axis, leading to decreased lipid storage. These findings reveal a direct, adipocyte-intrinsic mechanism of action that extends Tirzepatide's therapeutic potential beyond its established effects on central appetite regulation.},
	doi = {10.1016/j.ejphar.2026.178523},
	pmid = {41506434 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/21623945.2025.2603605,
	author = {Chen C and Gao H and Tian Q and Cao J},
	title = {cAMP-PKA/EPAC signaling pathways: crucial regulators of lipid homeostasis.},
	journal = {Adipocyte},
	year = {2026},
	abstract = {Adipose omeostasishomoeostasis is maintained through the precise coordination of lipogenesis, lipolysis, and adipocyte differentiation, with microenvironmental components dynamically regulating lipid metabolism. Even though the classical cAMP-PKA pathway has been well-characterized for its function in lipid metabolism by phosphorylating transcription factors and lipolytic enzymes, little is known about how it collaborates with elements of the adipose tissue microenvironment, such as immune cells and the vascular endothelium, especially in pathological situations like obesity. EPAC, a newly discovered cAMP effector, has shown new signalingsignallingsignalling signalling pathways in the immune and cardiovascular systems by activating small G proteins. However, there are important understanding gaps regarding its roles in adipose metabolism, namely adipocyte development, microenvironmental interaction, and the pathophysiology of metabolic diseases. By bringing together disparate studies on PKA and EPAC, this review provides the first comprehensive synthesis of the cAMP-PKA/EPAC dual signaling signalling signallingcins signalling network, filling in knowledge gaps. The reciprocal regulation between this signaling signalling signalling signalling network and the adipose microenvironment establishes a novel 'signaling-microenvironment-systemic metabolism' framework for understanding metabolic disorders, including obesity, diabetes, and hepatic steatosis. Pharmacological modulation of the PKA/EPAC signalingsignalling signalling signalling pathways may therefore represent a viable therapeutic approach for restoring adipose tissue homeostasis homoeostasis.},
	doi = {10.1080/21623945.2025.2603605},
	pmid = {41503874 [Indexed for MEDLINE]},
	note = {PMC12785204}
}

@ARTICLE{10.1016/j.bbalip.2026.159715,
	author = {Tian L and Wang G and Zhang S and He Z and Zhao F and Chang M and Han W and Ye D and Li S and Yang G},
	title = {MiR-432 mediates bidirectional regulation in the determination of adipocyte fate.},
	journal = {Biochim Biophys Acta Mol Cell Biol Lipids},
	year = {2026},
	abstract = {Fat deposition represents a fundamental physiological process in mammalian energy metabolism, yet its molecular regulatory mechanisms remain incompletely understood. Adipocytes, the primary site of fat storage, develop through proliferation and differentiation of preadipocytes-a process controlled by multiple molecular regulators. MicroRNAs (miRNAs) act as crucial post-transcriptional regulators and play an essential role in mammalian adipogenesis. However, their specific functions in ovine tail fat deposition remain poorly characterized. This study aimed to systematically investigate the regulatory role of miR-432 in adipogenesis using sheep tail fat as a model system. Through establishing an in vitro preadipocyte culture model and implementing gain- and loss-of-function approaches via miRNA overexpression and antisense oligonucleotide inhibition, we demonstrated that elevated expression of miR-432 significantly enhanced preadipocyte proliferation, accompanied by upregulation of proliferation-related genes (Cyclin D, PCNA). However, it decreased lipid droplet accumulation and reduced the expression of differentiation markers (PPARγ, FABP4). Conversely, inhibition of miR-432 reduced cellular proliferation, downregulated key cell cycle genes (CCNB1, Cyclin B3), and enhanced adipogenic differentiation, as evidenced by increased lipid droplet formation and elevated expression of adipogenic genes (PPARγ, Adiponectin, FABP4). These findings demonstrate that miR-432 exerts a dual regulatory role in sheep tail adipogenesis by modulating both proliferative and differentiative processes in adipocytes. This research provides novel molecular insights into the regulatory mechanisms underlying fat deposition.},
	doi = {10.1016/j.bbalip.2026.159715},
	pmid = {41500444 [Indexed for MEDLINE]}
}

@ARTICLE{10.1126/sciadv.adz1385,
	author = {Hu R and Park J and Qian Y and Xiong S and Elsabbagh AH and Chhikara A and Fan H and Shi Z and Liu L and Li Y and Song Z and Mahmoud AM and Chen J and Baur JA and He Y and Layden BT and Zhou Z and Xu P and Ong SG and Wang Z and Jiang Y},
	title = {ERα activates NAMPT/IL-33 signaling to enhance beige thermogenesis and metabolic fitness.},
	abstract = {Beige adipocytes are inducible thermogenic fat cells that emerge within white adipose tissue (WAT) in response to thermogenic stimuli and confer metabolic benefits. However, obesity impairs the generation of beige adipocytes, and the underlying mechanisms remain poorly understood. Here, we show that obesity leads to a loss of adipose progenitor cells (APCs) in WAT, accompanied by reduced estrogen (E2) levels and nicotinamide phosphoribosyltransferase (NAMPT) expression. Supplementation with E2 or nicotinamide mononucleotide (NMN), an NAMPT-derived nicotinamide adenine dinucleotide (NAD+) precursor, restores beige adipogenesis in diet-induced obese mice. Mechanistically, estrogen receptor α (ERα) in APCs is required for beige fat formation by promoting Nampt transcription. We further demonstrate that NAMPT is both necessary and sufficient to drive APC proliferation and differentiation, with interleukin-33 (IL-33) acting downstream to mediate these effects. These findings uncover a critical ERα/NAMPT/IL-33 axis that preserves progenitor function and thermogenic capacity, offering a potential therapeutic strategy to combat obesity-induced beige fat failure and associated metabolic dysfunction.},
	doi = {10.1126/sciadv.adz1385},
	pmid = {41499496 [Indexed for MEDLINE]},
	note = {PMC12778055}
}

@ARTICLE{10.1016/j.ijbiomac.2025.150072,
	author = {Zhang Y and Chu M and Fan L and Bao P and Zhang L and Chai X and Yan P},
	title = {microRNA profiling unravels an abundant bta-miR-181a_R-1 that regulates yak adipogenic differentiation via the SIRT/FoxO1 pathway.},
	journal = {Int J Biol Macromol},
	year = {2026},
	abstract = {Yaks (Bos grunniens) have evolved distinctive metabolic adaptations that enable survival under the prolonged cold and nutrient-deficient conditions of the Qinghai-Tibetan Plateau. Adipose tissue plays a pivotal role in maintaining energy homeostasis. The proliferation and differentiation of preadipocytes are critical for the development of adipose tissue in bovines. MicroRNAs (miRNAs) are small regulatory molecules that participate in many cell biological processes, including development, differentiation, apoptosis, and metabolism. However, the expression profiles and functional roles of miRNAs in yak lipid metabolism remain largely unknown. To elucidate the molecular mechanisms underlying yak adipogenesis, we performed miRNA sequencing during yak preadipocyte differentiation and identified stage-specific expression profiles. Data analysis indicated that 252 (day 12 vs day 0), 167 (day 12 vs day 2), and 103 (day 2 vs day 0) miRNAs were differentially expressed in three stages, respectively. Further analysis identified 13 differentially co-expressed miRNAs across the three stages. Among the differentially co-expressed miRNAs, bta-miR-181a_R-1 was markedly upregulated during adipogenic differentiation. Functional assays revealed that bta-miR-181a_R-1 dramatically increased triglyceride accumulation and the expression of adipogenic marker genes (PPARγ, FABP4, and C/EBPα, P < 0.05), whereas it did not significantly affect preadipocyte proliferation. Mechanistically, bta-miR-181a_R-1 directly targeted sirtuin 1 (SIRT1), resulting in enhanced acetylation of forkhead box O1 (FoxO1) and promotion of lipid deposition via the FoxO signaling pathway. These findings reveal a novel miR-181a_R-1/SIRT1/FoxO1 regulatory axis that promotes yak adipocyte differentiation, providing new insights into miRNA-mediated adipogenesis in ruminants and a potential molecular basis for improving fat deposition in high-altitude livestock.},
	doi = {10.1016/j.ijbiomac.2025.150072},
	pmid = {41485665 [Indexed for MEDLINE]}
}

@ARTICLE{10.1007/s12010-025-05504-w,
	author = {Eslami A and Ghayourvahdat A and Muhammad FA and Albadr RJ and Taher WM and Alwan M and Jawad MJ and Al-Nuaimi AMA and Azimizonuzi H},
	title = {An Overview of the Effects of Exercise on Viral Infection in Obesity: Recent Advances and Potential Mechanisms.},
	journal = {Appl Biochem Biotechnol},
	year = {2026},
	abstract = {The intersection of the global obesity epidemic with viral infection pandemics poses a significant public health problem. Obesity increases virus severity by inducing dyslipidemia-characterized by defective low-density lipoprotein (LDL) and high-density lipoprotein (HDL) particles-and establishes a condition of chronic, low-grade inflammation that undermines both innate and adaptive immunity. Moreover, cholesterol-enriched lipid rafts (LRs) in the plasma membrane, which are crucial for viral entry and replication, provide a molecular connection between dysregulated lipid metabolism and viral life cycles. Although exercise is acknowledged for its benefits to metabolic and immunological health, a thorough synthesis of its precise function in influencing the relationship between obesity and viral infection is lacking. This review examines the impact of exercise on lipid metabolism and adipose tissue function, as well as its subsequent effect on antiviral immunity. We discuss how exercise training may mitigate obesity-induced dyslipidemia, promote the health of white adipose tissue, reduce inflammation, and enhance both humoral and cellular immune responses. We also compile research about the direct impacts of exercise on different viral illnesses. In summary, obesity intensifies viral infections via dyslipidemia and compromised immunity. This study has identified a significant gap by demonstrating that regular exercise is a crucial non-pharmacological strategy for mitigating these hazards. We have outlined the comprehensive mechanism by which exercise enhances lipid metabolism and adipose tissue function, consequently strengthening antiviral immunity and disrupting the cycle of obesity-related susceptibility to severe viral diseases. Consequently, physical exercise should be regarded as a fundamental preventive measure.},
	doi = {10.1007/s12010-025-05504-w},
	pmid = {41485170 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.carbpol.2025.124809,
	author = {Lan W and Huang L and Teng J and Xia N and Song M and Li S and Li J},
	title = {Structural characterization and lipid-modulating effects of an inulin-type fructan from Bacillus amyloliquefaciens D189: Unraveling the microbiota-gut-liver axis.},
	journal = {Carbohydr Polym},
	year = {2026},
	abstract = {Our prior study isolated Bacillus amyloliquefaciens D189 from Liu-pao tea fermentation, finding its exopolysaccharide possessed lipid-lowering activity. This work addressed its unexplored EPS structure and in vivo anti-obesity mechanism. D189 produced a hybrid branched fructan-type EPS with a previously uncharacterized structure in the Bacillus genus, distinguishing it from other documented EPS. Its core comprises a β-(2→1)-linked fructofuranose backbone with α-(3,6)-linked glucopyranose branches and terminal β-fructofuranose residues via β-(2→3)/β-(2→1) linkages. In high-fat diet (HFD) mice, D189 EPS exhibited low-dose efficacy: 50 mg/kg significantly reduced LDL-C (surpassing positive controls), while 200 mg/kg yielded anti-obesity effects equivalent to 300 mg/kg inulin-type polysaccharides. Its metabolic benefits operated through: gut microbiota remodeling-enriching SCFA producers (Blautia for butyrate; Muribaculaceae for acetate/propionate) while suppressing pro-inflammatory Allobaculum/Lachnospiraceae. This was accompanied by elevations in butyrate (62.89%) and isovalerate (74.50%), which modulated folate/steroid pathways to reduce hepatic lipid deposition. Concurrently, the treatment decreased hyperlipidemia marker β-muricholic acid by inhibiting CDCA synthesis and enhancing its conversion to secondary bile acids (3β-HDCA/3β-UDCA), thereby lowering primary/secondary bile acid ratios. The treatment also restored hepatic FXR signaling (normalizing Cyp7a1/Cyp8b1) and ileal ASBT transporter expression. This study demonstrated that D189 EPS attenuated obesity by targeting the microbiota-gut-liver signaling pathway, suggesting its potential for metabolic disorder therapy.},
	doi = {10.1016/j.carbpol.2025.124809},
	pmid = {41475763 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.phrs.2025.108080,
	author = {Colognesi M and Gabbia D and Signor A and Sarill M and Centofanti L and Rinaldi A and Cascione L and Nunziata S and Banzato M and Mattarei A and Finzi G and Sonda S and Pendin D and Zanotto I and Comai S and Pasut G and Alajati A and Saponaro M and Bucciarelli L and Lunati ME and Guarato G and Goggi I and La Rosa S and Morano C and Paroni RC and Dei Cas M and Daniele G and Gentilucci M and Pappagallo M and Alimonti A and Manfredi PL and Folli F and De Martin S},
	title = {Low, non-psychedelic doses of psilocybin as a novel treatment for MASLD, obesity and type 2 diabetes via 5-HT2B receptor-dependent mechanisms.},
	journal = {Pharmacol Res},
	year = {2026},
	abstract = {The therapeutic potential of low, non-psychedelic doses of psilocybin, a fungal tryptamine alkaloid, was investigated in metabolic disorders including obesity, type 2 diabetes mellitus (T2DM), and liver steatosis. Mice fed a high-fat/high-fructose diet received chronic treatment with psilocybin (0.05 mg/kg) for 12 weeks. Body weight, liver histology, insulin sensitivity, and skeletal muscle function were assessed, and hepatic and muscle tissues underwent transcriptomic and lipidomic analyses. The role of three serotonin receptors (5-HT2A, 5-HT2B, and 5-HT2C) in psilocybin-induced metabolic effects was examined in human cell lines using pharmacological and CRISPR/Cas9-based genetic approaches. Low-dose psilocybin reduced body-weight gain, liver steatosis, hyperglycaemia, and insulin resistance without eliciting central nervous system effects. Multi-omics analyses revealed near-complete normalization of disrupted hepatic lipid and carbohydrate metabolism pathways. Psilocybin also improved muscle strength and function, potentially through restoration of leptin sensitivity. Mechanistic studies demonstrated that these metabolic benefits were independent of the canonical psychedelic target 5-HT2A and instead resulted from antagonism of the serotonin 5-HT2B receptor in the liver. Overall, chronic low-dose psilocybin exerts broad metabolic benefits via a hepatic 5-HT2B-dependent mechanism, distinct from its psychedelic effects, supporting its potential as a novel therapeutic strategy for liver steatosis, obesity, T2DM, and sarcopenia.},
	doi = {10.1016/j.phrs.2025.108080},
	pmid = {41475502 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jnutbio.2025.110245,
	author = {Kwon H and Seo DS and Ahmad Y and Park S and Yoo J and Lee J and Bae HJ and Jang Y},
	title = {Complementary mechanisms of high-carbohydrate diets and ketogenic diets restore adult hippocampal neurogenesis and cognitive function in high-fat diet induced obesity in mice.},
	journal = {J Nutr Biochem},
	year = {2026},
	abstract = {High-fat diet (HFD)-induced obesity impairs cognition and hippocampal neurogenesis, linked to reduced metabolic flexibility between mitochondrial fatty acid β-oxidation (FAO) and cytosolic de novo lipogenesis (DNL). It is not fully understood if switching to a high-carbohydrate diet (HCD) or a ketogenic diet (KD) could reverse these HFD-induced deficits, or if they do so through different mechanisms. Male C57BL/6J mice received HFD for 8 weeks to induce obesity. Mice were then either maintained on the HFD or switched to an HCD or KD for an additional 8 weeks. We evaluated systemic metabolism (body weight, serum biochemistry), tissue-specific metabolic remodeling (RNA-seq, histology, RT-qPCR, Western blot) and cognitive function (Y-maze test, novel object recognition test). Both HCD and KD interventions reversed HFD‐induced systemic abnormalities, including reducing ALT/AST, cholesterol, and LDL, and attenuating hepatic steatosis and adipocyte hypertrophy. Metabolically, KD markedly increased β‐hydroxybutyrate, whereas HCD showed a distinct triglyceride profile. Both diets improved hippocampus-dependent working and recognition memory. Hippocampal RNA‐seq revealed diet-specific mechanisms. HCD enriched anabolic processes, including upregulation of glucose transporters (Glut 1, 2, 3, 4) and DNL pathway (ACLY-ACC-FASN-SCD1). Conversely, KD enriched AMPK signaling, increasing monocarboxylate transporters (Mct 1, 2, 4) for ketone uptake and activating the neurotrophic AMPK-ERK-CREB-BDNF pathway. In conclusion, post-HFD switching to HCD or KD restores hippocampal structure and cognition via complementary mechanisms. HCD drives a substrate-centric, lipogenic program supporting proliferation, whereas KD engages a signaling-centric, neurotrophic program enhancing plasticity. Metabolic flexibility is a promising target for obesity-associated cognitive decline.},
	doi = {10.1016/j.jnutbio.2025.110245},
	pmid = {41475465 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.psj.2025.106334,
	author = {Li M and Liu M and Yang Y and Ruan J and Gu Z and Ge C and Cao W},
	title = {Transcriptomic and metabolomic insights into lipid metabolism genes underlying meat quality differences between yellow-feathered and white-feathered broilers in China.},
	abstract = {One important element impacting meat quality is fat metabolism, which mainly affects meat features through intramuscular fat deposition. Chinese native yellow-feathered broilers and white-feathered broilers differ significantly in intramuscular fat concentration. This study used transcriptomic and metabolomic sequencing technologies to identify a total of 173 differentially expressed genes and 259 differential metabolites in the pectoral muscles of Chahua Chicken No. 2 and Cobb broiler in order to explore the genetic mechanisms by which lipid metabolism influences meat quality in Chinese indigenous yellow-feathered and white-feathered broilers. These included differentially expressed genes like FABP1, LPL, ELOVL7, SLC27A1, MOGAT1, and ULK2, which were enriched in pathways relevant to lipid metabolism and showed strong associations with γ-linolenic acid and palmitaldehyde, two distinct metabolites. In order to develop local chicken germplasm resources and breed superior indigenous chicken varieties, these candidate genes could serve as the genetic foundation for the variations in meat quality and lipid metabolism between Chinese native yellow-feathered and white-feathered broilers.},
	doi = {10.1016/j.psj.2025.106334},
	pmid = {41475172 [Indexed for MEDLINE]},
	note = {PMC12804028}
}

@ARTICLE{10.1016/j.ygeno.2025.111182,
	author = {Fu X and Zhao L and Tian H and Zhang D and Zhang Y and Zhao Y and Cheng J and Li X and Xu Q and Xu D and Yang X and Ma Z and Wu W and Li F and Wang W and Zhang X},
	title = {Genome-wide association and transcriptome studies identify candidate genes regulating perirenal fat deposition in sheep.},
	journal = {Genomics},
	year = {2026},
	abstract = {Perirenal fat deposition significantly impacts sheep carcass quality and economic efficiency. To elucidate the underlying genetic regulation, we performed a genome-wide association study (GWAS) on 556 Hu sheep and a comparative transcriptome analysis on 24 Hu sheep (12 with high- and 12 with low-perirenal fat deposition), all with accurate phenotypic records. Furthermore, hub genes and tissue-specific genes (TSGs) were discerned through weighted gene co-expression network analysis (WGCNA) and by leveraging RNA-Seq data from 12 tissues, respectively. qRT-PCR is used to validate the accuracy of RNA-Seq data. GWAS identified significant SNPs near genes including SETD4, TIMP2, SOCS3, and DNAH17. Comparative transcriptome analysis of HPF and LPF groups identified 2072 differentially expressed genes (DEGs), which were significantly associated with lipid storage (LPL), fatty acid homeostasis (APOE, GOT1), and biosynthesis (ACACA). A total of 2333 differential alternative splicing events were identified in 1169 genes, with skipped exons (SE, 30.65 %) being the most common. GO analysis of these SEs showed links to RNA splicing and lipid metabolism, with genes like BSCL2, DGAT1, PLIN5, and PNPLA2 involved in lipid droplet organization and triglyceride storage. WGCNA revealed key modules that were positively and negatively correlated with perirenal fat deposition, emphasizing hub genes (SAR1B, THRSP, ACSS2, KIF5B) associated with lipid droplet organization and metabolism. The integrated analysis of GWAS and RNA-seq identified TIMP2, SOCS3, and DNAH17 as potential key genes involved in regulating perirenal fat deposition in sheep. An association analysis of 372 Hu sheep populations identified significant links (P < 0.05) between perirenal fat deposition traits and mutations in the TIMP2 (g.9759169 G > A) and DNAH17 (g.9494469C > T) genes. Crucially, tissue-specific gene analysis across 12 tissues identified 448 perirenal fat TSGs, of which 75 were also differentially expressed genes (e.g., LPL, THRSP, LEP, ADRB3). In conclusion, our multi-omics study identified key genes influencing perirenal fat deposition in sheep. Notably, mutations in TIMP2 and DNAH17 could serve as candidate markers for enhancing carcass quality through marker-assisted selection.},
	doi = {10.1016/j.ygeno.2025.111182},
	pmid = {41453584 [Indexed for MEDLINE]}
}

@ARTICLE{10.1152/ajpendo.00213.2025,
	author = {Shimada BK and Ogawa-Wong AN and Soares AG and Hallam KA and Santiago PJD and Saelua K and Nakahara-Akita KK and Torres DJ and Brockman JD and Kurokawa S and Ewell KL and Bellinger MT and Toh P and Lagatta Pamplona Remedios G and Alfulaij N and Swanson SM and Seyedali A and Zavacki AM and Berry MJ and Seale LA},
	title = {Global loss of selenocysteine lyase in mice drives lipid accumulation in brown adipocytes.},
	journal = {Am J Physiol Endocrinol Metab},
	year = {2026},
	abstract = {The enzyme selenocysteine (Sec) lyase (SCLY) decomposes Sec, releasing selenide for the synthesis of selenoproteins, which contain Sec in their primary structure and participate in strong redox reactions, maintaining redox balance. We previously showed that global disruption of the Scly gene (Scly KO) in mice leads to obesity. Targeted deletion of Scly in agouti-related peptide neurons enhances energy expenditure and brown adipose tissue (BAT) activation, augmenting leanness. We hypothesized that Scly KO mice develop obesity due to failure of BAT-controlled mechanisms of energy expenditure due to redirection of Sec to an alternative pathway. We analyzed BAT from male Scly KO mice on selenium (Se)-adequate [0.25 parts per million (ppm)] and Se-deficient (0.08 ppm) diets for morphology, Se content, selenoprotein expression, thyroid hormones, and additional Sec-using pathways. We found that the BAT of Scly KO mice was enlarged, with lower Se levels, and substantial whitening on a Se-adequate diet. This phenotype worsened on low Se and coincided with a mild impairment in adapting to cold exposure. BAT whitening coincided with an increase in triglycerides and reduced 3-hydroxy-3-methylglutaryl coenzyme A and cholesterol. BAT selenoproteins regulating energy metabolism, type 2 iodothyronine deiodinase (DIO2), glutathione peroxidase 1 (GPX1), and glutathione peroxidase 1 (GPX4), were significantly decreased. DIO2 reduction corresponded with an increase in thyroxine and thyroid-stimulating hormone and a reduction in heat-producing uncoupling protein 1. Downregulation of GPX4 did not affect ferroptosis in the BAT. Therefore, the whitened BAT of the Scly KO mouse is a multifactorial process involving the disruption of BAT function through changes to selenoproteins involved in energy metabolism.NEW & NOTEWORTHY Global loss of the selenocysteine-decomposing enzyme selenocysteine lyase in mice leads to lipid accumulation and whitening of the brown adipose tissue, with consequent obesity development. Selenocysteine lyase modulates selenium levels and selenoprotein expression, specifically GPX1, GPX4, and DIO2, in brown adipocytes. Selenocysteine metabolic fate hinges on the actions of selenocysteine lyase.},
	doi = {10.1152/ajpendo.00213.2025},
	pmid = {41452587 [Indexed for MEDLINE]},
	note = {PMC12857770}
}

@ARTICLE{10.1021/acs.jafc.5c12282,
	author = {Sang T and Xu T and Chen C and Wu J and Zhou C and Li F and Xu L and Liu S and Wang M and Zhang Y and Xia D and Chu L},
	title = {Ganoderma lucidum Polysaccharides Alleviate High-Fat Diet-Induced Obesity by Promoting Lipolysis and Inhibiting Inflammation through Lactobacillus johnsonii-Butyrate Axis.},
	journal = {J Agric Food Chem},
	year = {2026},
	abstract = {Ganoderma lucidum polysaccharides (GLPs) exert antiobesity effects that are linked to gut-microbiota modulation, yet the underlying mechanisms remain elusive. Here, we show that GLPs raise the fecal butyrate level, which in turn inhibits high-fat diet (HFD)-induced weight gain, fat accumulation, adipocyte hypertrophy, and elevated serum triglyceride by promoting adipose triglyceride lipase (ATGL) expression to activate lipolysis. GLPs and butyrate also strengthen the intestinal barrier, reflected by elevated tight junction proteins and goblet cells, leading to reduced serum lipopolysaccharide-binding protein (LBP) and attenuated white-adipose-tissue (WAT) inflammation. The intestinal barrier enhancement involves FABP4-PPARγ signaling. In addition, the butyrate-enhancement and antiobesity effects of GLPs are abolished after antibiotic-mediated microbiota depletion. Notably, GLPs selectively enrich the abundance of Lactobacillus, especially Lactobacillus johnsonii, whose supplementation alone increases fecal butyrate and recapitulates GLPs-induced benefits by reinforcing gut barrier integrity and lipolysis. Collectively, our findings identify the L. johnsonii-butyrate axis as a central target through which GLPs attenuate obesity and associated inflammation.},
	doi = {10.1021/acs.jafc.5c12282},
	pmid = {41442582 [Indexed for MEDLINE]}
}

@ARTICLE{10.1161/ATVBAHA.125.323273,
	author = {Yeh YS and Huang J and Liu Z and Cosme C Jr and Zhang X and Razani B},
	title = {Cytosolic Versus Lysosomal Lipolysis in Adipose Tissue: Opposing Roles in Cardiometabolic Disease.},
	journal = {Arterioscler Thromb Vasc Biol},
	year = {2026},
	abstract = {Adipose tissue lipid metabolism is a critical regulator of systemic energy balance, but its impact on cardiometabolic health is paradoxical. This review dissects the 2 primary lipolytic systems in adipocytes: the canonical cytosolic pathway driven by ATGL/PNPLA2 (adipose triglyceride lipase) and the lysosomal pathway governed by LAL/LIPA (lysosomal acid lipase). We present emerging evidence that these pathways exert opposing effects in the context of obesity. While excessive fatty acid efflux from dysregulated cytosolic lipolysis is a known driver of adiposopathic dyslipidemia, adipose inflammation, and direct cardiac lipotoxicity, which collectively impair cardiometabolic health, the activity of the lysosomal pathway is emerging as a protective counterbalance. Genetic and pharmacological studies demonstrate that inhibiting cytosolic ATGL is beneficial for metabolic health, whereas enhancing LAL-mediated lipolysis mitigates obesity-related dysfunction. This functional antagonism between cytosolic and lysosomal lipolysis presents a new paradigm in lipid metabolism, suggesting that therapeutic strategies must be pathway-specific. We conclude that selectively inhibiting pathogenic cytosolic lipid release while promoting beneficial lysosomal lipid processing offers a nuanced approach to treating metabolic disease.},
	doi = {10.1161/ATVBAHA.125.323273},
	pmid = {41431923 [Indexed for MEDLINE]},
	note = {PMC12758639}
}

@ARTICLE{10.1139/apnm-2025-0344,
	author = {Sakar M, Doğan Ç, Apaydın N, İpekoğlu G},
	title = {Does the MC4R rs17782313 gene polymorphism affect the rate of exercise-induced fat oxidation?},
	journal = {Appl Physiol Nutr Metab},
	year = {2026},
	abstract = {This study investigated the effect of the MC4R rs17782313 (T > C) polymorphism on substrate oxidation and metabolic responses during exercise in healthy sedentary men. Forty-eight participants (aged 20-30 years) underwent genotyping and completed a graded exercise test with respiratory gas analysis to assess oxygen consumption (VO2), respiratory quotient (RQ), and fat and carbohydrate oxidation rates. Participants were grouped as C-allele carriers (risk allele) and TT homozygotes. Group comparisons were conducted for VO2, RQ, substrate oxidation rates, and body mass index (BMI). Statistical analysis revealed no significant differences between genotypes in RQ, fat oxidation percentage, or carbohydrate oxidation percentage during moderate-intensity exercise (p > 0.05). However, significant differences were observed in BMI, with C-allele carriers exhibiting higher BMI values compared to TT homozygotes (p < 0.05). These results indicate that while the MC4R rs17782313 variant is associated with increased adiposity, it does not appear to affect acute substrate utilization during exercise. Thus, its contribution to obesity risk may be primarily mediated by behavioral and neuroendocrine mechanisms influencing energy intake rather than impairments in metabolic flexibility.},
	doi = {10.1139/apnm-2025-0344},
	pmid = {41429006 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.molmet.2025.102305,
	author = {Grothen JER and Martinez JM and Sidiropoulos N and Massier L and Zareifi D and Zhong J and Davidsen I and Platou JW and Mandelbaum J and Rothe P and Hvid H, Grønborg M and Madsen CT and Bruun JM, Rydén M and Mejhert N and Helge JW and Gerhart-Hines Z and Pedersen TÅ},
	title = {Single cell transcriptomics of human weight loss links adipocyte NPY1R to control of lipolysis.},
	abstract = {BACKGROUND: Combination of increased physical exercise and hypocaloric diet has long been recognized to improve cardiometabolic health and adipose tissue function, including lipid turnover. How such lifestyle interventions mediate benefits at the cellular level remains unknown. Given the critical role of subcutaneous white adipose tissue (scWAT) to systemic metabolic homeostasis, we set out to interrogate how exercise and diet lifestyle intervention impacted scWAT in individuals living with obesity, with a particular focus on lipolytic capacity and cell-specific gene profiling. METHODS: Single nuclei RNA sequencing (snRNAseq) was performed on cryopreserved scWAT biopsies originally collected before and after lifestyle intervention, involving regular exercise and hypocaloric diet in obese individuals. Findings on regulation of lipolysis in adipocytes were followed up with meta-analysis of clinical studies and pharmacological experiments in mature human adipocytes. RESULTS: snRNAseq analysis revealed intervention-induced changes in all scWAT cell-types. In adipocytes genes linked to protein and organelle turnover, branch chain amino acid catabolism, and lipolytic control were most significantly regulated. We identified a cell autonomous brake on adipocyte lipolysis via the neuropeptide Y receptor 1 (NPY1R). Expression of adipocyte NPY1R was reduced after weight loss and correlated positively with body fat percentage and body mass index. Findings were confirmed in meta-analysis across 23 studies. Finally, we found a negative correlation between NPY1R and beta-adrenergic-induced lipolysis and that NPY dose-dependently attenuated lipolysis and cAMP-signaling in primary human subcutaneous adipocytes. CONCLUSIONS: Our work suggests that decreases in adipocyte NPY1R during weight loss boost lipolytic capacity and contribute to improved systemic cardiometabolic health.},
	doi = {10.1016/j.molmet.2025.102305},
	pmid = {41412283 [Indexed for MEDLINE]},
	note = {PMC12926987}
}

@ARTICLE{10.1016/j.abb.2025.110703,
	author = {Guan C and Han R and Liu L and Liu J and Fu S and Tang X},
	title = {Exploring the multiple mechanisms of Hydroxytyrosol in treating obesity.},
	journal = {Arch Biochem Biophys},
	year = {2026},
	abstract = {BACKGROUND: The exploration of multi-mechanism therapeutics may represent a key strategy for treating obesity and metabolic dysfunction-associated steatotic liver disease. Hydroxytyrosol (HT), a phenolic compound derived from olive oil in the Mediterranean diet, exhibits potential for obesity treatment; however, its precise mechanisms remain incompletely understood. OBJECTIVE: This study aimed to elucidate the therapeutic effects of HT in obesity and to uncover its underlying regulatory mechanisms. METHODS: An obesity model was induced in C57BL/6 mice via a high-fat diet (HFD) to evaluate the in vivo effects of HT. Assessments included glucose tolerance test (GTT), insulin tolerance test (ITT) and biochemical analyses of fasting blood glucose (FBG), fasting serum insulin (FINS), uric acid (UA), blood lipid, aspartate aminotransferase (AST), and alanine aminotransferase (ALT). Hepatic, skeletal muscle, myocardial and adipose tissue (AT) morphology were examined via H&E staining. In vitro, 3T3-L1 preadipocytes were used to investigate the effects of HT on adipogenesis and thermogenic capacity. Lipid accumulation was assessed by Oil Red O and BODIPY 493/503 staining. Protein expression levels were determined via immunohistochemistry and Western blot analysis. RESULTS: HFD feeding led to increased body weight, FBG, FINS, UA, AST, ALT, and the area under the curve (AUC) for GTT and ITT. H&E staining revealed hepatic vacuolization, skeletal muscle fiber hypertrophy, and myocardial disorganization in HFD-fed mice. HT treatment significantly reduced body weight, improved glucose homeostasis, lipid metabolism, and liver function, and restored normal tissue morphology of liver, skeletal muscle, myocardium, and AT. HFD upregulated the expression of PPARγ, C/EBPβ, FABP4, STING1, and NLRP3 proteins in white AT, which were markedly attenuated by HT. HT reversed HFD-induced downregulation of PGC1α and UCP1 in brown AT. In vitro experiments confirmed that HT modulates adipogenesis and thermogenic activation in preadipocyte via the STING1/NLRP3 pathways. CONCLUSION: These findings demonstrate that HT acts as a novel anti-obesity agent by targeting the STING1/NLRP3 axis to suppress adipogenesis in adipose tissue and ameliorate obesity-related alterations in AT, liver, skeletal muscle, and myocardium. This study provides a mechanistic foundation for the potential application of HT in obesity intervention.},
	doi = {10.1016/j.abb.2025.110703},
	pmid = {41389891 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/mnfr.70352,
	author = {Almasri F and Aimaretti E and Sus N, Schéle E and Dickson SL and Landberg R and Collino M and Frank J},
	title = {Unfermented High-Fiber Rye Crispbread Increases Plasma HDL and Reduces Hepatic Lipids Compared to Refined Wheat in Rats Fed a High-Fat Diet.},
	abstract = {Fiber-rich rye foods reduced body weight in overweight or obese individuals compared to refined wheat, though the underlying mechanisms remain unclear. This study compared the effects of whole grain fermented and unfermented rye with refined wheat crispbread on body weight and lipid metabolism in rats. Exploratory outcomes included adiposity, appetite biomarkers, glucose homeostasis, colon inflammation, integrity, and permeability. Sprague Dawley rats (n = 54) were acclimatized (2 weeks) and randomized to control (n = 9) or high-fat diets (n = 45) for 16 weeks. Animals in the high-fat group were randomized to continue the high-fat (n = 9) or receive a standard diet alone (n = 9) or the standard diet with either refined wheat crispbread (n = 9), fermented rye crispbread (n = 9), or unfermented rye crispbread (n = 9) for 8 weeks. A high-fat diet did not affect final body weight, glucose homeostasis, and colon inflammation, but increased energy intake, adiposity, and leptin compared to control, and hepatic triacylglycerols compared to all other groups. Unfermented rye crispbread increased plasma HDL-cholesterol and reduced hepatic triacylglycerols and cholesterol compared to refined wheat, despite the absence of effects on obesity and glycemic control. No differences were observed between fermented and unfermented rye. Unfermented whole-grain rye crispbread may potentially exhibit favorable lipid-modulating effects.},
	doi = {10.1002/mnfr.70352},
	pmid = {41388979 [Indexed for MEDLINE]},
	note = {PMC12728384}
}

@ARTICLE{10.1111/jgh.70201,
	author = {Fan JB and Qin LQ and Ding L and Zhang L and Shao MM and Tong X and Xu JY},
	title = {Effects of Piperine on Obese and Lean Nonalcoholic Fatty Liver Disease in Mice.},
	journal = {J Gastroenterol Hepatol},
	year = {2026},
	abstract = {Nonalcoholic fatty liver disease (NAFLD) is commonly associated with overweight and obesity. But an increasing number of cases involve lean individuals, who tend to experience worse liver outcomes. In this study, we established mouse models of both obese and lean NAFLD by feeding mice a Western diet (WD) ad libitum and a WD with 30% caloric restriction (CR), respectively, to investigate the effects of piperine. After 12 weeks, hepatocyte lipid deposition and liver injury were similar in lean and obese NAFLD mice. Piperine treatment significantly reduced serum ALT levels and hepatic triglyceride (TG) content, alleviating hepatic steatosis in both groups. The mechanism of action involved the downregulation of fatty acid uptake, as evidenced by reduced expression of PPARγ and CD36, as well as the promotion of lipolysis through upregulation of hormone-sensitive lipase (HSL) and adipose triglyceride lipase (ATGL). Additionally, piperine enhanced hepatic mitochondrial β-oxidation in the obese NAFLD model by upregulating carnitine palmitoyltransferase 1A (CPT1A). In conclusion, feeding a WD with 30% CR successfully induced lean NAFLD in mice, and piperine effectively alleviated NAFLD in both lean and obese mice.},
	doi = {10.1111/jgh.70201},
	pmid = {41367157 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/dom.70371,
	author = {Hu Y and Zhao J and Xu S and Liu J and Xu J and Zhang Y and Chang J and Liu X},
	title = {Hypobaric hypoxia disrupts brown adipose thermogenic function in mice via Plin2 upregulation.},
	journal = {Diabetes Obes Metab},
	year = {2026},
	abstract = {OBJECTIVE: High-altitude environments are characterized by hypobaric hypoxia and pose a significant physiological challenge. While obesity-related hypoxia is known to impair brown adipose tissue (BAT) function by suppressing lipolysis and thermogenesis, whether hypobaric hypoxia similarly compromises BAT function remains unclear. We hypothesize that, unlike obesity-associated hypoxia, hypobaric hypoxia perturbs BAT thermogenesis via a distinct mechanism involving the upregulation of Plin2. METHODS: Mice were exposed to either normoxia or hypobaric hypoxia (simulating 6000 m, 9.2% O2) for 30 days. BAT function was assessed by analyzing lipid droplet size, lipid and triglyceride content, and expression of thermogenic protein. Thermogenic capacity was further evaluated in mice subjected to 30 days of normoxia or hypobaric hypoxia, followed by a 2-day cold exposure or 3-day treatment with the β3-adrenergic agonist CL316243. Differential proteomics and in vitro experiments were performed to explore underlying molecular mechanisms. RESULTS: After 30 days of hypobaric hypoxia, mice exhibited reduced body weight (normoxia: 26.64 ± 0.91 vs. hypoxia: 21.94 ± 0.79 g, p = 0.002), yet exhibited enlarged lipid droplets in BAT (142.7 ± 15.52 vs. 387.4 ± 31.91 μm2, p < 0.001) and increased lipid accumulation. Compared with normoxia, hypoxic mice displayed impaired thermogenic responses to both cold exposure and β3-adrenergic stimulation, as indicated by suppressed thermogenic gene expression. Mechanistically, hypobaric hypoxia elevated lactate levels and upregulated PPARγ, which subsequently enhanced Plin2 expression, ultimately leading to defective lipolysis and impaired thermogenesis. CONCLUSIONS: We identify a novel hypoxia-lactate/PPARγ-Plin2 axis that uncouples body weight loss from BAT thermogenesis under hypobaric hypoxia. This pathway represents a previously unrecognized therapeutic target for counteracting metabolic dysfunction induced by high-altitude exposure.},
	doi = {10.1111/dom.70371},
	pmid = {41366228 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.ejphar.2025.178436,
	author = {Comella F and Melini S and Opallo N and Di Napoli E and Navatti NP and Paciello O and Ferrante MC and Meli R and Mattace Raso G and Pirozzi C},
	title = {Uncovering the pleiotropic effects of oleoylethanolamide on obesity-driven chronic kidney disease in mice.},
	journal = {Eur J Pharmacol},
	year = {2026},
	abstract = {Metabolic alterations, resulting from obesity, drive chronic kidney disease (CKD) through mechanisms including lipotoxicity, inflammation, and fibrosis. Oleoylethanolamide (OEA), an endogenous compound belonging to the N-acylethanolamine family, has been widely studied for its metabolic properties. However, emerging evidence highlights its anti-inflammatory and anti-fibrotic effects. Here, we explored the effect of OEA on high-fat diet (HFD)-induced renal damage associated with obesity in mice. OEA treatment improved kidney function by restoring urine output and reducing proteinuria and albuminuria in obese mice. Moreover, OEA normalized serum creatinine and blood urea nitrogen levels, which were altered by HFD feeding, and decreased the transcription of kidney injury molecule-1 and neutrophil gelatinase-associated lipocalin, associated with renal damage. OEA also counteracted renal glucose dysmetabolism by reducing glycogen content and modulating the protein expression of glucose transporters. Furthermore, OEA exerted marked anti-inflammatory and antifibrotic effects in kidney, further confirmed by a reduction in the transcription of pro-inflammatory and pro-fibrotic markers. OEA reduced renal steatosis, improving lipid metabolism through increased peroxisome proliferator-activated receptor-α and fibroblast growth factor 21 transcription and reduced triglyceride trafficking by the downregulation of diacylglycerol O-acyltransferase 1. Finally, to highlight the direct effect of OEA in the kidney, we confirmed its protective activity against lipotoxicity and demonstrated its ability to improve mitochondrial bioenergetics in human proximal tubular epithelial cells (HK-2). These results indicate that OEA may be a promising therapeutic molecule for restraining CKD-related alterations associated with obesity and metabolic disorders.},
	doi = {10.1016/j.ejphar.2025.178436},
	pmid = {41352699 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/obr.70039,
	author = {Garcia N and Mellergaard M and Salomon C and Sepulveda P and Kristensen P and Handberg A},
	title = {CD36 and Its Role in Obesity.},
	journal = {Obes Rev},
	year = {2026},
	abstract = {Obesity is understood as a condition driven by interactions between genetics and environmental factors. The role of CD36 in the regulation of lipid metabolism and ectopic fat accumulation emerges as a key area of interest. This review presents CD36 not only as a crucial facilitator of fatty acid uptake but also as a regulator of how and where excess lipids are stored. Ectopic fat accumulation-lipid deposition in non-adipose tissues such as the liver, muscle, and pancreas-is linked to obesity-related complications, including metabolic dysfunction-associated steatotic liver disease (MASLD) and cardiovascular risk. Through CD36, tissues that normally play minor roles in lipid storage become overloaded, leading to metabolic dysfunction. We offer a fresh perspective on the adipose tissue expandability hypothesis, positioning CD36 as a regulator of adipose tissue's capacity to store lipids. Possibly, once adipose tissue reaches its expansion limit, CD36-mediated mechanisms drive the spillover of lipids into ectopic sites, exacerbating obesity complications. This insight offers a transformative view of CD36 as a player in the metabolic tipping point between healthy fat storage and pathogenic fat deposition. The connection between CD36 and extracellular vesicles (EVs) hints at a broader network of inter-tissue communication that could further amplify ectopic fat accumulation. Finally, we list evidence showing how CD36 genetics are related to the predisposition to develop and manage obesity. By understanding the role of CD36 in fat storage regulation, new personalized therapeutic strategies may emerge, targeting its pathways to prevent or reverse the metabolic damage caused by ectopic fat.},
	doi = {10.1111/obr.70039},
	pmid = {41344388 [Indexed for MEDLINE]},
	note = {PMC12926625}
}

@ARTICLE{10.1016/j.intimp.2025.115952,
	author = {Rakib A and Al Mamun MA and Mandal M and Yasmen N and Ofosu-Boateng M and Collier DM and Park F and Gyamfi MA and Jiang J and Singh UP},
	title = {Siglec-E deletion alters AT macrophages phenotypes, induces an inflammatory response, and adipogenesis during diet-induced obesity.},
	journal = {Int Immunopharmacol},
	year = {2026},
	abstract = {Obesity is currently a worldwide health problem, affecting more than 600 million people, and poses a threat to lifestyle and triggers metabolic complications. The infiltration of macrophages into adipose tissue (AT) plays a key role in inducing inflammation and multiple diseases during obesity. Therefore, comprehensive knowledge is required on the crosstalk between adipocytes with resident macrophages in AT to design therapeutic options for obesity and metabolic diseases. While we have demonstrated the role of Siglec-E in inflammation, the mechanism by which Siglec-E induces AT inflammation and adipogenesis remains unclear to date. Thus, this study describes how Siglec-E alters AT macrophages phenotypes, function, and adipogenesis using a high-fat diet (HFD)-induced model of obesity. We showed that during obesity, expression of Siglec-E orchestrated the infiltration of macrophages in the AT. Further, deletion of Siglec-E increased the frequency and expression of inflammatory markers and modulated macrophages towards M1 phenotypes to induce AT inflammation. We also noticed that interleukin (IL)-6 and monocyte chemoattractant protein 1 (MCP-1), inflammatory markers, increased in differentiated 3T3-L1 adipocytes after the inhibition of Siglec-E. Further, cultured 3T3-L1 adipocytes, treated with Siglec-E siRNA, show an increasing expression of peroxisome proliferator-activated receptor γ (PPARγ), NF-κB inducing kinase (NIK), NF-κB2, and decreasing expression of CCAAT-enhancer-binding protein-α (C/EBPα), and adiponectin, which in part suggests that Siglec-E is also associated with adipogenesis. Further, we observed that stromal vascular fractions (SVF) cells isolated from HFD-fed mice subjected to treatment with Siglec-E siRNAs exhibited decreased expression of the cell death-inducing DFA-like effector a (CIDEA), supporting the notion that Siglec-E might, in part, also play a role in AT browning. Taken together, our findings highlight new possibilities for the function of Siglec-E in obese conditions and instigate us to propose that Siglec-E might serve as a potential therapeutic for obesity-associated metabolic disease and AT inflammation.},
	doi = {10.1016/j.intimp.2025.115952},
	pmid = {41343943 [Indexed for MEDLINE]},
	note = {PMC12696692}
}

@ARTICLE{10.1016/j.phymed.2025.157608,
	author = {Hu L and Zhang Z and Xu T and Ma P and Wang Z and Zhang L and Chen J and He P and Yang X and Du G and Lian F and Li X and Qiang G},
	title = {Jiangtang Tiaozhi Formula alleviates obesity by enhancing adipose thermogenesis via TGR5-mediated gut-liver-adipose axis.},
	journal = {Phytomedicine},
	year = {2026},
	abstract = {BACKGROUND: Development of safe and effective anti-obesity drugs has emerged as an urgently needed issue. Jiangtang Tiaozhi Formula (JTTZF), a traditional Chinese medicine formulation, has demonstrated potential antidiabetic and hypolipidemic properties. However, the anti-obesity efficacy of JTTZF and its mechanisms remain insufficiently understood. METHODS: We assessed the pharmacodynamic effects of JTTZF in diet-induced obese (DIO) mice, as well as in HepG2 cells and adipocytes, focusing on body weight and glucose/lipid metabolism in vivo and in vitro, respectively. 16S rDNA sequencing profiling and fecal microbiota transplantation (FMT) were applied to validate the contribution of gut microbiota in anti-obesogenic effects of JTTZF. Untargeted fecal metabolomics was utilized to explore the potential metabolic pathways mediating gut-liver-adipose axis leading to anti-obesity effect of JTTZF via thermogenesis, which were subsequently confirmed by qPCR detection. RESULTS: JTTZF exhibited a significant effect of anti-obesity and metabolic benefit, including inhibiting weight gain and adiposity, reducing blood glycolipid, ameliorating glucose intolerance and insulin resistance, together with protecting against hepatic steatosis, compared with orlistat. Mechanistically, JTTZF boosted white fat browning and brown fat thermogenesis. More importantly, JTTZF remodeled gut microbiota by enhancing the colonization of beneficial bacteria. Further JTTZF-FMT induced weight loss and metabolic benefits in DIO mice, verifying that gut microbiota played a crucial role in the anti-obesity effect of JTTZF. Additionally, enrichment analysis of differential metabolites revealed that JTTZF obviously upregulated bile acid metabolism pathway, which promoted TGR5-mediated thermogenesis and energy expenditure in adipose tissue. CONCLUSION: JTTZF exerted significant anti-obesity effect and metabolic benefits via gut-liver-adipose axis, indicating that JTTZF hold a promising potential at the preclinical stage for obesity treatment.},
	doi = {10.1016/j.phymed.2025.157608},
	pmid = {41338112 [Indexed for MEDLINE]}
}

