@ARTICLE{10.1016/j.tox.2025.154362,
	author = {Gong J and Park IG and Hwang S and Cho J and Lee MJ and Kim M and Kang J and An S and Noh M},
	title = {Interaction-profile cheminformatic read-across identifies the UV filter benzophenone-4 as a PPARγ agonist and potential obesogen.},
	abstract = {Obesogens are chemicals, often encountered as environmental contaminants, that disrupt metabolic regulation and promote obesity. Here, we present a cheminformatics framework that integrates interaction-profile docking simulations with cluster-level enrichment analysis to enhance read-across and prioritize candidate environmental metabolic disruptors. Protein-ligand contact features from docking to obesity-related nuclear receptors were summarized at the pose level and combined into a 327-dimensional interaction-profile descriptor. Dimensionality-reduced descriptors from 6022 Tox21 compounds were clustered, and enrichment analysis against Tox21 assay results identified clusters associated with specific nuclear receptor activities. One cluster was selectively enriched for peroxisome proliferator-activated receptor γ (PPARγ) agonists. Although benzophenone-4 (BP-4, sulisobenzone), a sunscreen UV filter in this cluster, is labeled as inactive in Tox21, experimental validation confirmed selective PPARγ binding and recruitment of SRC-2 and PGC-1α coactivators. In human bone marrow-derived mesenchymal stem cells, BP-4 promoted adipogenic differentiation, lipid accumulation, and adiponectin production, establishing its potential as an environmental obesogen. This study demonstrates the power of combining interaction-profile read-across with functional assays to predict environmental metabolic disruptors and provides a mechanistic template for systematic chemical safety evaluation.},
	doi = {10.1016/j.tox.2025.154362},
	pmid = {41325878 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/mnfr.70341,
	author = {Das P and Kar R and Panchali T and Dutta A and Phoujdar M and Ghosh K and Pradhan S},
	title = {Antiobesity Efficacy of Marine Tapra Fish (Opisthopterus tardoore) Oil in High-Fat Diet-Induced Obese Mice by Activating Lipolysis and Suppressing Adipose Inflammation.},
	abstract = {The present study sought to elucidate the potentiality of oil extracted from Opisthopterus tardoore (OT, marine fish available in Bay of Bengal region) on diet induced obesity and explored into the primary molecular process that underlies these effects. Male Swiss albino mice were fed a high-fat diet for 12 weeks to develop obesity, and different doses of OT (200, 400, and 600 mg/kg/day) oil was administered orally for 4 weeks. Following treatment, body weight, biochemical, histological, and genomic parameters were assessed from liver and adipose tissues (ATs). Significant reductions were observed in body weight, lipid profiles, blood glucose, liver, and visceral AT weight, correlated with decreased adipocyte size by supplementation with OT oil. The fish oil significantly upregulates mRNA levels of lipolytic factors such as adiponectin, peroxisome proliferator-activated receptor-α, carnitine palmitoyl transferase-1, lipoprotein lipase, and antiinflammatory cytokines, including interleukin-1 receptor antagonist (IL-1Ra), IL-10, than those of high-fat diet group. Concomitantly, adipogenesis and fatty acid synthesis were arrested by reduction of lipogenic genes, including leptin, fatty acid synthase, sterol regulatory element binding protein-1c, and proinflammatory markers (tumor necrosis factor-α, IL-6, inducible nitric oxide synthase, and IL-1β) in adipocytes. The results therefore concluded that OT oil exhibited lipid-lowering along with antiinflammatory properties.},
	doi = {10.1002/mnfr.70341},
	pmid = {41321257 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.tice.2025.103245,
	author = {Gong H and Song Y and Yang D and Jiang C and Jiao R and Ma Y and Raza SHA and Zhang J and Wei D},
	title = {Analysis of WNT5A as a key regulator of intramuscular fat deposition in muscle-adipocyte co-cultures.},
	abstract = {The coordinated development of skeletal muscle and intramuscular adipose tissue in animals essentially determines meat yield and quality, a process co-regulated by multiple genes. Using a co-culture model of bovine skeletal muscle cells (SMCs) and intramuscular adipocytes (IMAs), integrated with transcriptomic sequencing and bioinformatic analyses, key candidate genes coregulating muscle development and fat deposition were identified. Three potential coregulators-WNT5A, APOE, and BDKRB2-were selected. Protein-protein interaction (PPI) network analysis, along with tissue and cellular expression profiling, indicates that WNT5A potentially interacts with key protein markers of adipogenesis and myogenesis. Furthermore, it is highly expressed in both adipose and muscle tissues. Pathway enrichment analysis revealed significant enrichment of WNT5A in the Wnt signaling pathway. These findings suggest that WNT5A plays a dual regulatory role in the development of both skeletal muscle and intramuscular fat (IMF). This finding lays a solid theoretical foundation for deciphering the molecular mechanisms of muscle-fat deposition in beef cattle and for improving meat quality.},
	doi = {10.1016/j.tice.2025.103245},
	pmid = {41314095 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/ptr.70108,
	author = {Tie F and Hu N and Dong Q and Wang H},
	title = {Vitisin A Regulates Lipid Metabolism in 3T3-L1 Adipocytes and High-Fat Diet-Induced Obese Mice.},
	journal = {Phytother Res},
	year = {2026},
	abstract = {Obesity is a leading cause of various metabolic disorders, and its prevalence is rapidly increasing globally. In this study, we investigated the potential lipid-inhibitory and anti-obesity effects of oligostilbene compounds derived from Iris lactea in 3T3-L1 adipocytes. Particularly, Vitisin A on lipid accumulation in 3T3-L1 adipocytes, as well as on lipid metabolism in HFD-induced obese mice. The 3T3-L1 adipocytes and HFD-induced obese mice model were used in the study. In 3T3-L1 adipocytes, MTT assay, oil red O staining, transmission electron microscopy, MitoSox/DCFH-DA probe, and western blotting were used to assess specific indicators. In HFD-induced obese mice, lipid profile and hepatic injury were analyzed in the liver samples, histological sections were prepared and liver lipidomics analysis was performed, and western blotting was used to analyze the proteins associated with lipid lowering in Vitisin A. Vitisin A significantly reduced intracellular lipid accumulation, inhibited preadipocyte differentiation, and improved mitochondrial function in 3T3-L1 adipocytes. Transcriptomics analysis revealed notable changes in adipogenic gene expression in Vitisin A-treated 3T3-L1 cells. Furthermore, Vitisin A administration in HFD-induced obese mice resulted in smaller adipose depots and lower lipid concentrations. Lipidomics analysis indicated that Vitisin A modified lipid metabolic pattern in obese mice, significantly impacting triglycerols (TGs), phosphatidylcholines (PCs), and phosphatidylethanolamines (PEs). Mechanistic study revealed that Vitisin A is likely to activate the PPARγ/PGC-1α signaling pathway to ameliorating lipid metabolism disorders. The lipid-inhibitory and anti-obesity effects of Vitisin A from Iris lactea are regulated by lipid homeostasis and metabolism.},
	doi = {10.1002/ptr.70108},
	pmid = {41277332 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jnutbio.2025.110190,
	author = {Yahya MA and Alshammari GM and Eleawa SM and Amawi K and Alkhateeb M and Al-Farga AM and Alshaikhli H and AlFaris NA and Alotaibi SN},
	title = {Decoding the anti-obesity mechanisms of isoliquiritigenin: AMPK activation modulates adipogenesis, lipolysis, oxidative stress, and inflammation in high-fat diet rat models.},
	journal = {J Nutr Biochem},
	year = {2026},
	abstract = {This study investigated the effects of Isoliquiritigenin (ISL) on adiposity in Wistar rats fed a high-fat diet (HFD), positing that ISL mitigates adiposity by inhibiting adipogenesis and promoting lipolysis via AMPK activation. Adult male Wistar rats were divided into six groups (n=8): Control (vehicle), Control + ISL (40 mg/kg), HFD (vehicle), HFD + ISL (20 mg/kg), HFD + ISL (40 mg/kg), and HFD + ISL (40 mg/kg) + Dorsomorphin (0.2 mg/kg) for 12 weeks. In a dose-dependent manner, ISL (thrice a week) significantly attenuated the increase in body weight and adipocyte size, improving glucose and insulin tolerance, HbA1c, and HOMA-IR without affecting food intake in HFD rats. Particularly, the higher dose of ISL (40 mg/kg) significantly increased the phosphorylation of AMPK (+193.3%), resulting in a p-AMPK/AMPK activity ratio increase of 191.0% in the white adipose tissue (WAT) of HFD rats. This dose also reduces body weight (24.6%), weight gain (28.7), fat deposit weight (-39.2% %), HOMA-IR (-67.62%), and serum triglycerides (-62.4%), cholesterol (56.7%), IL-6 (-66.1%) and TNF-α (-79.5%) in these HFD rats. It also increased p-ACC levels (+86.7%), Nrf2 mRNA (+392.7%), and PPARα mRNA (+255.0%), as well as the levels of HSL (+149.7%) and ATGL (139.62%). ISL (40 mg/kg) also decreased WAT levels of IL-6 (-57.86%), TNF-α (-74.96%), mRNA of SREBP1 (-38/8%), FAS (-50%) and NF-kB (58.8%), and levels of PLIN1 (-50.1) in these HFD rats. Dorsomorphin treatment reversed these effects in ISL + HFD rats. In conclusion, ISL demonstrates anti-obesity effects in HFD-induced rats through AMPK activation.},
	doi = {10.1016/j.jnutbio.2025.110190},
	pmid = {41274316 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.metabol.2025.156439,
	author = {Pedersen L and Gliniak CM and Dale TM and Zhu Q and Li C and Funcke JB and Crewe C and Luo J and Palluth L and Zhu Y and Scherer PE},
	title = {Induction of Yin Yang 1 (YY1) overexpression in mature adipocytes promotes dysfunctional adipose tissue and systemic insulin resistance in mice.},
	journal = {Metabolism},
	year = {2026},
	abstract = {The ubiquitous transcription factor Ying Yang 1 (YY1) plays a fundamental role in multiple biological processes and is believed to regulate up to 10 % of all human genes. In thermogenic brown adipose tissue, YY1 has been linked to controlling mitochondrial gene expression and regulating cellular oxidative respiration, protecting against diet-induced obesity and alterations in energy balance. The role of YY1 in non-thermogenic, white adipose tissue, on the other hand, remains largely unknown. Here, we show that adipocyte-specific induction of YY1 promotes dysfunctional adipose tissue and systemic insulin resistance in mice. Long-term YY1 induction in mature adipocytes leads to reduced weight gain, systemic insulin resistance, and increased liver steatosis in comparison to control littermates. In contrast, brown adipose tissue-specific YY1 overexpression has little effect on mice fed a high-fat diet. In an obesogenic environment, acute ectopic adiponectin promoter-driven YY1 expression promotes weight loss, cell death, and adipose tissue inflammation. Underlying the observed reduction in adipose tissue mass, we find that YY1 controls gene networks related to adipose tissue expansion, lipid anabolic pathways (hypertrophy), and hyperplasia (adipogenesis). Taken together, our results demonstrate novel roles of Yy1 in white adipose tissue. This versatile transcription factor regulates central aspects of white adipose tissue biology that are essential for maintaining whole-body physiology.},
	doi = {10.1016/j.metabol.2025.156439},
	pmid = {41265559 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/jsfa.70301,
	author = {Feng Z and Yong W and Zhang R and Li M and Pang M and Zhang X and Wei Y and Sun G},
	title = {Corn peptides alleviate high-fat diet-induced obesity and metabolic disorders in mice by regulating adipogenesis and intestinal microbial disorders.},
	journal = {J Sci Food Agric},
	year = {2026},
	abstract = {BACKGROUND: Corn peptides (CPs) are natural bioactive peptides with multiple beneficial effects. A previous study found that CPs enhanced endurance by activating the AMPK/PGC-1α signaling pathway and increasing intestinal probiotics involved in lipid metabolism, leading to the hypothesis that CPs may have anti-obesity effects. RESULTS: The current study established an obesity model by feeding mice a high-fat diet (HFD) for 8 weeks, followed by CPs for 4 weeks. The results show that CPs effectively decreased bodyweight, epididymal fat weight, and liver fat accumulation in obese mice. They also show that CPs administration reduced lipid levels and metabolic disorders and ameliorated liver steatosis in HFD-fed obese mice. Corn peptides significantly increased the expression levels of PPARγ and PGC-1α proteins in subcutaneous inguinal white adipose tissue (iWAT), while those of SREBP1 and FAS were decreased. Corn proteins also increased the abundance of intestinal probiotic bacteria and reduced the harmful bacteria count, which may contribute to their anti-obesity effects. The Kyoto Encyclopedia of Genes and Genomes database revealed significant differences in genes that were differentially expressed in response to treatment with CPs. Genes associated with various transporters, including ATP-binding cassette transporters, and with lipid metabolism were enriched. Those related to amino acid metabolism, oxidative phosphorylation, insulin resistance, and atherosclerosis were downregulated. There were also significant changes in genes involved in carbohydrate metabolism. CONCLUSIONS: Corn proteins can alleviate HFD-induced weight gain and related metabolic disorders by regulating lipid adipogenesis and intestinal microecology. © 2025 Society of Chemical Industry.},
	doi = {10.1002/jsfa.70301},
	pmid = {41255063 [Indexed for MEDLINE]}
}

@ARTICLE{10.1021/acs.jafc.5c10351,
	author = {Koh YC and Kamchonemenukool S and Ho PY and Weerawatanakorn M and Pan MH},
	title = {Oleic Acid-Esterified Octacosanol as a Functional Ingredient to Counter Obesity-Associated Lipid Dysregulation through PPAR-Targeted Regulation.},
	journal = {J Agric Food Chem},
	year = {2026},
	abstract = {Octacosanol, a major constituent of policosanol, exhibits lipid-lowering activity, particularly when esterified with fatty acids. Although its cholesterol-lowering actions have been linked to the modulation of fatty acid and cholesterol biosynthesis, its functions within adipose tissue remain poorly defined. Here, we examined nonesterified octacosanol (NO), lauric acid-esterified octacosanol (LEO), and oleic acid-esterified octacosanol (OEO) in high-fat diet-fed mice for 11 weeks. Target prediction and molecular docking identified PPARα and PPARδ as putative targets of octacosanol, guiding downstream mechanistic analyses in adipose tissue. Both NO and OEO enhanced lipolysis; NO preferentially increased fatty acid β-oxidation, whereas OEO specifically promoted thermogenic remodeling, indicating distinct metabolic consequences driven by ester chemistry. Together, these findings demonstrate that structural modification, particularly oleic acid esterification, substantially augments the metabolic activity of octacosanol in lipid catabolism and thermogenesis, underscoring its potential relevance in obesity-associated metabolic regulation.},
	doi = {10.1021/acs.jafc.5c10351},
	pmid = {41254832 [Indexed for MEDLINE]},
	note = {PMC12862754}
}

@ARTICLE{10.1016/j.psj.2025.106104,
	author = {Gao M and Han Q and Zhu Q and Li D and Li X and Lv Z and Guo Y},
	title = {Maternal effects of choline on skeletal muscle development and intramuscular fat deposition in broiler offspring.},
	abstract = {Low-protein diets with low inclusion of soybean meal have been used in breeder hens and not affected the laying performance, however, it's usually observed the detrimental effects on skeletal muscle growth and intramuscular fat deposition in the offspring. One of the major reasons is the reduced supply of choline when the dietary inclusion of soybean meal is limited. Choline is an essential methyl donor and a critical regulator of lipid metabolism. The underlying mechanisms through which maternal chloride supplementation affects offspring muscle growth and lipid metabolism remain largely unclear. This study aimed to clarify the maternal effect of choline on regulating embryonic and post-hatch skeletal muscle development and intramuscular fat deposition in broiler offspring. Maternal choline chloride (CC) supplementation improved egg weight, Haugh unit, and shell strength, and increased yolk S-adenosylmethionine concentration (P < 0.01). It also elevated phosphatidylcholine (PC) levels in serum and yolk of hens and in the serum of newly hatched chicks (P < 0.05). Enhanced embryonic breast muscle fiber formation and higher half-eviscerated yield at 42 d of age were observed in the CC group (P < 0.05). Maternal choline increased lipid droplet accumulation in the liver and breast muscle of embryos at day 19. In cultured chicken myotubes, choline chloride upregulated the expression of SLC16A7 and FASN and increased intracellular malonyl-CoA and triglyceride (TG) contents (P < 0.01). At 42 d, maternal choline supplementation enhanced TG deposition in the breast muscle by activating SLC16A7 and FASN-mediated fatty acid synthesis. Targeted metabolomics further revealed elevated concentrations of myristic and palmitic acids in the offspring muscle (P < 0.01). Collectively, maternal choline supplementation improved egg quality and yolk PC deposition in breeder hens and promoted muscle growth and intramuscular fat accumulation in the offspring. These findings provide a new insight into the significance of the trans-generational effects of choline nutrition for optimizing broiler breeder diets and improving meat quality of the offspring.},
	doi = {10.1016/j.psj.2025.106104},
	pmid = {41252858 [Indexed for MEDLINE]},
	note = {PMC12666344}
}

@ARTICLE{10.1002/cbdv.202502019,
	author = {Xiao C and Zhou P and Luo L and Zhang Q and Zhang Y and Tan L and Fu M and Quan W and Tang Y and Zhou L and Wu K and Deng L},
	title = {Chinese Yam Polysaccharide Ameliorates Obesity by Promoting Lipolysis Via the cAMP/PKA Signaling Pathway.},
	journal = {Chem Biodivers},
	year = {2026},
	abstract = {Obesity is associated with multiple health problems and has become a major public health challenge worldwide. In this study, the monosaccharide composition of CYP was determined using the PMP pre-column derivatization method. The results showed that CYP was composed of Glc, Gal, Ara, Man, and GlcA. In addition, the anti-obesity effects of CYP were evaluated using OP9 cells in vitro and a zebrafish obesity model in vivo. The findings revealed that CYP effectively promoted lipolysis, significantly modulated the expression of lipolysis-related proteins, and markedly reduced lipid accumulation in obese zebrafish. Subsequently, the potential molecular mechanism underlying the anti-obesity effects of CYP was explored via network pharmacology, molecular docking, and experimental validation. Protein-protein interaction network analysis identified five core targets, including STAT3, CASP3, PPARA, JUN, and MMP9. Moreover, KEGG enrichment analysis and molecular docking indicated that the cAMP signaling pathway may mediate the anti-obesity effects of CYP, with STAT3 serving as a potential therapeutic target. Furthermore, Western blot experiments demonstrated that CYP downregulated STAT3 expression and activated the cAMP/PKA signaling pathway, thereby ameliorating obesity. Collectively, these findings suggest that CYP holds promise as a novel anti-obesity agent.},
	doi = {10.1002/cbdv.202502019},
	pmid = {41240330 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/advs.202417330,
	author = {Wang H and Yang C and Luo D and Liu P and Zeng Z and Peng W and Peng D and Su H and Xiao X and Wang H and Jin X},
	title = {Obesity-Associated TRIM15 Promotes the Proliferation of Esophageal Adenocarcinoma Through the YY2/FOXRED1 Axis.},
	journal = {Adv Sci (Weinh)},
	year = {2026},
	abstract = {Obesity has been identified as an independent risk factor for gastroesophageal reflux disease (GERD) and esophageal adenocarcinoma (EAC). Oxidative stress and inflammation driven by chronic GERD are the main causes of the tumorigenesis of EAC, but the underlying mechanism remains elusive. Here, the inflammation-upregulated E3 ligase, tripartite motif 15 (TRIM15), is identified as a key driver of obesity-associated EAC. TRIM15 promotes the degradation of YY2 is demonstrated through the ubiquitin-proteasome system, which in turn dysregulates lipid metabolism and enhances the proliferation of EAC cells. Furthermore, YY2 transcriptionally is shown that increases FOXRED1 expression. FOXRED1 is subsequently identified as an essential effector for the TRIM15-induced dysregulation of lipid and energy metabolism in EAC cells. Thus, a novel obesity-associated TRIM15/YY2/FOXRED1 axis is identified that contributes to the proliferation of EAC. Given that lipid metabolism regulates ferroptosis by controlling cellular processes associated with phospholipid peroxidation. The TRIM15/YY2/FOXRED1 axis demonstrates that it modulates SLC3A2 expression via the mTOR/c-MYC pathway, thereby regulating GPX4 levels to influence EAC sensitivity to ferroptosis-inducing compounds and proposing a therapeutic strategy for EAC.},
	doi = {10.1002/advs.202417330},
	pmid = {41237333 [Indexed for MEDLINE]},
	note = {PMC12822407}
}

@ARTICLE{10.1038/s41366-025-01945-9,
	author = {Shi Y and Cao M and Wang K and Qi G and Dong F and Zhang X},
	title = {The role of SIRT4 in obesity: from molecular mechanisms to clinical implications.},
	journal = {Int J Obes (Lond)},
	year = {2026},
	abstract = {Obesity has emerged as a pervasive global public health issue, and the etiology of obesity is now understood to be increasingly intricate and multifactorial, encompassing genetic predispositions, sedentary lifestyles coupled with excessive caloric intake, as well as environmental and social interactions. Recent studies have indicated a close association between SIRT4 and obesity. The pathophysiological mechanisms underlying its influence on obesity predominantly involve four interconnected pathways: fatty acid oxidation, adipocyte differentiation, insulin secretion, and inflammation. Furthermore, emerging studies are exploring the clinical translational potential of SIRT4. As a mitochondria-localized member of the sirtuin family, SIRT4 possesses both deacetylase and ADP-ribosyltransferase enzymatic activities. This mitochondrial enzyme is involved in metabolic regulation through modulating energy homeostasis and lipid metabolic processes, inflammatory signaling pathways, neuroendocrine regulatory networks, and the epigenetics of adipocyte differentiation. However, the lack of comprehensive synthesis and critical evaluation of existing evidence has left the precise relationship between SIRT4 and obesity incompletely understood. Therefore, this review systematically synthesizes current knowledge regarding SIRT4's mechanistic involvement in obesity development, while evaluating clinical correlations and regulatory strategies. This review focuses on the potential of SIRT4 in the regulation of obesity and the progress in related studies. The search criteria encompass keywords related to the role of SIRT4 in physiological and biochemical processes such as lipid and energy metabolism, adipocyte differentiation, as well as its clinical applications, with a total of 63 references cited.},
	doi = {10.1038/s41366-025-01945-9},
	pmid = {41233560 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.envres.2025.123297,
	author = {Jiang N and Chen Q and Cheng B and Meng K and Wang J and Li T and Chen H and Liao Y and Sun H and Liu R},
	title = {Associations of urinary environmental phenols with obesity and lipid metabolism in children and adolescents: The expanded Chinese National Human Biomonitoring (CNHBM) project.},
	journal = {Environ Res},
	year = {2026},
	abstract = {Despite ubiquitous exposure to environmental phenols (EPs), their associations with obesity are poorly understood due to inconsistent findings and inadequate mechanistic insights. Within the China National Human Biomonitoring program, we measured 15 urinary EPs in 860 children/adolescents from Jiangsu Province, employing lipidomics to investigate obesity associations. EPs were detectable in 17.93 %-96.79 % samples, with Bisphenol B (BPB) and benzophenone-4 (BP-4) emerging as predominant compounds. Urinary EPs concentrations correlated significantly with sex, BMI status, household income, and dietary patterns. Multivariable logistic regression showed a linear inverse association between BPB and BP-4 exposure and overweight/obesity in pubertal girls. Bayesian Kernel Machine Regression (BKMR) and Quantile g-computation (QGC) analyses confirmed that urinary EPs were inversely associated with overweight/obesity in the overall cohort (OR = 0.76, 95 % CI: 0.59-0.98) and among girls (OR = 0.63, 95 % CI: 0.44-0.90). Lipidome-wide association studies (LWAS) applied generalized linear models (GLMs) with Gaussian and binomial distributions to evaluate the relationships of EP concentrations and overweight/obesity status with lipid abundances, identifying 28 metabolites and 10 pathways that link EPs exposure to overweight/obesity. Mediation analyses indicated BP-4 effects were partially mediated by glycerophospholipid (-6 % to -13 %) and sphingolipid metabolites (9 %-18 %), whereas BPB effects were driven by sphingolipid (7 %-8 %). Stratified analyses indicate that alterations in glycerophospholipid and sphingolipid pathways mediate sex-specific EPs effects on overweight and obesity, providing a theoretical basis for targeted public health strategies.},
	doi = {10.1016/j.envres.2025.123297},
	pmid = {41232908 [Indexed for MEDLINE]}
}

@ARTICLE{10.2337/db25-0295,
	author = {Wang C and Hou Y and Zhang M and Wang J and Chu X and Liang M and Sun C and Xie J and Zhang J and Wang CY},
	title = {miR-432 Exacerbates Obesity-Induced Dysregulation of Glucose and Lipid Homeostasis.},
	journal = {Diabetes},
	year = {2026},
	abstract = {miRNAs are key regulators of metabolic homeostasis, yet their role in obesity-associated dysfunction remains incompletely understood. Here, we identify miR-432 as a driver of systemic metabolic dysregulation. Serum miRNA profiling revealed a positive correlation between miR-432 expression and obesity/type 2 diabetes mellitus. Functionally, adipose-specific miR-432 exacerbated high-fat diet-induced obesity and insulin resistance. Similarly, hepatic-specific miR-432 aggravated hepatic steatosis and systemic glucose dysregulation, while skeletal muscle-specific miR-432 disrupted glucose homeostasis without affecting body composition. Mechanistically, miR-432 disrupted insulin sensitivity by inhibiting the PIK3R3/AKT pathway and perturbed lipid homeostasis by suppressing the PIK3R3/PPAR-α axis. Notably, obesity-induced miR-432 upregulation was predominantly localized in adipocytes and driven by the CDK5/PPAR-γ axis. Furthermore, adipocyte-derived exosomal miR-432 was identified as a mediator of systemic metabolic dysfunction, facilitating intertissue cross talk in obesity. Collectively, our data demonstrate that miR-432 exacerbates obesity-induced dysregulation of glucose and lipid metabolism. ARTICLE HIGHLIGHTS: miR-432 overexpression in adipose tissue, liver, and skeletal muscle exacerbates high-fat diet-induced disruption of metabolic homeostasis. miR-432 impairs glucose homeostasis by suppressing the PIK3R3/AKT pathway and disrupts lipid homeostasis via inhibition of the PIK3R3/PPAR-α axis or directly suppressing PPAR-α. Obesity-induced elevation of miR-432 is predominantly localized in adipocytes and driven by the CDK5/PPAR-γ axis. Adipocyte-derived exosomal miR-432 mediates systemic metabolic dysfunction, establishing an intertissue regulatory network.},
	doi = {10.2337/db25-0295},
	pmid = {41218910 [Indexed for MEDLINE]},
	note = {PMC12716619}
}

@ARTICLE{10.1016/j.micres.2025.128393,
	author = {Zheng C and Xie J and Tang F and Wang Z and Liu L and Pi Y and Zhong Y and He Z and Liu T and Zheng J and Luo J},
	title = {Bacteroides acidifaciens alleviates high-fat diet-induced obesity-related osteoporosis by regulating gut microbiota and bile acid metabolism via the gut-bone axis.},
	journal = {Microbiol Res},
	year = {2026},
	abstract = {Obesity disrupts bone formation-resorption balance. Despite the established role of Bacteroides acidifaciens (B. acidifaciens) in modulating metabolic homeostasis, reducing inflammation, and improving lipid metabolism, its impact on obesity-associated osteoporosis is still not well understood. In this study, we delved into the potential protective influence of B. acidifaciens on high-fat diet (HFD) induced bone loss. The results showed that B. acidifaciens sharply improved weight gain, glucose and lipid metabolism in 16 weeks HFD mice. Both In vitro and in vivo experiments have conclusively demonstrated that the introduction of B. acidifaciens notably ameliorated the imbalance of HFD induced osteogenesis and osteoclastogenesis. B. acidifaciens also regulated HFD induced gut microbiota and bile acid metabolism, and strengthened intestinal mucosal barrier function. Additionally, B. acidifaciens significantly activated the AMPK-PPARα signaling pathway in bone tissue. Thus, our study indicated that B. acidifaciens regulated metabolism, restored gut microbiota balance, and activated AMPK-PPARα pathway to prevent HFD-induced bone loss, potentially aiding in preventing and treating obesity-related osteoporosis.},
	doi = {10.1016/j.micres.2025.128393},
	pmid = {41205303 [Indexed for MEDLINE]}
}

@ARTICLE{10.1038/s41386-025-02273-2,
	author = {Liu C and Li Z and Ji JJ and Liu K and Samsom JN and Li T and Lu Q and Liu F},
	title = {Single-cell RNA sequencing uncovers molecular features underlying microglial lipid accumulation and depression-related behaviors in high-fat diet mouse model of obesity.},
	journal = {Neuropsychopharmacology},
	year = {2026},
	abstract = {Obesity is a worldwide health crisis, with unhealthy diet as a major contributor. Comorbid neuropsychiatric conditions such as depression and anxiety are associated with obesity. Since obesity is a pro-inflammatory state, chronic neuroinflammation may mediate obesity and neuropsychiatric comorbidity. We used RNA-seq to provide a single-cell resolution transcriptome of brain immune cells using long-term high-fat diet (HFD) to model obesity in male mice. HFD mice exhibited depression and anxiety-like behavior. We observed a shift towards increased proportions of lipid droplet-accumulating microglia (LDAM) in the long-term HFD brain. By in-depth characterization of the transcriptional signature of LDAM, we identified that ACSL1, a key regulator of lipid droplet biogenesis, was highly expressed in LDAM induced by HFD. Finally, we demonstrated that ACSL1 inhibition reduced lipid droplets deposition in microglia exposed to free fatty acids (FFA). Our findings provide a comprehensive view of the molecular changes in brain immune cells associated with HFD, suggesting a link between microglial lipid droplet accumulation and neurological comorbidities induced by obesity.},
	doi = {10.1038/s41386-025-02273-2},
	pmid = {41198848 [Indexed for MEDLINE]},
	note = {PMC12824154}
}

@ARTICLE{10.1016/j.carbpol.2025.124436,
	author = {Yin C and Li C and Fan X and Shi D and Li J and Qiu J and Yao F and Yu W and Gao H},
	title = {Schizophyllum commune polysaccharide ameliorates diet-induced obesity by regulating the Faecalibaculum rodentium/indole-3-lactic acid/microRNA axis.},
	journal = {Carbohydr Polym},
	year = {2026},
	abstract = {Diet-induced metabolic disorder is a global health concern, and bioactive polysaccharides have been shown to mitigate metabolic disorder by modifying gut microbiota. Polysaccharides from Schizophyllum commune have shown excellent anti-obesity effects, but the specific regulatory mechanisms remain unclear. Herein, we reported that SCP could effectively inhibit 3 T3-L1 preadipocyte differentiation in vitro and supplementation with SCP alleviated obesity in HFD-fed mice. SCP treatment significantly enriched Faecalibaculum rodentium and ILA and increased the expression levels of several lipid metabolism-related genes including AMPKα, PGC-1α and PPARγ. The anti-obesogenic effects of SCP can be transferred by FMT. SCP supplementation and FMT significantly increased the ILA levels in serum and feces. Moreover, FMT significantly increased the levels of miR-144-5p, miR-142a-5p and miR-150-5p; these miRNAs were enriched in the phosphatidylinositol signaling pathway and were positively correlated with the content of ILA. The lipogenesis-related gene Nr2F6 was coregulated by the above miRNAs, and its expression level significantly increased in FMT mice. These results indicate that SCP ameliorates diet-induced obesity by increasing the abundance of F. rodentium and ILA as well as the expression levels of certain miRNAs. Our study may provide a new reference for understanding the anti-obesogenic effects of natural polysaccharides.},
	doi = {10.1016/j.carbpol.2025.124436},
	pmid = {41198290 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cellsig.2025.112214,
	author = {Zhang L and Hou N and Wang X and Quan L and Yu Z and Du X and Wu S},
	title = {KCNK3 coordinates adipocyte lipid storage and thermogenic shifts via AMPK, modulating a ferroptosis-permissive state.},
	journal = {Cell Signal},
	year = {2026},
	abstract = {Fat deposition is a critical economic trait in pigs, intricately linked to meat quality and feed efficiency. Although the potassium channel KCNK3 is well-established as a key regulator of brown adipose tissue function in humans and mice, its role in porcine adipobiology and lipid metabolism remains poorly understood. This study identifies the two-pore potassium channel KCNK3 as a key mediator of porcine adipocyte differentiation and lipid accumulation via a previously unrecognized, ferroptosis-dependent mechanism, thereby revealing a novel link between ionic signaling and metabolic reprogramming. Using CRISPR-engineered porcine cell models combined with multi-omics approaches, we demonstrate that KCNK3 displays distinct expression patterns in adipose tissue that correlate with fat deposition phenotypes across swine breeds. Genetic disruption of KCNK3 markedly enhances thermogenic capacity while suppressing lipid accumulation, a process associated with AMPK and AKT pathway activation. Integrated transcriptomic and lipidomic analyses further demonstrate that KCNK3 deficiency promotes the pathological accumulation of polyunsaturated fatty acids alongside sphingolipid depletion, resulting in a lipid profile characteristic of a pro-ferroptotic state. Mechanistically, KCNK3 loss-of-function induces iron overload, reactive oxygen species burst, and glutathione depletion, culminating in key ferroptotic events, potentially mediated by the AMPK-p53-GPX4 signaling cascade. While our multi-omics data support this model, further functional studies are needed to fully establish causality. Our findings thus provide the first evidence for the ion channel-mediated coordination of adipocyte lipid metabolism with the ferroptotic process, uncover a species-divergent role for KCNK3 in promoting lipogenesis in swine in contrast to its thermogenic role in rodents, and implicate the evolutionarily conserved AMPK-p53-GPX4 regulatory axis in this context. These discoveries not only highlight KCNK3 as a potential target for precision breeding of lean swine varieties but also suggest novel therapeutic strategies for human metabolic disorders based on targeted adipose tissue remodeling.},
	doi = {10.1016/j.cellsig.2025.112214},
	pmid = {41197888 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.cmet.2025.10.007,
	author = {Klag K and Ott D and Tippetts TS and Nicolson RJ and Tatum SM and Bauer KM and Stephen-Victor E and Weis AM and Bell R and Weagley J and Maschek JA and Vu DL and Heaver S and Ley R and O'Connell R and Holland WL and Summers SA and Stephens WZ and Round JL},
	title = {Dietary fat disrupts a commensal-host lipid network that promotes metabolic health.},
	journal = {Cell Metab},
	year = {2026},
	abstract = {The microbiota influences metabolic health; however, few specific microbial molecules and mechanisms have been identified. We isolated a Turicibacter strain from a community of spore-forming bacteria that promotes leanness in mice. Human metagenomic analysis demonstrates reduced Turicibacter abundance in individuals with obesity. Similarly, a high-fat diet reduces Turicibacter colonization, preventing its weight-suppressive effects, which can be overcome with continuous Turicibacter supplementation. Ceramides accumulate during a high-fat diet and promote weight gain. Transcriptomics and lipidomics reveal that the spore-forming community and Turicibacter suppress host ceramides. Turicibacter produces unique lipids, which are reduced during a high-fat diet. These lipids can be transferred to host epithelial cells, reduce ceramide production, and decrease fat uptake. Treatment of animals with purified Turicibacter lipids prevents obesity, demonstrating that bacterial lipids can promote host metabolic health. These data identify a lipid metabolic circuit between bacteria and host that is disrupted by diet and can be targeted therapeutically.},
	doi = {10.1016/j.cmet.2025.10.007},
	pmid = {41197631 [Indexed for MEDLINE]},
	note = {PMC12717881}
}

@ARTICLE{10.1002/advs.202507149,
	author = {Szekely K and Gerl MJ and Peters B and Schwarz J and Schuppelius B and Damm M and Soliz-Rueda JR and Sehgal R and Lazaratos M and Klose C and Simons K and Pfeiffer AFH, Schürmann A and Kramer A and Michalsen A and Pivovarova-Ramich O},
	title = {Impact of Intended Isocaloric Early versus Late Time-Restricted Eating on Plasma Lipidome in Women with Overweight or Obesity: Secondary Analysis of the ChronoFast Trial.},
	journal = {Adv Sci (Weinh)},
	year = {2026},
	abstract = {Time-restricted eating (TRE) is a promising strategy against metabolic disorders, but its effects on lipid metabolism remain controversial. The present research assesses and compares the impact of early (eTRE) versus late (lTRE) TRE on the plasma lipidomic profile. This is an exploratory outcome of the previously published randomized crossover trial, which examines 31 women with overweight or obesity who follow a two-week eTRE and a two-week lTRE in an intended isocaloric setting. Blood plasma and subcutaneous adipose tissue biopsies are analyzed using shotgun lipidomics and transcriptomics, respectively. Between interventions and within the lTRE, lipid species and classes, as well as enzyme activity indices, are not substantially changed. Within the eTRE, changes are observed for 103 lipid species, including a reduction of ceramide and phosphatidylcholine classes, and for the desaturation indices D5D, D6D, and D9D, as well as the elongation index ELOVL6. Combined analysis of plasma lipidome and adipose tissue reveals alterations in the glycerophospholipid pathway and in the expression of phospholipase enzymes PLB1, PLA2G6, and PLAG4B, dependent on TRE timing. These results suggest that eating timing during TRE may be crucial for remodeling the plasma lipidome and adipose tissue transcriptome and highlight the need of future lipidomic research in TRE.},
	doi = {10.1002/advs.202507149},
	pmid = {41186047 [Indexed for MEDLINE]},
	note = {PMC12822420}
}

@ARTICLE{10.1016/j.freeradbiomed.2025.10.282,
	author = {Fan S and Yu Y and Wei Y and An J and Wang Q and Yang Y},
	title = {Targeting the mTOR-mitochondrial function axis: Calcitriol attenuates sarcopenic obesity with lipid dysregulation etiology.},
	journal = {Free Radic Biol Med},
	year = {2026},
	abstract = {Sarcopenic obesity (SO) manifests as intramuscular lipid deposition and regenerative impairment triggered by dysregulation of the mitophagy-associated axis. Mitochondria-associated membranes (MAMs) are critical for lipid metabolism and mitochondrial function regulation. The mechanistic target of rapamycin (mTOR) is a functional protein at the MAMs and a central metabolic regulator; however, the underlying mechanisms by which mTOR dysregulation affects SO remain unclear. Calcitriol possesses the potential to improve mitochondrial function and fatty acid oxidation. This study investigated the mechanism of Calcitriol in SO using an in vivo SO mice model and an in vitro lipotoxicity-induced myoblast atrophy model. Calcitriol significantly ameliorated muscle atrophy in SO mice, as evidenced by increased grip strength, enhanced behavioral activity, and improved histopathological lesions. Untargeted metabolomic analysis revealed that Calcitriol intervention significantly ameliorated lipid metabolic disorders in SO mice, manifested by a marked reversal of aberrant changes in key lipid metabolites and the restoration of β-oxidation and mitochondrial function-related metabolites to physiological levels. Calcitriol treatment reduced pro-inflammatory cytokines while increasing anti-inflammatory cytokines, restored the contact distance between mitochondria and endoplasmic reticulum at MAMs, and enhanced mitophagy. RNA-Seq, molecular docking, and molecular dynamics simulations collectively demonstrated that these effects were attributable to mTOR downregulation. Furthermore, in vitro mTOR knockdown confirmed that Calcitriol ameliorates lipotoxicity-induced myoblast atrophy through an mTOR-dependent pathway, maintaining MAMs, stabilizing calcium homeostasis, mitigating mitochondrial dysfunction, and reducing ROS generation. In summary, this study demonstrates a novel mechanism whereby Calcitriol effectively inhibits mTOR, which is associated with the restoration of structural integrity of MAMs and the amelioration of disordered lipid metabolism, thereby attenuating SO.},
	doi = {10.1016/j.freeradbiomed.2025.10.282},
	pmid = {41173312 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/oby.70053,
	author = {Zu Y and Mikhael M and Andrade J and Scoggin S and Yosofvand M and Moussa H and Festuccia WT and Moustaid-Moussa N},
	title = {Effects of Eicosapentaenoic Acid on the Glycerophosphate Shuttle-Regulated Inflammatory and Thermogenic Responses.},
	journal = {Obesity (Silver Spring)},
	year = {2026},
	abstract = {OBJECTIVE: Mitochondrial glycerol-3-phosphate dehydrogenase (GPD2) is a crucial enzyme in the glycerophosphate shuttle, linking glycolysis, lipogenesis, and oxidative phosphorylation, making it a potential target for obesity treatment. Given the metabolic benefits of eicosapentaenoic acid (EPA), an omega-3 polyunsaturated fatty acid, we hypothesized that EPA modulates the GPD2-centered glycerophosphate shuttle to reduce adiposity, glucose intolerance, and inflammation while increasing energy expenditure. METHODS: Male and female GPD2 knockout (KO) and wild-type (WT) littermates were fed a high-fat diet (HF) without or with an 18 g EPA/kg (EPA) diet for 13 weeks. Body weight, glucose tolerance, and metabolic profiles were assessed, and blood and tissues were collected following euthanasia. RESULTS: Male GPD2 KO mice exhibited reduced adiposity and lower lipid accumulation in hepatic and adipose tissues compared to WT males. These effects were linked to lipid metabolism and beige fat activation. EPA supplementation reduced body weight and promoted glucose clearance in both WT and KO males, with enhanced hepatic lipid oxidation. However, GPD2 deficiency and EPA had minimal metabolic effects in females. CONCLUSIONS: Our findings highlight potential mechanisms by which GPD2 combats obesity by mediating lipid metabolism. Our findings further demonstrate the sex-dependent nature of EPA's metabolic benefits, independent of GPD2 deficiency.},
	doi = {10.1002/oby.70053},
	pmid = {41151774 [Indexed for MEDLINE]}
}

@ARTICLE{10.1210/clinem/dgaf586,
	author = {Metwally E and Burton L and Mirza I and Morsy MH and Scichilone G and Mostafa A and Shimotake Y and Lighter M and Bianco FM and Hassan C and Masrur MA and Layden BT and Mahmoud AM},
	title = {Adiposome Lipidomic Shifts Following Bariatric Surgery in Association With Weight Loss and Cardiometabolic Benefit.},
	journal = {J Clin Endocrinol Metab},
	year = {2026},
	abstract = {CONTEXT: Adiposomes carry bioactive lipids that shape systemic metabolism and vascular function. OBJECTIVE: Building on our previous findings that obese adiposomes are ceramide/free fatty acid-enriched and linked to dysfunction, we tested whether bariatric surgery remodels adiposome lipidomes and whether these shifts track with metabolic and vascular improvements. METHODS: Twenty-three obese individuals were assessed before and after bariatric surgery. Clinical evaluations included body mass index (BMI), body composition, glycemic markers, inflammatory markers, and vascular function. Adipose tissue biopsies were collected, and adiposomes were isolated for non-targeted lipidomic analysis using mass spectrometry. RESULTS: Bariatric surgery induced significant reductions in BMI, visceral fat, HOMA-IR, inflammatory markers, and systolic blood pressure, alongside marked improvements in vascular function. Adiposome lipidomics identified 550 species across 19 classes; 124 increased and 66 decreased after surgery. Class-level shifts showed decreases in triglycerides, diglycerides, cholesteryl esters, phosphatidic acids, fatty acids, and acylcarnitines, with increases in phosphocholines, phosphoethanolamines, lysophosphatidylcholines, sphingomyelins, ultralong-chain ceramides, and fatty acid-hydroxy fatty acids (FAHFAs); these changes were larger in participants with ≥20% BMI reduction. Changes in 36 lipid species correlated with BMI change: triglycerides 18:1/20:4/22:6 positively, and sphingomyelins (SM) d40:1, SM d42:4, and phosphatidylcholine 17:0/18:2 inversely. Improvements in nitric oxide, vascular reactivity, and adiponectin tracked with rises in ultralong-chain ceramide/FAHFAs/phospholipids and declines in acylcarnitine/cholesterol esters/diacylglycerols/phosphatidic acids. Machine learning models predicted BMI from lipid features with >80% accuracy (R2 >0.90; mean absolute error <0.3), highlighting SM d40:1, SM d42:4, and fatty acid 17:1 as top contributors. Pathway enrichment analysis linked these changes to sphingolipid signaling and glycerophospholipid metabolism. CONCLUSION: Bariatric surgery remodels adiposome lipids, and these shifts align with improvements in cardiometabolic risk markers.},
	doi = {10.1210/clinem/dgaf586},
	pmid = {41137449 [Indexed for MEDLINE]}
}

@ARTICLE{10.1111/dom.70220,
	author = {Liu Q and Guo S and Tong Y and Qiu L and Zhuang B and Wang J and Wang Y and Gao W and Zou X},
	title = {Renal lipotoxicity in diabetic and obesity-associated kidney diseases: Molecular mechanisms and therapeutic targeting.},
	abstract = {Metabolic disorders, including diabetes mellitus and obesity, have become major global health burdens that significantly increase the risk of kidney disease. A central pathological feature linking these conditions is lipotoxicity-the deleterious effects of lipid overload on cellular and organ function. In the kidney, lipotoxicity contributes to disease pathogenesis through a complex interplay of molecular mechanisms-such as mitochondrial dysfunction, impaired autophagy, oxidative stress, endoplasmic reticulum stress, and sustained inflammatory responses-which are detailed with a focus on their cell-specific effects in podocytes and proximal tubular cells. These pathological processes collectively disrupt renal cellular homeostasis, promote cell death, and drive progressive fibrosis, ultimately leading to functional decline. Despite significant advances in our understanding of metabolic kidney diseases, effective pharmacological interventions specifically addressing renal lipotoxicity remain strikingly limited. Current therapeutic strategies should extend beyond mere lipid reduction to comprehensively address the underlying metabolic dysregulation and its downstream cellular consequences. This review aims to analyse the pathogenic molecular mechanisms and potential therapeutic agents for renal lipotoxicity in diabetic and obesity-associated kidney diseases. It systematically examines the cell-type-specific injury mechanisms, lipotoxicity-induced renal injury, and the available evidence from both preclinical studies and clinical trials of metabolically active agents with renoprotective effects, with a view to offering novel insights and informing future therapeutic strategies for metabolic kidney diseases.},
	doi = {10.1111/dom.70220},
	pmid = {41126548 [Indexed for MEDLINE]}
}

@ARTICLE{10.1002/rcm.10157,
	author = {Wang Y and Shi S and Cai J},
	title = {Lipidomic Profiling Reveals Phenotype-Specific Metabolic Signatures in Obese and Hyperuricemic Children.},
	journal = {Rapid Commun Mass Spectrom},
	year = {2026},
	abstract = {OBJECTIVE: This study aims to investigate the phenotype-specific alterations in lipid metabolism among children with obesity, hyperuricemia, and their co-occurrence and to explore the potential associations between lipidomic profiles and clinical indicators. METHODS: A nontargeted lipidomic analysis was conducted on serum samples from 100 children aged 6-18 years, categorized into control, hyperuricemia, obesity, and combined phenotype groups based on serum uric acid levels and body mass index. Metabolic network reconstruction, pathway enrichment, and correlation analyses were performed to delineate the relationships between lipid metabolic changes and clinical features. RESULTS: The obesity group was characterized by a marked upregulation of triacylglycerols (TG). In the hyperuricemia group, membrane lipids such as phosphatidylcholine (PC) and lysophosphatidylcholine (LPC) were predominantly downregulated, whereas phosphatidylinositol (PI) showed heterogeneous alterations. The combined phenotype exhibited more extensive disruptions across multiple metabolic pathways. Correlation analysis revealed a consistent inverse relationship between TG and glomerular filtration rate (GFR), a strong association between ceramides (Cer) and insulin metabolism, and a distinctive positive correlation between LPC and aspartate aminotransferase (AST) in the hyperuricemia group. Carnitines (CAR) showed bidirectional associations with kidney function-related parameters. CONCLUSION: Lipid metabolism displays phenotype-specific regulatory patterns across distinct clinical presentations, with differential pathway involvement and functional enrichment. Key lipid species such as TG, PC, and Cer may serve as potential subtype biomarkers or therapeutic targets, offering novel insights into the early identification and precision management of metabolic disturbances in children.},
	doi = {10.1002/rcm.10157},
	pmid = {41126449 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jtha.2025.09.020,
	author = {Miles LA and Bai H and Chakrabarty S and Baik N and Zhang Y and Parmer RJ and Samad F},
	title = {Macrophage Plg-R(KT) expression promotes diet-induced obesity and metabolic dysfunction-associated steatotic liver disease.},
	journal = {J Thromb Haemost},
	year = {2026},
	abstract = {BACKGROUND: Plg-RKT is a transmembrane plasminogen receptor that enhances the activation of plasminogen to plasmin and localizes proteolytic activity of plasmin on the cell surface. OBJECTIVES: We investigated the role of Plg-RKT in high-fat diet (HFD)-induced obesity and metabolic dysfunction-associated steatotic liver disease (MASLD). METHODS: Mice deficient in Plg-RKT in macrophages (mPlg-RKT-/-) or hepatocytes (hPlg-RKT-/-) and control mice (Plg-RKTflox/flox) were fed a HFD to determine the cell-specific role of this receptor in obesity and MASLD. Glucose homeostasis, hepatic lipogenesis, fatty acid oxidation pathways, adipose macrophage phenotypes, and inflammation were analyzed. RNA sequencing analysis of liver was performed to identify differentially expressed genes and functional pathways impacted by the loss of myeloid Plg-RKT. RESULTS: Plg-RKT levels were significantly elevated in the liver of HFD-fed mice with MASLD. HFD-fed mPlg-RKT-/- mice were protected from obesity, MASLD, and liver dysfunction. mPlg-RKT-/- mice exhibited reduced liver fat, lower plasma alanine aminotransferase levels, and improved glucose homeostasis. In contrast, HFD-fed hPlg-RKT-/- mice were not protected from obesity and MASLD. Mechanistically, mPlg-RKT deficiency reduced hepatic Akt activation, lowered fatty acid synthase expression, and activated the PPARα fatty acid oxidation pathway. In adipose tissue, mPlg-RKT deficiency shifted macrophage polarization from proinflammatory M1-like to anti-inflammatory M2-like, enhancing insulin sensitivity, decreasing lipolysis, and lowering plasma free fatty acids available for liver uptake. RNA sequencing revealed significant gene expression changes in lipid metabolism, fibrosis, and inflammation. CONCLUSION: These findings underscore the critical role of macrophage Plg-RKT signaling in the pathogenesis of obesity and MASLD.},
	doi = {10.1016/j.jtha.2025.09.020},
	pmid = {41077131 [Indexed for MEDLINE]},
	note = {PMC12671604}
}

@ARTICLE{10.1007/s11010-025-05399-5,
	author = {Jaroch A},
	title = {Metabolomics of abdominal adipose tissue samples collected from patients with obesity - a critical review.},
	journal = {Mol Cell Biochem},
	year = {2026},
	abstract = {Obesity is a multifactorial metabolic disorder characterized by excessive fat accumulation and associated with numerous health risks, including insulin resistance, cardiovascular disease, and metabolic syndrome. Adipose tissue, particularly subcutaneous (SAT) and visceral (VAT) fat, plays a central role in metabolic regulation, yet its biochemical properties and functions differ significantly. While metabolomics offers a promising approach to studying adipose tissue at a molecular level, significant methodological limitations and inconsistencies in study design undermine the reliability of current findings. Although VAT is frequently characterized by a pro-inflammatory and lipolytic metabolic profile, whereas SAT is more involved in lipid storage and insulin, these generalizations overlook important depot-specific variations and fail to address the heterogeneity within adipose tissue. This critical review evaluates existing metabolomic studies, identifying key discrepancies in lipid metabolism, energy homeostasis, and inflammation-related pathways across VAT and SAT. It highlights the need for improved standardization in metabolomic analyses, greater inclusion of diverse populations, and more robust longitudinal studies. By addressing these issues, future research can provide more precise insights into adipose tissue's role in obesity-related metabolic dysfunction and better inform clinical strategies for obesity management.},
	doi = {10.1007/s11010-025-05399-5},
	pmid = {41023340 [Indexed for MEDLINE]},
	note = {PMC12906582}
}

@ARTICLE{10.1016/j.jnutbio.2025.110128,
	author = {García-Ruiz E, Reynés B and Ceresi E and Palou A and Oliver P},
	title = {Interscapular white adipose tissue: An interesting depot for browning research in rodents.},
	journal = {J Nutr Biochem},
	year = {2026},
	abstract = {Interscapular brown adipose tissue is surrounded by a white fat depot, the interscapular WAT (isWAT), which has received little attention. Here, we have characterized isWAT and the impact of chronic intake of a very high-fat diet, the cafeteria diet, on isWAT browning capacity. The effect of high-fat diets on WAT browning is controversial, however, some groups have described increased WAT UCP1 expression, probably to counteract increased adiposity. We analyzed mRNA expression of key brown/brite markers and lipid metabolism genes, and of selected proteins in isWAT of control, cafeteria-obese and post-cafeteria rats. Morphological/immunohistochemical characterization was also performed. Results present isWAT as a depot with a molecular profile close to that of browning-prone white fat depots (inguinal and retroperitoneal), which also shares key features with BAT, including UCP1 expression (mRNA/protein). The cafeteria diet intake induced mRNA expression of browning/thermogenic genes, which was restored after the diet was withdrawn, and increased expression of key genes involved in lipid catabolism in isWAT. Moreover, basal mRNA expression of brown/brite markers was greater than in other white depots and higher UCP1 protein levels were observed compared to the browning-prone retroperitoneal depot. Thus, isWAT appears as an interesting depot to be taken into consideration for lipid research and to better characterize browning regulation.},
	doi = {10.1016/j.jnutbio.2025.110128},
	pmid = {40992635 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jnutbio.2025.110120,
	author = {Han HS and Chung KS and Kim YR and Jang SY and Lee SH and Lee KT},
	title = {Hydrangenol exerts anti-obesity effects by disturbing adipogenesis via mitotic clonal expansion and gut microbiota dysbiosis.},
	journal = {J Nutr Biochem},
	year = {2026},
	abstract = {Obesity is a metabolic disorder influenced by genetic and environmental factors. Developing therapeutic strategies that maintain energy metabolism and gut microbiota balance is essential for addressing obesity. This study investigated the anti-obesity potential of hydrangenol (HG), a bioactive compound found in the leaves of Hydrangea serrata (Thunb.) Ser., in 3T3-L1 preadipocytes as well as high-fat diet (HFD)-induced and db/db obese mice. HG inhibited lipid accumulation in differentiated 3T3-L1 cells by disrupting mitotic clonal expansion through modulation of cell cycle-related proteins (cyclin D1, cyclin E, cyclin B1, CDK2, and p21). It also enhanced AMP-activated protein kinase α (AMPKα) phosphorylation while suppressing Akt and mTOR phosphorylation. In line with these in vitro results, HG also suppressed lipid deposition in obese mice by regulating key adipogenesis-related proteins such as C/EBPα, PPAR-γ, and AMPKα in white adipose and liver tissues, resulting in reduced fat mass. Furthermore, HG lowered plasma cholesterol, low-density lipoprotein, leptin, and insulin levels in HFD-fed mice resulting in the improvement of plasma profiles. 16S rRNA sequencing revealed that HG altered the composition of the gut microbiota, increasing the relative abundance of Bacteroidetes and decreasing Firmicutes and Proteobacteria in obese mice. Overall, these results highlight HG's potential as a promising candidate for reducing lipid accumulation and correcting gut microbiota dysbiosis, offering a strategy for obesity prevention.},
	doi = {10.1016/j.jnutbio.2025.110120},
	pmid = {40975182 [Indexed for MEDLINE]}
}

@ARTICLE{10.1038/s41418-025-01551-2,
	author = {Zheng C and Ye J and Yang Q and Liu K and Chen C and Cao J and Li Q and Xue Y and Ma H and Rabson AB and Shao C and Hua F and Sorokin L and Melino G and Shi Y and Wang Y},
	title = {ICAM-1 identifies preadipocytes and restricts white adipogenesis by adhering immune cells.},
	journal = {Cell Death Differ},
	year = {2026},
	abstract = {Adipose stem cell hierarchy was delineated by scRNA-seq analysis, revealing that ICAM-1, a glycoprotein that mediates cell-cell interaction, is a preadipocyte marker. However, the cellular and molecular mechanisms of how ICAM-1+ preadipocytes contribute to adipose tissue homeostasis in vivo remain unclear. To address this, Icam1+/CreERT2 mice were generated, and it was demonstrated that ICAM-1-expressing progenitors actively participated in developing and remodeling white adipose tissue. Under a high-fat diet, both proliferation and adipogenic differentiation of ICAM-1+ preadipocytes increased significantly. Interestingly, ICAM-1 plays a critical role in maintaining the interaction between preadipocytes and immune cells, acting as a checkpoint on white adipogenesis. Mice lacking ICAM-1 specifically in stromal cells exhibited worsened hyperplastic obesity, showing heightened fatty acid synthesis and lipid storage in adipose tissue, and the related insulin resistance. In human adipose tissue, ICAM-1 also marked committed preadipocytes and mediated adhesion between preadipocytes and immune cells. Thus, our study shows that ICAM-1 marks preadipocytes and curbs adipogenesis by facilitating adhesion between preadipocytes and immune cells.},
	doi = {10.1038/s41418-025-01551-2},
	pmid = {40813463 [Indexed for MEDLINE]},
	note = {PMC12881632}
}

@ARTICLE{10.4093/dmj.2025.0120,
	author = {Lee G and Lee YC and Park M and Kim SM and Park JH and Lee DH},
	title = {Dynamic Lipidomic Remodeling and Clinical Correlations after Sleeve Gastrectomy in Obese Subjects.},
	journal = {Diabetes Metab J},
	year = {2026},
	abstract = {BACKGRUOUND: Sleeve gastrectomy (SG) is an effective and the most commonly performed surgical intervention for obesity. However, detailed studies on the underlying mechanisms, particularly those involving lipid metabolism, remain limited. This study aimed to identify novel pathways associated with the metabolic efficacy of SG by assessing alterations in the serum lipidomic profiles of obese subjects following surgery. METHODS: A prospective study of 50 obese participants undergoing laparoscopic SG was conducted at a tertiary medical center. Serum samples were collected before surgery and 6 months after SG. Lipidomic profiling was performed alongside comprehensive follow-up assessments. Statistical analyses explored lipidomic alterations and their correlations with changes in clinical parameters (Clinical trial registration No. KCT0003527 and KCT0009704). RESULTS: Participants experienced a 25% reduction in body weight 6 months after SG, with a marked reduction (>70%) in hepatic steatosis and insulin resistance, and a 2-fold increase in plasma oxyntomodulin levels. Lipidomic analysis revealed significant molecular shifts in lipid subclasses based on the fatty acyl composition of lipid species, showing a trend toward higher unsaturation and longer carbon chain lengths, as well as metabolic regulation in specific lipid pathways. Key findings included characteristic shifts within triacylglycerols and glycerophospholipids, which were significantly associated with changes in oxyntomodulin levels. Enhanced phosphatidylcholine-to-lysophosphatidylcholine conversion and upregulated ether lipid levels correlated with liver stiffness measures. Metabolic remodeling of sphingolipids-characterized by a decrease in ceramide/sphingomyelin levels and upregulation of the hexosylceramide pathway-emerged as an additional lipidomic signature after SG. CONCLUSION: These findings highlight the complex lipidomic remodeling underlying the metabolic efficacy and therapeutic potential of SG.},
	doi = {10.4093/dmj.2025.0120},
	pmid = {40808226 [Indexed for MEDLINE]},
	note = {PMC12996952}
}

