@ARTICLE{10.1007/s12011-025-04754-3,
	author = {Tu M and Chen S and Ma L and Zhang J and Cai G and Wang T and Wang C},
	title = {Nano-ZnO Improves IUGR-Induced Abnormal Fat Deposition in Finishing Pigs by Remodeling the Intestinal Microbiota and Regulating Serum Metabolism.},
	journal = {Biol Trace Elem Res},
	year = {2026},
	abstract = {Intrauterine growth retardation (IUGR) in pigs is closely associated with excessive obesity and lipid metabolic abnormalities during postnatal catch-up growth. Nano zinc oxide (Nano-ZnO) is a novel nanomaterial that has antioxidant properties and can improve abnormal lipid metabolism. This study aimed to investigate the weight-reducing effects and mechanisms of Nano-ZnO in IUGR pigs. Six normal birth weight (NBW) and twelve IUGR male piglets were divided into three groups post-weaning (day 22): NBW and IUGR groups received a basal diet, while the IUGR + Zn group was fed a Nano-ZnO-supplemented diet (600 mg/kg). Nano-ZnO significantly reduced backfat thickness and improved fatty acid composition in IUGR pigs. Mechanistically, Nano-ZnO activated the NRF2 signaling pathway, enhancing antioxidant capacity in adipose tissue by elevating T-SOD and T-AOC activities, upregulating SOD/GCLC/GCLM expression, and suppressing KEAP1 and MDA levels. Concurrently, it promoted lipolysis via the adiponectin/AMPK/SREBP1C/PPARγ axis, increasing ACC/CPT-1/HSL activity and mRNA expression while inhibiting FAS. Furthermore, Nano-ZnO modulated gut microbiota composition (e.g., increasing cecal UCG-005, Rikenellaceae RC9, and fecal Phascolarctobacterium) and serum metabolites (e.g., reducing phenylpyruvic acid and 9(10)-EpOME, elevating docosahexaenoic acid and glycochenodeoxycholic acid). These findings demonstrate that Nano-ZnO ameliorates abnormal fat deposition in IUGR pigs through coordinated antioxidant, lipolytic, gut microbial, and metabolic reprogramming.},
	doi = {10.1007/s12011-025-04754-3},
	pmid = {40728547 [Indexed for MEDLINE]}
}

@ARTICLE{10.1210/clinem/dgaf382,
	author = {London A and Schaufuss A, Považan M and Dichman ML and Merhout J and Dirksen C and Madsbad S and Siebner HR and Lundsgaard A and Fritzen AM and Kiens B, Bojsen-Møller KN},
	title = {Effects of Acute Iso- and Hypocaloric Carbohydrate Restriction on Liver Fat and Glucose and Lipid Metabolism.},
	journal = {J Clin Endocrinol Metab},
	year = {2026},
	abstract = {CONTEXT: Liver fat is reduced within days after a low-carbohydrate diet substituted with fat to maintain isocaloric conditions. OBJECTIVE: Investigate the effect of matched carbohydrate restriction during isocaloric and hypocaloric conditions on liver fat and postprandial glucose and lipid metabolism. METHODS: Crossover randomized clinical trial at a research unit. Participants included 15 people with overweight/obesity (body mass index [BMI] 32.5 [31-34] kg/m2, median [IQR]). There were 3 dietary interventions: (1) 2 days of isocaloric control diet (CON), (2) 2 days of CON followed by 2 days of carbohydrate restriction (∼60 g/day) during very-low-calorie conditions (VLCDs), and (3) 2 days of CON followed by 2 days of isocaloric conditions with low carbohydrate (∼60 g/day), high-fat (LCHF) diet. Liver fat was measured using 1H-magnetic resonance spectroscopy. RESULTS: Liver fat was -16% (-34; 4) (median [IQR]) after LCHF relative to after CON (P = .020), but did not differ between VLCD and CON. Fasting plasma concentrations of triacylglycerol, glucose, and insulin were lower after both LCHF and VLCD than after CON. However, postprandial plasma glucose concentrations were higher and insulinogenic index lower after both LCHF and VLCD. CONCLUSION: Two days of LCHF led to lower liver fat, which was not observed after VLCD. This demonstrates the dynamic regulation of liver fat and the beneficial role of substituting carbohydrates with fat to maintain energy provision. Both LCHF and VLCD had positive effects on fasting parameters for glucose metabolism; however, both diets impaired early β-cell response resulting in deterioration in glucose handling during the meal test.},
	doi = {10.1210/clinem/dgaf382},
	pmid = {40601817 [Indexed for MEDLINE]},
	note = {PMC12819859}
}

@ARTICLE{10.1016/j.jare.2025.06.041,
	author = {Shi R and Wei J and Ye J and Song X and Yang X and Zhang Y and Liu S and Ren J and Wang D and Zhao Z and Liu Z and Wang Y and Zhao B and Xiao C and Dai X and Ai L and Liu X},
	title = {The novel synbiotic (Lactiplantibacillus plantarum and galacto-oligosaccharides) ameliorates obesity-related metabolic dysfunction: Arginine as a key mediator signaling molecule.},
	abstract = {OBJECTIVE: This study aimed to develop a novel synbiotic composed of Lactiplantibacillus plantarum LLY-606 and galacto-oligosaccharides (GOS) to improve lipid metabolism in obesity. DESIGN: Through genome-wide analysis using COG and CAZy databases, we identified GOS as a specific growth substrate for Lactiplantibacillus plantarum LLY-606. The efficacy of this synbiotic (LP-GOS) was evaluated in both obese individuals and high-fat diet-induced obese mice. RESULTS: LP-GOS supplementation reduced visceral fat and waist circumference in humans and attenuated obesity in mice. It also improved gut microbiota composition and increased serum arginine levels. Metabolomic and microbiota analyses suggested that enhanced arginine production plays a key role. This was further confirmed by arginine synthesis inhibition, antibiotic treatment, and CRISPR-Cas9-mediated knockout of the Ass1 gene in Lactiplantibacillus plantarum LLY-606. These interventions demonstrated that LP-GOS improves lipid metabolism through arginine-mediated activation of the AMPK pathway. CONCLUSIONS: LP-GOS effectively alleviates obesity-associated lipid metabolism disorders by enhancing arginine production and activating the AMPK signaling pathway.},
	doi = {10.1016/j.jare.2025.06.041},
	pmid = {40545235 [Indexed for MEDLINE]},
	note = {PMC12957849}
}

@ARTICLE{10.1007/s12011-025-04711-0,
	author = {Li X and Wang T and Wang W and Wang Z and Wang H and Fan K and Yang B},
	title = {Gene Dynamics in Maternal Nutrition: The Role of Chromium in Mitigating Offspring Obesity.},
	journal = {Biol Trace Elem Res},
	year = {2026},
	abstract = {This study investigates the potential mechanisms by which maternal chromium (Cr) supplementation mitigates offspring obesity through identification of key regulatory genes. Sixteen pregnant C57BL/6 mice were randomly allocated to either control (CON) or chromium-supplemented (CR) dietary groups, with nutritional interventions administered throughout gestation and lactation. Post-weaning, all offspring received CR diets until 32 weeks of age. Comparative analysis revealed significant reductions in adipose tissue mass and 136 differentially expressed genes (DEGs) in CR offspring adipose tissue, identified through GEO2R analysis. Functional enrichment analyses revealed significant involvement of these DEGs in critical metabolic pathways: lipid metabolism regulation (PPAR signaling), steroid hormone biosynthesis, cholesterol homeostasis, and fatty acid oxidation processes. Protein-protein interaction network analysis identified 14 hub genes central to adipocyte regulation, including ACSL1, DGAT1, ADIPOQ, PPARD, PPARG, SREBF1, APOC2, and FABP1, which collectively demonstrate synergistic effects in suppressing lipid accumulation. These findings elucidate molecular mechanisms underlying chromium-mediated protection against metabolic disorders and propose novel therapeutic targets for intergenerational obesity prevention. The identified gene network provides a framework for developing maternal nutritional strategies and pharmacological interventions targeting epigenetic regulation of lipid metabolism.},
	doi = {10.1007/s12011-025-04711-0},
	pmid = {40536644 [Indexed for MEDLINE]}
}

@ARTICLE{10.1080/15257770.2025.2517378,
	author = {Chen QT and Liu MW and Yu HJ and Zhang J and He QQ},
	title = {Identification of key genes in the liver of offspring from obesity maternal mice by bioinformatics analysis.},
	journal = {Nucleosides Nucleotides Nucleic Acids},
	year = {2026},
	abstract = {Murine maternal obesity predisposes offspring to obesity and other non-communicable diseases. Fetal programming enables researchers to trace this detrimental effect in the early life of the offspring. The aim of the current study was to explore the molecular impact of maternal obesity on the livers of murine offspring at weaning age. C57BL/6 female mice were exposed to a high-fat diet to induce obesity, after which they were mated to produce offspring. At weaning age, the metabolic health of female offspring was assessed and hepatic mRNAs were investigated via mRNA high throughput sequencing. The differentially expressed genes were identified using gene and protein expression analyses. The results revealed that murine maternal obesity altered the blood parameters, liver histology and gene expression of offspring. Cyclin-dependent kinase 1 (Cdk1) and E2f transcription factor 1 (E2f1) were identified as hub genes by bioinformatics analysis. Reverse transcription-quantitative PCR, western blotting and immunohistochemical analysis all revealed that the expression of Cdk1 and E2f1 was decreased in the livers of offspring born from obese does. In conclusion, murine maternal obesity impaired lipid metabolism in the livers of their offspring at weaning age. Furthermore, Cdk1 and E2f1 were identified as hub genes in the regulatory mechanism.},
	doi = {10.1080/15257770.2025.2517378},
	pmid = {40513071 [Indexed for MEDLINE]}
}

@ARTICLE{10.1016/j.jare.2025.05.049,
	author = {Wang B and Pi Q and Mohsin A and Gao WQ and Guo M and Xu H},
	title = {Exosomal miR-1246 of adipose stem cells attenuates obesity by polarizing M2 macrophages, reducing fat mass, and beiging of white adipose tissue.},
	abstract = {INTRODUCTION: Adipose stem cells (ADSC) have demonstrated therapeutic potential in ameliorating obesity and metabolic disorders, with their exosomes showing comparable therapeutic effects. However, the underlying molecular mechanism remains incompletely understood. Furthermore, the limited availability and inherent heterogeneity of primary ADSC present substantial challenges for consistent therapeutic outcomes. OBJECTIVE: This study aimed to investigate the molecular mechanism underlying the unique biological effects mediated by microRNAs (miRNAs) in exosomes derived from immortalized adipose stem cells (iADSC). METHODS AND RESULTS: We first established stable iADSC and isolated their exosomes (iADSC-EXO), which exhibited both high yield and stability. In high fat diet (HFD)-fed obese mice, iADSC-EXO administration significantly attenuated obesity, reduced blood glucose and lipid levels, and alleviated hepatic steatosis. miRNA chips analysis revealed that miR-1246 is highly enriched in exosomes derived from iADSC and ADSC. Administration of miR-1246 to HFD-fed obese mice produced beneficial effects on obesity and metabolic disorders comparable to those with iADSC-EXO. Mechanistic studies revealed that miR-1246 exerts its beneficial effects through multiple pathways: First, reducing fat mass by downregulating of the expression of fat mass and obesity-associate protein (FTO) and subsequent inhibition of adipogenesis and lipogenesis. Second, enhancing white adipose tissue (WAT) beiging by suppressing Runt-related transcription factor 1 (RUNX1T1) and FTO expression. Third, promoting M2 macrophage polarization and suppressing WAT inflammation via inhibition of TNF receptor-associated factor 6 (TRAF6)-mediated inflammatory pathway. CONCLUSION: Our study elucidates a novel molecular mechanism through which ADSC regulates adipose tissue homeostasis and metabolism and presents a potential therapeutic approach for treating obesity and related metabolic disorders via iADSC-EXO or miR-1246-based interventions.},
	doi = {10.1016/j.jare.2025.05.049},
	pmid = {40419017 [Indexed for MEDLINE]},
	note = {PMC12957830}
}

@ARTICLE{10.1016/j.jare.2025.05.011,
	author = {Jin M and Liu G and Liu E and Wang L and Jiang Y and Zheng Z and Lu J and Lu Z and Ma Y and Liu Y and Quan K and Jin H and Jiang X and Fei X and Li T and Cao J and Yuan Z and Du L and Wang H and Wei C},
	title = {Genomic insights into the population history of fat-tailed sheep and identification of two mutations that contribute to fat tail adipogenesis.},
	abstract = {INTRODUCTION: Since their domestication, domestic sheep (Ovis aries) have been culturally and economically significant farming animals worldwide. Fat-tailed sheep serve as a unique genetic resource for understanding adipogenesis and adaptive evolution in livestock. OBJECTIVES: Several genomic analyses have been conducted on various sheep breeds to elucidate the genome and regulation mechanism of the fat tail trait, prior genomic studies have failed to reconcile conflicting evidence about the genetic basis of tail morphology, particularly regarding the roles of PDGFD and BMP2. METHODS: Here, we conducted whole-genome resequencing of 283 sheep, encompassing 66 domestic breeds and 5 wild ovine species, to investigate the domestication history and selection signatures of fat-tailed sheep. Additionally, we performed transcriptome sequencing on adipose tissue to identify differentially expressed genes and cellular assays to validate these results. RESULTS: Demographic analysis revealed that domestic sheep descended from Asiatic mouflon and fat-tailed sheep began to diverge from thin-tailed sheep approximately 4.4-7.5 thousand years ago in East Asia. Chinese indigenous sheep were classified into Mongolian, Kazakh, Tibetan, and Yunnan populations. The Yunnan population may have experienced more recent genetic introgression from wild species, rather than an independent domestication event. Moreover, many potential regions associated with the fat-tailed phenotype (DDI1, PDGFD, and BMP2) were identified by selective sweep and genome-wide association analyses. Additionally, a fine-scale analysis of fat-tailed and thin-tailed sheep revealed two novel mutations: a G/A missense variant of PDGFD (Chr15: 3900312) and a C/T missense variant of BMP2 (Chr13: 48462350), both of which were significantly associated with tail adiposity. Functional validation demonstrated that mutant A-PDGFD significantly activated PFGFD expression and reduced fat deposition compared to wildtype. The C-BMP2 mutant activated BMP2 expression and promoted preadipocyte fat deposition. CONCLUSION: Our study provides the first evidence that these genes jointly regulate fat tail development through complementary mechanisms: PDGFD promotes adipose expansion, whereas BMP2 modulates energy partitioning. These findings offer new insights into the evolutionary history of fat-tailed sheep and identify potential targets for precision breeding in small ruminants.},
	doi = {10.1016/j.jare.2025.05.011},
	pmid = {40339746 [Indexed for MEDLINE]},
	note = {PMC12869290}
}

@ARTICLE{10.1016/j.jare.2025.04.010,
	author = {Khaliq SA and Park SY and Maham S and Cho Y and Lee M and Nam S and Seong JK and Chen J and Choi CS and Yoon MS},
	title = {ARHGEF3 coordinates adipocyte hypertrophy and differentiation through dual YAP-RhoA and PPARγ activation.},
	abstract = {INTRODUCTION: Obesity presents a significant global health burden, necessitating insights into the molecular drivers of adipogenesis and adipose tissue regulation. OBJECTIVES: This study investigates the role of Rho guanine nucleotide exchange factor 3 (ARHGEF3) in adipocyte differentiation and hypertrophy, focusing on its influence on adipogenesis and body weight regulation under high-fat diet conditions. METHODS: ARHGEF3-/- mice and littermate controls were subjected to a high-fat diet (HFD) and underwent comprehensive metabolic phenotyping. In vitro studies in C3H10T1/2 cells were conducted to assess ARHGEF3's role in adipogenesis, utilizing quantitative PCR, western blotting, chromatin immunoprecipitation (ChIP), immunoprecipitation (IP), immunostaining, and luciferase reporter assays. RESULTS: ARHGEF3 expression increased in white adipose tissue (WAT) of HFD-fed mice and during adipogenic differentiation in C3H10T1/2 cells. ARHGEF3-deficient mice exhibited reduced weight gain and adipocyte size, correlating with decreased RhoA expression and altered cytoskeletal dynamics. Additionally, ARHGEF3 facilitated yes-associated protein (YAP) nuclear translocation and its direct binding to the RhoA promoter, an effect reliant on ARHGEF3. ARHGEF3 also enhanced the transcriptional activity of peroxisome proliferator-activated receptor gamma (PPARγ), establishing a reciprocal activation loop to drive adipocyte differentiation and hypertrophy. CONCLUSION: ARHGEF3 emerges as a pivotal regulator of adipocyte dynamics by coordinating YAP-RhoA signaling and enhancing PPARγ activity. These findings offer novel therapeutic insights for addressing obesity and related metabolic disorders.},
	doi = {10.1016/j.jare.2025.04.010},
	pmid = {40216078 [Indexed for MEDLINE]},
	note = {PMC12766213}
}
